(@Tenant VARCHAR(90),@filter NVARCHAR(100),@userId INT)
AS
BEGIN



DECLARE @SQL VARCHAR(MAX)
DECLARE @startDate varchar(50);
DECLARE @endDate varchar(50);
SET @startDate = 'Start Date';
SET @endDate = 'End Date';



SET @SQL=N';



select row_number() OVER (ORDER BY year(j.created_datetime)) id, year(j.created_datetime) as year,FORMAT(DATEFROMPARTS(1900, month(j.created_datetime), 1), ''MMM'', ''en-US'') as month, count(*) as count
from '+QUOTENAME(@Tenant)+'.'+'job_details j where j.referred_type=''People'' and j.referred_by in
