and j.current_job_status NOT IN (''Deleted'',''Rejected'')
and j.created_datetime>='''+[dbo].[get_filter_datetime](@filter,@startDate)+''' and j.created_datetime<='''+[dbo].[get_filter_datetime](@filter,@endDate)+'''
group by month(j.created_datetime),year(j.created_datetime) '




END
