c.zip AS mailingAddressZip,c.contact_address2 AS otherAddress,c.contact_address2_city AS otherAddressCity,
c.contact_address2_state AS otherAddressState,contact_address2_zip AS otherAddressZip,
c.contact_mobile_phone AS mobile,c.contact_work_phone AS phoneNo,c.contact_other_phone AS otherNo,
c.contact_email AS email,c.tags AS tags,c.date_of_birth AS dateOfBirth,c.fax_number AS faxNo,
c.description AS description,c.sales_representative AS salesRepresentative,c.extension AS extension,
(select concat(first_name,'' '',last_name) from '+QUOTENAME(@Tenant)+'.'+'user_user_details where user_id=c.sales_representative) AS salesRep,
c.external_agency_id AS organizationId,(select e.external_agency_name from '+QUOTENAME(@Tenant)+'.'+'external_agency_details e where e.external_agency_id=c.external_agency_id) As organization,
c.contact_type AS jobTitle,c.contact_profile_pic AS contactProfilePic,c.contact_cadence AS contactCadence,
(select count(*) from '+QUOTENAME(@Tenant)+'.'+'job_details j where (j.referred_by=cast(c.contact_id AS CHAR) and j.referred_type=''People'') and j.current_job_status
 NOT IN(''Deleted''))  AS totalReferrals,
 (select count(*) from '+QUOTENAME(@Tenant)+'.'+'job_details j join '+QUOTENAME(@Tenant)+'.'+'common_milestones m on
 m.source_id=j.job_id where (j.referred_by=cast(c.contact_id AS CHAR) and j.referred_type=''People'') and m.dateofWorkAuthorization is not null and j.current_job_status
 NOT IN(''Deleted''))  AS soldReferrals,
 (select sum(j.total_invoice) from '+QUOTENAME(@Tenant)+'.'+'job_details j where (j.referred_by=cast(c.contact_id AS CHAR) and j.referred_type=''People'')  and j.current_job_status
 NOT IN(''Deleted''))  AS totalRevenue,c.contact_stage AS contactStage,
 (select TOP 1 DATEDIFF(day,dla.days_last_activity, '''+@EstDate+''') from '+QUOTENAME(@Tenant)+'.'+'contact_details dla where dla.contact_id=c.contact_id and dla.contact_status=''Active''
order by dla.days_last_activity desc)  as daysLastActivity
   from '+QUOTENAME(@Tenant)+'.'+'contact_details c

where c.contact_id= '+ cast (@contactId as NVARCHAR(10))


END
PRINT(@SQL)
EXEC (@SQL)
