CREATE OR ALTER PROCEDURE  [dbo].[crm_contact_list]
(@Tenant Varchar(255),@organizationId NVARCHAR(255))
As

DECLARE @SQL VARCHAR(MAX)
SET @SQL=N';

select c.contact_id as contactId,c.contact_first_name as firstName,c.contact_last_name as lastName,e.external_agency_name as organization,e.external_agency_id as organizationId,
c.contact_type as jobTitle,c.contact_email as email,c.contact_mobile_phone as mobile,c.contact_work_phone as phoneNo,c.contact_other_phone as otherNo,c.fax_number as faxNo,c.tags as tags,
c.date_of_birth as dateOfBirth,c.contact_address1 as mailingAddress,c.city as mailingAddressCity,c.state as mailingAddressState,c.zip as mailingAddressZip,c.contact_address2 as otherAddress,c.contact_address2_city as otherAddressCity,
c.contact_address2_state as otherAddressState,c.contact_address2_zip as otherAddressZip,c.sales_representative as salesRepresentative,concat(u.first_name,u.last_name) as salesRepName,
c.[extension] as extension,c.[contact_address1_formatted] as contactAddress1Format,c.[contact_address1_lat] as contactAddress1Lat,c.[contact_address1_lan] as contactAddress1Lan,
c.[contact_address2_formatted] as contactAddress2Format,c.[contact_address2_lat] as contactAddress2Lat,
c.[contact_address2_lan] as contactAddress2Lan,c.[contact_address1_country] as contactAddress1Country,
c.[contact_address2_country] as contactAddress2Country,c.[contact_profile_pic] as contactProfilePic,
c.[contact_cadence] as contactCadence,e.external_agency_type as organizationType,
(select(count(*)) from '+QUOTENAME(@tenant)+'.job_details j where j.job_Id in(select jc.job_Id from '+QUOTENAME(@tenant)+'.Job_Contacts jc where jc.contact_Id=c.contact_id and jc.status=''Active'')) as fileCount,
c.description as description  from '+QUOTENAME(@tenant)+'.contact_details c 
left join '+QUOTENAME(@tenant)+'.external_agency_details e on e.external_agency_id=c.external_agency_id 
left join '+QUOTENAME(@tenant)+'.user_user_details u on u.user_id = c.sales_representative and u.status=''Active''
where c.contact_status=''Active'''

IF(@organizationId is null or @organizationId = 'null')

BEGIN
SET @SQL=@SQL+' and c.contact_type not in (''Sales Representative'')';
END

ELSE
BEGIN

SET @SQL=@SQL+'  and c.external_agency_id='+@organizationId;

END


EXEC (@SQL)
print  (@SQL)
