-- Stored Procedure: [dbo].[crm_contact_notes_export]
-- Repeatable Migration - Re-runs when content changes
-- =============================================
CREATE OR ALTER PROCEDURE  [dbo].[crm_contact_notes_export]
(@Tenant Varchar(255))
As

DECLARE @SQL VARCHAR(MAX)

SET @SQL=N';

SELECT n.[notes]
      ,n.[contact_id]
      ,n.[updated_by]
      ,n.[updated_datetime]
      ,n.[source]
      ,n.[status]
      ,n.[external_ref_id]
	  ,u.[first_name] AS ''Written By (First Name)''
	  ,u.[last_name] AS ''Written By (Last Name)''
	  ,c.[contact_first_name]
	  ,c.[contact_last_name]
	  ,c.[contact_stage]
  FROM '+QUOTENAME(@Tenant)+'.'+'[contact_notes] n

  INNER JOIN '+QUOTENAME(@Tenant)+'.'+'[user_user_details] u
  ON u.[user_id] = n.[updated_by]

  LEFT JOIN '+QUOTENAME(@Tenant)+'.'+'[contact_details] c
   ON n.[contact_id] = c.[contact_id]

   ORDER BY n.[updated_datetime] DESC;';


EXEC (@SQL)
print  (@SQL)
GO

