(select sum(e.estimated_amount) from '+QUOTENAME(@Tenant)+'.'+'job_contacts jc,'+QUOTENAME(@Tenant)+'.'+'job_estimate e,'+QUOTENAME(@Tenant)+'.'+'job_details j where e.job_id=jc.job_id and jc.contact_id=c.contact_id and j.job_id=jc.job_id and j.job_id=e.job_id
 and j.current_job_status  NOT IN (''Closed'',''Rejected'')) as OpenJobAmount,
(select sum(e.estimated_amount) from '+QUOTENAME(@Tenant)+'.'+'job_contacts jc,'+QUOTENAME(@Tenant)+'.'+'job_estimate e,'+QUOTENAME(@Tenant)+'.'+'job_details j where e.job_id=jc.job_id and jc.contact_id=c.contact_id and j.job_id=jc.job_id and j.job_id=e.job_id
 and j.current_job_status IN (''Closed'')) as ClosedJobAmount,c.extension as extension,c.contact_profile_pic as contactProfilePic,c.contact_cadence as contactCadence 
,c.contact_stage As contactStage from '+QUOTENAME(@Tenant)+'.'+'contact_details c 
left join '+QUOTENAME(@Tenant)+'.'+'external_agency_details e on e.external_agency_id=c.external_agency_id and c.contact_status=''Active''
'


IF(@Type = 'Contacts')
BEGIN 
SET @SQL=@SQL+'where c.contact_status=''Active'' and c.contact_id='+ cast (@Id as NVARCHAR(10));
END 

ELSE
BEGIN
SET @SQL=@SQL+' where c.external_agency_id='+cast (@Id as NVARCHAR(10))+' and c.contact_status=''Active'' order by c.contact_first_name';
END

EXEC (@SQL)
print  (@SQL)
GO

