CREATE OR ALTER PROCEDURE  [dbo].[crm_document_expiration]
(@Tenant Varchar(255))
As

DECLARE @SQL VARCHAR(MAX)

SET @SQL=N';

SELECT [file_id]
	  ,[internal_file_name]
      ,[expiration_date]
	  ,e.[external_agency_name]
  FROM '+QUOTENAME(@Tenant)+'.'+'[crm_file_details] c

  INNER JOIN '+QUOTENAME(@Tenant)+'.'+'[external_agency_details] e ON 
  c.[source_id] = e.[external_agency_id] and c.source_category=''Organization''

  ORDER BY c.[expiration_date];';


EXEC (@SQL)
print  (@SQL)
