CASE
WHEN e.external_agency_type =''tpa'' THEN
(select count(*) from '+QUOTENAME(@Tenant)+'.'+'job_details j where j.tpa=e.external_agency_id and j.current_job_status not in (''Closed'',''Rejected''))
when  e.external_agency_type =''Insurance Company''
THEN
(select count(*) from '+QUOTENAME(@Tenant)+'.'+'job_details j,'+QUOTENAME(@Tenant)+'.'+'job_insurance_details i where
j.job_id = i.job_id and i.insurance_company=e.external_agency_id and j.current_job_status not in (''Closed'',''Rejected''))
ELSE
(select count(*) from '+QUOTENAME(@Tenant)+'.'+'job_details j,'+QUOTENAME(@Tenant)+'.'+'job_contacts jc,'+QUOTENAME(@Tenant)+'.'+'contact_details
cj
where j.job_Id=jc.job_Id  and jc.contact_Id=cj.contact_Id and  cj.external_Agency_Id=e.external_agency_id and cj.contact_status=''Active'' and j.current_job_status Not in (''Closed'',''Rejected''))
end
as openFilesCount,
CASE
WHEN e.external_agency_type =''tpa'' THEN
(select sum(je.estimated_amount) from '+QUOTENAME(@Tenant)+'.'+'job_estimate je,'+QUOTENAME(@Tenant)+'.'+'job_details j
where j.tpa=e.external_agency_id and je.job_id=j.job_id and j.current_job_status not in (''Closed'',''Rejected''))
when  e.external_agency_type =''Insurance Company''
THEN
(select sum(je.estimated_amount) from '+QUOTENAME(@Tenant)+'.'+'job_estimate je,'+QUOTENAME(@Tenant)+'.'+'job_details j,'+QUOTENAME(@Tenant)+'.'+'job_insurance_details i where
j.job_id = i.job_id and i.insurance_company=e.external_agency_id and je.job_id=j.job_id and j.current_job_status not in (''Closed'',''Rejected''))
ELSE
(select  sum(je.estimated_amount) from '+QUOTENAME(@Tenant)+'.'+'job_estimate je, '+QUOTENAME(@Tenant)+'.'+'job_details j,'+QUOTENAME(@Tenant)+'.'+'job_contacts jc,'+QUOTENAME(@Tenant)+'.'+'contact_details cj
where je.job_id=j.job_id and j.job_Id=jc.job_Id  and jc.contact_Id=cj.contact_Id and  cj.external_Agency_Id=e.external_agency_id and cj.contact_status=''Active'' and j.current_job_status Not in (''Closed'',''Rejected''))
end
as totalAmountSum,
(select sum(s.amount_spent) from '+QUOTENAME(@Tenant)+'.'+'sales_activities s where s.external_agency_id is not null and s.status != ''Deleted'' and s.external_agency_id=e.external_agency_id ) as jobSpent,'
BEGIN
SET @SQL=@SQL+'(CASE WHEN (select TOP 1 DATEDIFF(day,n.updated_datetime, '''+@EstDate+''') from '+QUOTENAME(@Tenant)+'.'+'external_agency_notes n where n.external_agency_id=e.external_agency_id and n.status=''Active''
order by updated_datetime desc) IS NOT NULL THEN (select TOP 1 DATEDIFF(day,n.updated_datetime, '''+@EstDate+''') from '+QUOTENAME(@Tenant)+'.'+'external_agency_notes n where n.external_agency_id=e.external_agency_id and n.status=''Active''
order by updated_datetime desc) ELSE DATEDIFF(day,e.created_datetime, '''+@EstDate+''') END) as daysLastActivity,e.created_datetime as createdDatetime, (select TOP 1 n.updated_datetime from '+QUOTENAME(@Tenant)+'.'+'external_agency_notes n
where n.external_agency_id=e.external_agency_id
and n.status=''Active'' order by updated_datetime desc) as lastNoteAdded,e.external_agency_address_lat AS externalAgencyAddressLat,e.external_agency_address_lan AS externalAgencyAddressLan,e.extension As extension,
(select top 1  DATEDIFF(day,j.created_datetime, getDate())
from '+QUOTENAME(@Tenant)+'.'+'job_details j where j.referred_type=''Organization'' and j.current_job_status not in (''Deleted'',''Rejected'') and j.referred_by=cast(e.external_agency_id AS CHAR)
order by j.created_datetime desc) as lastReferral,
e.contact_cadence as contactCadence,e.external_agency_stage AS externalAgencyStage '


END
BEGIN
SET @SQL=@SQL+'

from '+QUOTENAME(@Tenant)+'.'+'external_agency_details e
where e.external_agency_status=''Active''
'
END

IF(@SalesRepId !='null')
BEGIN
SET @SQL=@SQL+' and e.sales_representative = '''+@SalesRepId+''' order by  e.external_agency_name ASC';
END

ELSE
BEGIN
SET @SQL=@SQL  + 'order by  e.external_agency_name ASC';
END

print  (@SQL)
EXEC (@SQL)
GO

