CREATE OR ALTER PROCEDURE [dbo].[crm_org_leaderboard_java21]
(@Tenant VARCHAR(90),@externalAgencyId INT,@EstDate VARCHAR(90))
AS
BEGIN

DECLARE @SQL VARCHAR(MAX);
SET @SQL=N';
select e.external_agency_id as externalAgencyId,e.external_agency_name as externalAgencyName,
e.external_agency_type as externalAgencyType,
(select count(*) from '+QUOTENAME(@Tenant)+'.'+'job_details j where ((j.referred_by=cast(e.external_agency_id AS CHAR) and j.referred_type=''Organization'') or j.referred_by_org=e.external_agency_id ) and j.current_job_status
 NOT IN(''Deleted'',''Rejected''))  AS totalReferrals,
 (select count(*) from '+QUOTENAME(@Tenant)+'.'+'job_details j join '+QUOTENAME(@Tenant)+'.'+'common_milestones m on
 m.source_id=j.job_id where ((j.referred_by=cast(e.external_agency_id AS CHAR) and j.referred_type=''Organization'') or j.referred_by_org=e.external_agency_id ) and m.dateofWorkAuthorization is not null and j.current_job_status
 NOT IN(''Deleted'',''Rejected''))  AS soldReferrals,
 (select sum(j.total_invoice) from '+QUOTENAME(@Tenant)+'.'+'job_details j where ((j.referred_by=cast(e.external_agency_id AS CHAR) and j.referred_type=''Organization'') or j.referred_by_org=e.external_agency_id ) and j.current_job_status
 NOT IN(''Deleted'',''Rejected''))  AS totalRevenue,(CASE WHEN (select TOP 1 DATEDIFF(day,n.updated_datetime, '''+@EstDate+''') from '+QUOTENAME(@Tenant)+'.'+'external_agency_notes n where n.external_agency_id=e.external_agency_id and n.status=''Active''
order by updated_datetime desc) IS NOT NULL THEN (select TOP 1 DATEDIFF(day,n.updated_datetime, '''+@EstDate+''') from '+QUOTENAME(@Tenant)+'.'+'external_agency_notes n where n.external_agency_id=e.external_agency_id and n.status=''Active''
order by updated_datetime desc) ELSE DATEDIFF(day,e.created_datetime, '''+@EstDate+''') END) as daysLastActivity
 from '+QUOTENAME(@Tenant)+'.'+'external_agency_details e

where e.external_agency_id= '+ cast (@externalAgencyId as NVARCHAR(10))


END
PRINT(@SQL)
EXEC (@SQL)
GO

