-- =============================================
-- Stored Procedure: [dbo].[crm_org_notes_export]
-- Repeatable Migration - Re-runs when content changes
-- =============================================
CREATE OR ALTER PROCEDURE  [dbo].[crm_org_notes_export]
(@Tenant Varchar(255))
As

DECLARE @SQL VARCHAR(MAX)

SET @SQL=N';

SELECT n.[notes]
      ,n.[external_agency_id]
      ,n.[updated_by]
      ,n.[updated_datetime]
      ,n.[source]
      ,n.[status]
      ,n.[external_ref_id]
	  ,u.[first_name] AS ''Written By (First Name)''
	  ,u.[last_name] AS ''Written By (Last Name)''
	  ,e.[external_agency_name] AS ''Organization Name''
	  ,e.[external_agency_type] AS ''Organization Type''
	  ,e.[external_agency_stage] AS ''Sales Stage''
  FROM '+QUOTENAME(@Tenant)+'.'+'[external_agency_notes] n

  INNER JOIN '+QUOTENAME(@Tenant)+'.'+'[user_user_details] u
  ON u.[user_id] = n.[updated_by]

  LEFT JOIN '+QUOTENAME(@Tenant)+'.'+'[external_agency_details] e
   ON n.[external_agency_id] = e.[external_agency_id]

   ORDER BY [updated_datetime] DESC;';


EXEC (@SQL)
print  (@SQL)
GO

GO
-- =============================================
-- Stored Procedure: [dbo].[crm_organization_details_java21]
-- Repeatable Migration - Re-runs when content changes
-- =============================================
CREATE OR ALTER PROCEDURE [dbo].[crm_organization_details_java21](@Tenant VARCHAR(90), @OrgName VARCHAR(90), @EstDate VARCHAR(90),
                                                  @Type VARCHAR(90), @SalesRepId VARCHAR(90))
AS


DECLARE @SQL VARCHAR(MAX)

    SET @SQL = N';
select e.external_agency_id as companyId,e.external_agency_name as companyName,e.external_agency_phone1 as phone1,
e.external_agency_email as email,e.external_agency_address as address,e.external_agency_city as city,e.external_agency_state as state,
e.external_agency_fax as fax,e.description as description,e.external_agency_type as type,e.external_agency_code as companyCode,
e.external_agency_hash_code as companyHashCode,e.external_agency_zip as zip,e.open_files as openFiles,e.external_agency_website as website,
e.tags as tags,e.total_amount as totalAmount,e.external_agency_type as orgType, e.sales_representative as salesRepresentative,
(select u.first_name+'' ''+u.last_name from ' + QUOTENAME(@Tenant) + '.' + 'user_user_details u where u.user_id=e.sales_representative) as salesRepresentativeName,

CASE
WHEN e.external_agency_type =''tpa'' THEN
(select count(*) from ' + QUOTENAME(@Tenant) + '.' + 'job_details j where j.tpa=e.external_agency_id and j.current_job_status not in (''Closed'',''Rejected''))
when  e.external_agency_type =''Insurance Company''
THEN
(select count(*) from ' + QUOTENAME(@Tenant) + '.' + 'job_details j,' + QUOTENAME(@Tenant) + '.' + 'job_insurance_details i where
j.job_id = i.job_id and i.job_insurance_id=e.external_agency_id and j.current_job_status not in (''Closed'',''Rejected''))
ELSE
(select count(*) from ' + QUOTENAME(@Tenant) + '.' + 'job_details j,' + QUOTENAME(@Tenant) + '.' + 'job_contacts jc,' +
               QUOTENAME(@Tenant) + '.' + 'contact_details cj
where j.job_Id=jc.job_Id  and jc.contact_Id=cj.contact_Id and cj.external_Agency_Id=e.external_agency_id and cj.contact_status=''Active'' and j.current_job_status Not in (''Closed'',''Rejected''))
end
as openFilesCount,
CASE
WHEN e.external_agency_type =''tpa'' THEN
(select sum(je.estimated_amount) from ' + QUOTENAME(@Tenant) + '.' + 'job_estimate je,' + QUOTENAME(@Tenant) + '.' + 'job_details j
where j.tpa=e.external_agency_id and je.job_id=j.job_id and j.current_job_status not in (''Closed'',''Rejected''))
when  e.external_agency_type =''Insurance Company''
THEN
(select sum(je.estimated_amount) from ' + QUOTENAME(@Tenant) + '.' + 'job_estimate je,' + QUOTENAME(@Tenant) + '.' +
               'job_details j,' + QUOTENAME(@Tenant) + '.' + 'job_insurance_details i where
j.job_id = i.job_id and i.insurance_company=e.external_agency_id and je.job_id=j.job_id and j.current_job_status not in (''Closed'',''Rejected''))
ELSE
(select  sum(je.estimated_amount) from ' + QUOTENAME(@Tenant) + '.' + 'job_estimate je, ' + QUOTENAME(@Tenant) + '.' +
               'job_details j,' + QUOTENAME(@Tenant) + '.' + 'job_contacts jc,' + QUOTENAME(@Tenant) + '.' + 'contact_jobtitle_details cj
where je.job_id=j.job_id and j.job_Id=jc.job_Id  and jc.contact_Id=cj.contact_Id and  cj.external_Agency_Id=e.external_agency_id and cj.status=''Active'' and j.current_job_status Not in (''Closed'',''Rejected''))
end
as totalAmountSum,
(select sum(s.amount_spent) from ' + QUOTENAME(@Tenant) + '.' +
               'sales_activities s where s.external_agency_id is not null and s.status != ''Deleted'' and s.external_agency_id=e.external_agency_id ) as jobSpent,'
BEGIN
    SET @SQL = @SQL + '
(select count(*) from ' + QUOTENAME(@Tenant) + '.' +
               'sales_activities s where s.external_agency_id is not null and s.status != ''Deleted'' and s.external_agency_id=e.external_agency_id and s.activty_datetime >= DATEADD(DAY, -90,''' +
               @EstDate + ''')) as last90DaysActivity,
(select count(*) from ' + QUOTENAME(@Tenant) + '.' +
               'sales_activities s where s.external_agency_id is not null and s.status != ''Deleted'' and s.external_agency_id=e.external_agency_id and s.activty_datetime >= DATEADD(year, -1, ''' +
               @EstDate + ''')) as lastYearActivity,

(select count(*) from  ' + QUOTENAME(@Tenant) + '.' + 'job_details j where j.referred_type=''Organization'' and j.current_job_status IN(''Deleted'',''Rejected'') and j.referred_by=cast(e.external_agency_id AS CHAR)
and j.created_datetime>=  DATEADD(DAY, -90,''' + @EstDate + ''')) as last90DaysOrgReferral,'
    SET @SQL = @SQL + '
(select count(*) from  ' + QUOTENAME(@Tenant) + '.' + 'job_details j where j.referred_by_org=e.external_agency_id and j.current_job_status IN(''Deleted'',''Rejected'')
and j.created_datetime>=  DATEADD(DAY, -90, ''' + @EstDate + ''')) as last90DaysPeopleReferral,

(select count(*) from  ' + QUOTENAME(@Tenant) + '.' + 'job_details j where j.referred_type=''Organization'' and j.current_job_status IN(''Deleted'',''Rejected'') and j.referred_by=cast(e.external_agency_id AS CHAR)
and j.created_datetime>=  DATEADD(year, -1, ''' + @EstDate + ''')) as lastYearOrgReferral,

(select count(*) from  ' + QUOTENAME(@Tenant) + '.' + 'job_details j where j.referred_type=''people'' and j.referred_by_org=e.external_agency_id and j.current_job_status IN(''Deleted'',''Rejected'')
and j.created_datetime>=  DATEADD(year, -1, ''' + @EstDate + ''')) as lastYearPeopleReferral,
';

    SET @SQL = @SQL + 'LEAST(
 (CASE
        WHEN (
            SELECT TOP 1 DATEDIFF(DAY, n.updated_datetime,''' + @EstDate + ''')
            FROM ' + QUOTENAME(@Tenant) + '.' + 'external_agency_notes n
            WHERE n.external_agency_id = e.external_agency_id AND n.status = ''Active''
            ORDER BY n.updated_datetime DESC
        ) IS NOT NULL
        THEN (
            SELECT TOP 1 DATEDIFF(DAY, n.updated_datetime,''' + @EstDate + ''')
            FROM ' + QUOTENAME(@Tenant) + '.' + 'external_agency_notes n
            WHERE n.external_agency_id = e.external_agency_id AND n.status = ''Active''
            ORDER BY n.updated_datetime DESC
        )
        ELSE DATEDIFF(DAY, e.created_datetime,''' + @EstDate + ''')
        END
    ),
    (CASE
        WHEN (
            SELECT TOP 1 DATEDIFF(DAY, sa.updated_datetime,''' + @EstDate + ''')
            FROM ' + QUOTENAME(@Tenant) + '.' + 'sales_activities sa
            WHERE sa.external_agency_id = e.external_agency_id
            ORDER BY sa.updated_datetime DESC
        ) IS NOT NULL
        THEN (
            SELECT TOP 1 DATEDIFF(DAY, sa.updated_datetime, ''' + @EstDate + ''')
            FROM ' + QUOTENAME(@Tenant) + '.' + 'sales_activities sa
            WHERE sa.external_agency_id = e.external_agency_id
            ORDER BY sa.updated_datetime DESC
        )
        ELSE DATEDIFF(DAY, e.created_datetime, ''' + @EstDate + ''')
        END
    )) AS daysLastActivity,e.created_datetime as createdDatetime,
(select TOP 1 n.updated_datetime from ' + QUOTENAME(@Tenant) + '.' + 'external_agency_notes n
where n.external_agency_id=e.external_agency_id
and n.status=''Active'' order by updated_datetime desc) as lastNoteAdded,e.external_agency_address_lat AS externalAgencyAddressLat,
e.external_agency_address_lan AS externalAgencyAddressLan,e.extension As extension,
(select count(*) from  '+QUOTENAME(@Tenant)+'.'+'job_details j where j.referred_type=''Organization'' and j.current_job_status NOT IN (''Deleted'',''Rejected'') and  j.referred_by=cast(e.external_agency_id AS CHAR)
) as directOrgReferral,

(select count(*) from  '+QUOTENAME(@Tenant)+'.'+'job_details j where j.referred_type=''people'' and j.current_job_status NOT IN (''Deleted'',''Rejected'') and j.referred_by_org = e.external_agency_id) as inDirectOrgReferral,'


    SET @SQL = @SQL + '(select top 1  DATEDIFF(day,j.created_datetime, getDate())
from ' + QUOTENAME(@Tenant) + '.' + 'job_details j where j.referred_type=''Organization'' and j.current_job_status IN(''Deleted'',''Rejected'') and j.referred_by=cast(e.external_agency_id AS CHAR)
order by j.created_datetime desc) as lastReferral,

(select top 1  DATEDIFF(day,j.created_datetime, getDate())
from ' + QUOTENAME(@Tenant) + '.' + 'job_details j where j.referred_type=''Organization'' and j.current_job_status IN(''Deleted'',''Rejected'') and j.referred_by=cast(e.external_agency_id AS CHAR)
order by j.created_datetime ASC) as xValue,

(select MAX(t.rowNumber) from (SELECT count(*) OVER () AS rowNumber
FROM  ' + QUOTENAME(@Tenant) + '.' + 'job_details j where j.referred_type=''Organization'' and j.current_job_status IN(''Deleted'',''Rejected'') and j.referred_by=CAST(e.external_agency_id AS CHAR)
group by convert(varchar,j.created_datetime,23)) As t) as yValue,e.contact_cadence as contactCadence,e.external_agency_stage as externalAgencyStage, e.campaign as campaign '


    SET @SQL = @SQL + ' from ' + QUOTENAME(@Tenant) + '.' + 'external_agency_details e
where e.external_agency_status=''Active''
'
END
    IF (@OrgName = 'null')
        BEGIN
            SET @SQL = @SQL;
        END

    ELSE
        BEGIN

            SET @SQL = @SQL + ' and e.external_agency_name like ''%' + @OrgName + '%''  ';

        END
    IF (@Type = 'My')
        BEGIN
            SET @SQL = @SQL + ' and e.sales_representative = ''' + @SalesRepId + ''' order by  e.external_agency_name';
        END

    ELSE
        BEGIN
            SET @SQL = @SQL + 'order by  e.external_agency_name';
        END
    EXEC (@SQL)
    print (@SQL)
GO

GO
