-- =============================================
CREATE OR ALTER PROCEDURE [dbo].[crm_organizationJob_ViewDetails]
(@Tenant VARCHAR(90),@Id INT,@Type VARCHAR(90))
AS


DECLARE @SQL VARCHAR(MAX)

SET @SQL=N';

select j.job_id as jobId,j.job_code as subJobCode,j.job_hash_code as jobhashCode,j.job_type as jobType,j.loss_address as lossAddress,
j.loss_address_city as city,j.loss_address_state as state,j.loss_address_zip as zip,
j.created_datetime as createdDatetime,m.mast_num_id as mastNumId,m.mast_num_code as mastNumCode,m.mast_num_hash as mastNumHash,
c.last_name+'' ''+c.first_name as customerName,
c.mobile as phoneNo,c.email as email
from '+QUOTENAME(@Tenant)+'.'+'job_details j,'+QUOTENAME(@Tenant)+'.'+'mast_num_details m,
'+QUOTENAME(@Tenant)+'.'+'customer_details c'

IF(@Type ='TPA')

BEGIN 
SET @SQL=@SQL +' where m.mast_num_id=j.mast_num_id and m.customer_id=c.customer_id and  
j.current_job_status not in (''Closed'',''Rejected'') and c.status=''Active'' and j.tpa='+ cast (@Id as NVARCHAR(10));
END 

ELSE IF(@Type ='INSURANCE')

BEGIN 
SET @SQL=@SQL +','+QUOTENAME(@Tenant)+'.'+'job_insurance_details ji  where m.mast_num_id=j.mast_num_id and m.customer_id=c.customer_id and  
j.current_job_status not in (''Closed'',''Rejected'') and ji.job_id=j.job_id and c.status=''Active'' and ji.job_insurance_id='+ cast (@Id as NVARCHAR(10));
END

Else

BEGIN 
SET @SQL=@SQL +','+QUOTENAME(@Tenant)+'.'+'job_contacts jc,'+QUOTENAME(@Tenant)+'.'+'contact_details cj 
where m.mast_num_id=j.mast_num_id and m.customer_id=c.customer_id and  
j.current_job_status not in (''Closed'',''Rejected'') and c.status=''Active'' and j.job_id=jc.job_id
and jc.contact_Id=cj.contact_Id and cj.contact_status=''Active'' 
and cj.external_agency_id='+ cast (@Id as NVARCHAR(10));
END 


EXEC (@SQL)
print  (@SQL)
GO

GO
