THEN
(select sum(je.estimated_amount) from '+QUOTENAME(@Tenant)+'.'+'job_estimate je,'+QUOTENAME(@Tenant)+'.'+'job_details j,'+QUOTENAME(@Tenant)+'.'+'job_insurance_details i where
j.job_id = i.job_id and i.job_insurance_id=e.external_agency_id and je.job_id=j.job_id and j.current_job_status not in (''Closed'',''Rejected''))
ELSE
(select  sum(je.estimated_amount) from '+QUOTENAME(@Tenant)+'.'+'job_estimate je, '+QUOTENAME(@Tenant)+'.'+'job_details j,'+QUOTENAME(@Tenant)+'.'+'job_contacts jc,'+QUOTENAME(@Tenant)+'.'+'contact_details cj
 where je.job_id=j.job_id and j.job_Id=jc.job_Id  and jc.contact_Id=cj.contact_Id and  cj.external_Agency_Id=e.external_agency_id and cj.contact_status=''Active'' and j.current_job_status Not in (''Closed'',''Rejected''))
end
as totalAmountSum,
CASE
WHEN e.external_agency_type =''tpa'' THEN
(select sum(je.estimated_amount) from '+QUOTENAME(@Tenant)+'.'+'job_estimate je,'+QUOTENAME(@Tenant)+'.'+'job_details j
where j.tpa=e.external_agency_id and je.job_id=j.job_id and j.current_job_status  in (''Closed''))
when  e.external_agency_type =''Insurance Company''
THEN
(select sum(je.estimated_amount) from '+QUOTENAME(@Tenant)+'.'+'job_estimate je,'+QUOTENAME(@Tenant)+'.'+'job_details j,'+QUOTENAME(@Tenant)+'.'+'job_insurance_details i where
j.job_id = i.job_id and i.job_insurance_id=e.external_agency_id and je.job_id=j.job_id and j.current_job_status in (''Closed''))
ELSE
(select sum(je.estimated_amount) from '+QUOTENAME(@Tenant)+'.'+'job_estimate je,'+QUOTENAME(@Tenant)+'.'+'job_details j
 where  je.job_id=j.job_id and j.current_job_status in (''Closed'') and j.company_id=e.external_agency_id)
end
as ClosedFilesTotalAmount,
(select sum(s.amount_spent) from '+QUOTENAME(@Tenant)+'.'+'sales_activities s where s.external_agency_id=e.external_agency_id ) as jobSpent,e.organization_profile_pic as organizationProfilePic,
e.extension AS extension,e.contact_cadence as contactCadence,e.external_agency_stage AS externalAgencyStage, e.campaign AS campaign
 from '+QUOTENAME(@Tenant)+'.'+'external_agency_details e
 where e.external_agency_status=''Active''
 '

BEGIN

SET @SQL=@SQL+' and e.external_agency_id='+cast (@OrgId as NVARCHAR(10));

END

