-- =============================================
-- Stored Procedure: [dbo].[crm_salesActivity_calendar_list_java21]
-- Repeatable Migration - Re-runs when content changes
-- =============================================
CREATE OR ALTER PROCEDURE [dbo].[crm_salesActivity_calendar_list_java21]
@Tenant VARCHAR(90),@startDate NVARCHAR(90),@endDate NVARCHAR(90)
AS
BEGIN

DECLARE @SQL VARCHAR(MAX)

SET @SQL=N';
select ROW_NUMBER() OVER (ORDER BY CAST(e.created_datetime AS DATE) desc) AS id,e.schedule_id as scheduleId,
(case when e.schedule_start_date is null then concat(e.schedule_date,'' '',''00:00:00'') else e.schedule_start_date end) as scheduleStartDate,
(case when e.schedule_end_date is null then concat(DateADD(D,1,e.schedule_date),'' '',''00:00:00'') else e.schedule_end_date end) as scheduleEndDate,
(select u.first_name+'' ''+u.last_name from '+QUOTENAME(@Tenant)+'.'+'user_user_details u where u.user_id=ed.technician_id and ed.status=''Active'') as technicianName,

e.sales_activity_type as salesActivityType,e.arrival_time as arrivalTime,
e.expected_duration as expectedDuration,ed.technician_id as technicianId,
e.description,e.location,e.event_occurrence as eventOccurrence,ed.schedule_detail_id as scheduleDetailId,
e.title  as title,e.type_of_visit as typeOfVisit,e.external_agency_id as organizationId,e.contact_id as contactId,
o.external_agency_name as organizationName,
c.contact_first_name+'' ''+c.contact_last_name as contactName,
e.all_day_event as allDayEvent,e.amount_budgeted as amountBudgeted,e.amount_spent as amountSpent,
e.calendar_guid as internalId,e.calendar_type as calendarType,e.external_guid as externalId,e.activity_status as activityStatus,
e.appointment_type as appointmentType


from '+QUOTENAME(@Tenant)+'.'+'ems_schedule e
left join '+QUOTENAME(@Tenant)+'.'+'ems_schedule_details ed on ed.schedule_id=e.schedule_id and ed.status=''Active''
left join '+QUOTENAME(@Tenant)+'.'+'contact_details c on c.contact_id=e.contact_id and c.contact_status=''Active''
left join '+QUOTENAME(@Tenant)+'.'+'external_agency_details o on o.external_agency_id=e.external_agency_id and o.external_agency_status=''Active'''


BEGIN
SET @SQL=@SQL+'where e.status=''Active'' and ((e.schedule_start_date >='''+ @startDate+''' and  e.schedule_end_date <= '''+@endDate+''') or
(e.schedule_date>='''+ @startDate+''' and e.schedule_date <= '''+@endDate+''')) '
END

END
EXEC (@SQL)
print  (@SQL)
GO

GO
