e.all_day_event as allDayEvent,e.amount_budgeted as amountBudgeted,e.amount_spent as amountSpent,
e.calendar_guid as internalId,e.calendar_type as calendarType,e.external_guid as externalId,e.activity_status as activityStatus,
e.appointment_type as appointmentType


from '+QUOTENAME(@Tenant)+'.'+'ems_schedule e
left join '+QUOTENAME(@Tenant)+'.'+'ems_schedule_details ed on ed.schedule_id=e.schedule_id and ed.status=''Active''
left join '+QUOTENAME(@Tenant)+'.'+'contact_details c on c.contact_id=e.contact_id and c.contact_status=''Active''
left join '+QUOTENAME(@Tenant)+'.'+'external_agency_details o on o.external_agency_id=e.external_agency_id and o.external_agency_status=''Active'''


BEGIN
SET @SQL=@SQL+'where e.status=''Active'' and ((e.schedule_start_date >='''+ @startDate+''' and  e.schedule_end_date <= '''+@endDate+''') or 
(e.schedule_date>='''+ @startDate+''' and e.schedule_date <= '''+@endDate+''')) '
END

END
EXEC (@SQL)
print  (@SQL)
GO

