-- =============================================
-- Stored Procedure: [dbo].[crm_salesActivity_details_list]
-- Repeatable Migration - Re-runs when content changes
-- =============================================
CREATE OR ALTER PROCEDURE [dbo].[crm_salesActivity_details_list]
@userId INT,@Tenant VARCHAR(90),@type VARCHAR(90)
AS
BEGIN

DECLARE @SQL VARCHAR(MAX)

SET @SQL=N';
select s.sales_activity_id as activityId,s.activity_title as activityName,s.activity_desc as description,
s.sales_activity_type as activityType,s.activty_datetime as scheduledDatetime,s.amount_budgeted as amountBudgeted,s.amount_spent as amountSpent,
s.external_agency_id as organizationId,s.contact_id as contactId,o.external_agency_name as organizationName,
c.contact_first_name+'' ''+c.contact_last_name as contactName,u.first_name+'' ''+u.last_name as userName , 
s.status as status,s.user_id as assigneeId,u.first_name+'' ''+u.last_name as assignedTo, s.comments as notes
from '+QUOTENAME(@Tenant)+'.'+'sales_activities s
left join '+QUOTENAME(@Tenant)+'.'+'contact_details c on c.contact_id=s.contact_id
left join '+QUOTENAME(@Tenant)+'.'+'external_agency_details o on o.external_agency_id=s.external_agency_id
left join '+QUOTENAME(@Tenant)+'.'+'user_user_details u on u.user_id=s.user_id'
IF(@type = 'My Open')
BEGIN
SET @SQL=@SQL+' where s.status=''Not Completed'' and s.user_id='+ cast (@userId as NVARCHAR(10))
END
ELSE IF(@type = 'All Open')
BEGIN
SET @SQL=@SQL+' where s.status=''Not Completed'' '
END
ELSE IF(@type = 'Completed')
BEGIN
SET @SQL=@SQL+' where s.status=''Completed'' '
END

END
EXEC (@SQL)
GO

