-- =============================================
-- Stored Procedure: [dbo].[sales_activities_export]
-- Repeatable Migration - Re-runs when content changes
-- =============================================
CREATE OR ALTER PROCEDURE  [dbo].[sales_activities_export]
(@Tenant Varchar(255))
As

DECLARE @SQL VARCHAR(MAX)

SET @SQL=N';

SELECT u.[first_name] as "User First Name"
	  ,u.[last_name] as "User Last Name"
      ,s.[activity_title]
      ,s.[activity_desc]
      ,s.[sales_activity_type]
      ,s.[comments] as "CRM Note"
	  ,s.[updated_datetime] as "Note Entered Date"
      ,s.[amount_budgeted]
      ,s.[amount_spent]
      ,s.[source]
      ,s.[status]
	  ,c.[contact_first_name] as "CRM Contact First"
	  ,c.[contact_last_name] as "CRM Contact Last"
	  ,e.[external_agency_name] as "CRM Company Name"
  FROM '+QUOTENAME(@Tenant)+'.'+'[sales_activities] s

  INNER JOIN '+QUOTENAME(@Tenant)+'.'+'[user_user_details] u
  ON s.[user_id]=u.[user_id]

  LEFT JOIN '+QUOTENAME(@Tenant)+'.'+'[contact_details] c
  ON s.[contact_id]=c.[contact_id]

  LEFT JOIN '+QUOTENAME(@Tenant)+'.'+'[external_agency_details] e
  ON s.[external_agency_id]=e.[external_agency_id]



  WHERE s.[status] = ''Completed''
  AND s.[comments] IS NOT NULL

  ORDER BY s.[updated_datetime] DESC;';


EXEC (@SQL)
print  (@SQL)





GO

