-- =============================================
-- Stored Procedure: [dbo].[all_estimates]
-- Repeatable Migration - Re-runs when content changes
-- =============================================
CREATE OR ALTER PROCEDURE [dbo].[all_estimates]
    @Tenant NVARCHAR(50),
    @startDate DATETIME,
    @endDate DATETIME
AS
BEGIN

    DECLARE @SQL NVARCHAR(MAX);

    SET @SQL = '
    SELECT
        ROW_NUMBER() OVER (ORDER BY je.estimate_id) AS rowId,
        je.estimated_amount AS estimatedAmt,
        je.comments AS comments,
        je.document_id AS documentId,
        (SELECT job_code 
         FROM ' + QUOTENAME(@Tenant) + '.job_details jd 
         WHERE jd.job_id = je.job_id) AS fileNumber,
		je.source AS source,
        je.status AS status,
        je.estimated_datetime AS estimatedDatetime,
        je.updated_datetime AS updatedDatetime,
        (SELECT CONCAT(first_name, '' '', last_name) 
         FROM ' + QUOTENAME(@Tenant) + '.user_user_details 
         WHERE user_id = je.estimated_by) AS createdBy,
        (SELECT CONCAT(first_name, '' '', last_name) 
         FROM ' + QUOTENAME(@Tenant) + '.user_user_details 
         WHERE user_id = je.updated_by) AS updatedBy
    FROM ' + QUOTENAME(@Tenant) + '.job_estimate je
    WHERE je.estimated_datetime BETWEEN @startDate AND @endDate 
      AND je.status = ''Active'';
    ';

    -- Execute the dynamic SQL query
    EXEC sp_executesql @SQL, N'@startDate DATETIME, @endDate DATETIME', @startDate, @endDate;
END;
GO

