    @endDate DATETIME
AS
BEGIN

    DECLARE @SQL NVARCHAR(MAX);
 
    SET @SQL = '
    SELECT
	   ROW_NUMBER() OVER (ORDER BY fi.doc_id) AS rowId,
	    fi.doc_id AS docId,
	    fi.doc_no AS docNo,
        fi.doc_type AS docType,
		fi.doc_date AS docDate,
        fi.doc_amt AS docAmt,
		fi.file_number AS fileNumber,
		fi.source AS source ,
		fi.status AS status,
		fi.sub_total_amount AS subTotalAmount,
        fi.tax_amount AS taxAmount,
		fi.quickbook_ref_no AS quickbookRefNo,
        fi.transaction_date AS transactionDate,
        fi.created_datetime AS createdDatetime,
        fi.updated_datetime AS updatedDatetime,
       (SELECT CONCAT(first_name, '' '', last_name) 
         FROM ' + QUOTENAME(@Tenant) + '.user_user_details 
         WHERE user_id = fi.created_by) AS createdBy,
        (SELECT CONCAT(first_name, '' '', last_name) 
         FROM ' + QUOTENAME(@Tenant) + '.user_user_details 
         WHERE user_id = fi.updated_by) AS updatedBy,
        fi.comments AS comments
        
    FROM ' + QUOTENAME(@Tenant) + '.file_invoice fi
    WHERE fi.doc_date BETWEEN @startDate AND @endDate
    AND fi.doc_type Not IN (''Payments'', ''Payment'') AND fi.status=''Active'';
    ';
 
    -- Execute
    EXEC sp_executesql @SQL, N'@startDate DATETIME, @endDate DATETIME', @startDate, @endDate;
END;
