CREATE OR ALTER PROCEDURE [dbo].[all_workOrders]
    @Tenant NVARCHAR(50),
    @startDate DATETIME,
    @endDate DATETIME
AS
BEGIN
    DECLARE @SQL NVARCHAR(MAX);

    SET @SQL = N'
    SELECT 
        ROW_NUMBER() OVER (ORDER BY wo.work_order_id) AS rowId,
        wo.work_order_name AS workOrderName,
        wo.work_order_desc AS workOrderDesc,
        wo.source_type AS sourceType,
        wo.assignee_name AS assigneeName,
        wo.category AS category,
        wo.base_value AS baseValue,
        wo.budget_percentage AS budgetPercentage,
        wo.budgeted_hours AS budgetedHours,
        wo.budget_amount AS budgetAmount,
        wo.created_datetime AS createdDatetime,
        wo.updated_datetime AS updatedDatetime,
        jd.job_code AS fileNumber,
		wo.source AS source,
        wo.status AS status,
        wo.start_date AS startDate,
        wo.end_date AS endDate,
        wo.po_number AS poNumber,
        wo.actual_cost_amount AS actualCostAmount,
        wo.assignee_type AS assigneeType,
        wo.assignee_email AS assigneeEmail,
        wo.type AS type,
        (SELECT CONCAT(first_name, '' '', last_name) 
         FROM ' + QUOTENAME(@Tenant) + '.user_user_details 
         WHERE user_id = wo.created_by) AS createdBy,
        (SELECT CONCAT(first_name, '' '', last_name) 
         FROM ' + QUOTENAME(@Tenant) + '.user_user_details 
         WHERE user_id = wo.updated_by) AS updatedBy
    FROM 
        ' + QUOTENAME(@Tenant) + '.job_work_orders AS wo
    INNER JOIN 
        ' + QUOTENAME(@Tenant) + '.job_details AS jd
    ON 
        wo.source_id = jd.job_id
    WHERE 
        wo.created_datetime BETWEEN @startDate AND @endDate 
        AND wo.status != ''Deleted'';';
    
    EXEC sp_executesql @SQL, N'@startDate DATETIME, @endDate DATETIME', @startDate, @endDate;
