	  ,e.[estimate_id]
      ,e.[job_id]
      ,e.[document_id]
      ,e.[estimated_amount]
      ,e.[comments]
      ,e.[source]
      ,e.[status]
      ,e.[estimated_by]
      ,e.[estimated_datetime]
      ,e.[updated_by]
