  LEFT JOIN '+QUOTENAME(@Tenant)+'.'+'[user_user_details] u
  ON e.[estimated_by] = u.[user_id]

  WHERE e.[estimated_datetime] >=GETDATE() - 7
  ORDER BY [email_id];';


