-- =============================================
CREATE OR ALTER PROCEDURE [dbo].[file_cost_export_tenant68] (@Tenant AS VARCHAR(255))
AS
BEGIN
DECLARE @SQL VARCHAR(MAX)
SET @SQL=N';
SELECT 
f.[vendor_name],f.[doc_no],f.[doc_amt],f.[file_number],j.[created_datetime] as "File Created Date"
,f.[category_name],f.[category_description],j.[job_name],j.[total_estimates]
,ROUND(j.[total_invoice], 2, 1) AS "Total Invoiced"
,ROUND(j.[total_payment], 2, 1) AS "Total Payments"
,ROUND(j.[total_invoice] - j.[total_payment], 2, 1) as "Balance Owing"
FROM '+QUOTENAME(@Tenant)+'.[file_cost] f INNER JOIN '+QUOTENAME(@Tenant)+'.[job_details] j ON 
f.[file_number] = j.[job_code]
WHERE YEAR(j.[created_datetime]) > 2022
  AND f.[status] = ''Active'''
END;
EXEC (@SQL)
