-- =============================================
CREATE OR ALTER PROCEDURE  [dbo].[payroll_details_by_user_proc_java21]
(@Tenant Varchar(255),@startDate Datetime,@endDate Datetime,@timeOffStartDate Datetime,@timeOffEndDate Datetime,@userId int)
As

DECLARE @SQL VARCHAR(MAX)
SET @SQL=N';

select p.user_payroll_id AS userPayrollId,u.user_id AS userId,u.first_name AS firstName,u.last_name AS lastName,
u.first_name+'' ''+u.last_name AS empName,p.shift_date AS shiftDate, p.timesheet_approval_status AS timesheetApprovalStatus, p.clock_in_time AS clockInTime,p.clock_out_time AS clockOutTime,
			p.duration AS duration,p.hourly_rate AS hourlyRate,p.total_cost AS totalCost,p.created_datetime AS createdDatetime,
			p.additional_details AS additionalDetails,p.labor_type AS laborType,p.hour_type AS hourType,p.job_id AS jobId,p.source,
			(select j.job_code from '+QUOTENAME(@Tenant)+'.job_details j where j.job_id=p.job_id) as jobCode,
			(select j.job_type from '+QUOTENAME(@Tenant)+'.job_details j where j.job_id=p.job_id) as jobType,
			(select j.job_name from '+QUOTENAME(@Tenant)+'.job_details j where j.job_id=p.job_id) as jobName,
            p.tsheet_user_name as tsheetUserName,p.source as source,p.tsheet_user_id as tsheetUserId,p.status status
			from '+QUOTENAME(@Tenant)+'.user_payroll_details p,'+QUOTENAME(@Tenant)+'.user_user_details u where p.user_id=u.user_id and
			((p.clock_in_time>='''+CONVERT(nvarchar, @startDate)+''' and p.labor_type IN(''Uncategorized/Shop'',''Labor'',''Travel Time'') and p.clock_in_time<='''+CONVERT(nvarchar, @endDate)+''')
			or (p.clock_in_time>='''+CONVERT(nvarchar, @timeOffStartDate)+''' and p.labor_type is null and p.clock_in_time<='''+CONVERT(nvarchar, @timeOffEndDate)+'''))';
	SET @SQL=@SQL+' and p.user_id='''+cast (@userId as NVARCHAR(10))+''' and p.status=''Active'' order by p.clock_in_time';


EXEC (@SQL)
print  (@SQL)
GO

