CREATE OR ALTER PROCEDURE  [dbo].[qb_file_list_java21]
(@Tenant Varchar(255),@locationId INT)
As

DECLARE @SQL VARCHAR(MAX)
SET @SQL=N';

select j.job_id AS jobId,j.job_code AS jobCode,j.job_hash_code AS jobHashCode,j.job_type AS jobType,j.current_job_status AS currentJobStatus,
j.qb_status As qbStatus,j.qb_flag AS qbFlag,j.first_name AS firstName,j.last_name AS lastName,j.customer_type AS customerType,
j.customer_company_name AS customerCompanyName,j.company AS company,j.qb_date AS qbDate,j.qbo_status AS qboStatus,j.job_name AS jobName,j.qbo_date AS qboDate,j.qbo_customer_failure AS qboCustomerFailure,
(select location_city from '+QUOTENAME(@Tenant)+'.'+'rest_comp_location where rest_comp_location_id=j.rest_comp_location_id) AS locationName,
j.qbd_customer_failure AS qbdCustomerFailure,j.created_datetime AS createdDatetime
 from '+QUOTENAME(@Tenant)+'.'+'job_details j where j.created_datetime> ''2019-01-01 00:00:00'' and j.current_job_status NOT IN(''Closed'',''Rejected'',''Deleted'') '
IF(@locationId != 0)
BEGIN
