SET @SQL=N';
select  jd.job_id AS jobId,';
IF(@Tenant = 'tenant31')
BEGIN
SET @SQL=@SQL+'
CASE when jd.first_name is not null then jd.last_name'+'+'',''+'+' first_name
ELSE jd.customer_company_name END AS customerName,'
END
ELSE IF(@Tenant = 'tenant34')
BEGIN
SET @SQL=@SQL+'
CASE when jd.first_name is not null then LTRIM(RTRIM(jd.last_name))'+'+'', ''+'+' LTRIM(RTRIM(first_name))
ELSE jd.customer_company_name END AS customerName,'
END
ELSE IF(@Tenant = 'tenant53')
BEGIN
SET @SQL=@SQL+'
CASE when jd.first_name is not null then LTRIM(RTRIM(jd.last_name))'+'+'', ''+'+' LTRIM(RTRIM(first_name))
ELSE jd.customer_company_name END AS customerName,'
END
ELSE
BEGIN
SET @SQL=@SQL+'
CASE when jd.first_name is not null then jd.first_name'+'+'', ''+'+' last_name
ELSE jd.customer_company_name END AS customerName,'
END
SET @SQL=@SQL+'replace(replace(jd.job_code, ''FN'', '' ''), ''_'' , '' '') ''jobName'',
LTRIM(RTRIM(jd.first_name)) ''firstName'',
LTRIM(RTRIM(jd.last_name)) ''lastName'',
jd.customer_company_name ''customerCompanyName'',
jd.customer_company_name ''companyName'',
jd.billing_address AS billingAddress,
jd.billing_address_city AS city,
jd.billing_address_state AS state,
jd.billing_address_zip AS zip,
''USA'' ''country'',
jd.loss_address AS shippingAddress,
jd.loss_address_city AS sCity,
jd.loss_address_state AS sState,
jd.loss_address_zip AS sZip,
''USA'' ''sCountry'',
jd.email AS email,
      jd.phone1 AS homePhone,
jd.mobile AS cellPhone,
i.claim_number AS cliamNumber,
'' '' AS salesRepresentative,
m.startdate AS startDate,
m.targetcompletiondate AS targetCompletionDate,
m.dateOfcOs AS cocDate
from

'+QUOTENAME(@Tenant)+'.'+'job_details as jd
left join '+QUOTENAME(@Tenant)+'.'+'v_roles as r
on jd.job_id = r.job_id
left join '+QUOTENAME(@Tenant)+'.'+'[common_milestones] m
on jd.job_id = m.source_id
left join '+QUOTENAME(@Tenant)+'.'+'[job_insurance_details] i
on i.job_id=jd.job_id
where ((current_job_status In (''Planning'', ''Production'', ''Receivables'', ''Invoicing'') and (qb_flag=''Y'' or qb_flag is null)) or qb_flag=''Y'') and (qb_status is null or qb_status=''Failure'') and
convert(date,jd.created_datetime, 110) >= (select [qb_start_date] from '+QUOTENAME(@Tenant)+'.'+'[rest_comp_details])'
END
EXEC (@SQL)
GO

