-- =============================================
-- Stored Procedure: [dbo].[form_list_offline]
-- Repeatable Migration - Re-runs when content changes
-- =============================================
CREATE OR ALTER PROCEDURE [dbo].[form_list_offline]
 (@Tenant Varchar(255),@Franchisor_Name varchar(255),@Type varchar(50),@listType varchar(100),
 @lastSyncDate varchar(100), @start VARCHAR(50),@end VARCHAR(50)) 
AS
BEGIN
    DECLARE @SQL VARCHAR(MAX)
    SET @SQL=N';
    Select f.form_template_id,f.form_content,f.form_type,f.operational_notes,f.display_mode'

	
IF(@Type = 'Tasks')
BEGIN
SET @SQL=@SQL+',f.form_name'
END
ELSE 
BEGIN
SET @SQL=@SQL+',(CASE when f.source=''Franchisor'' then concat(f.form_name,'' - '','''+@Franchisor_Name+''') ELSE f.form_name END)  AS form_name'
END

SET @SQL=@SQL+' from '+QUOTENAME(@Tenant)+'.form_templates f where f.status=''Active''';
END

IF(@listType = 'partial')
BEGIN

SET @SQL= @SQL+' and (f.created_datetime >='''+ @lastSyncDate+''' or f.updated_datetime >= '''+ @lastSyncDate+''')';
END

BEGIN
SET @SQL=@SQL+' ORDER BY f.form_template_id DESC OFFSET ' +@start+ ' ROWS FETCH NEXT '+@end+ ' ROWS ONLY ';
END
EXEC (@SQL)
print  (@SQL)
GO

