-- =============================================
-- Stored Procedure: [dbo].[Loadfranchisee_m_taskpack_tasks]
-- Repeatable Migration - Re-runs when content changes
-- =============================================
CREATE OR ALTER PROCEDURE [dbo].[Loadfranchisee_m_taskpack_tasks]
(
@Franchisor INT,
@FranchisorSchema NVARCHAR(50)
)
AS
BEGIN
-- SET NOCOUNT ON added to prevent extra result sets from
    -- interfering with SELECT statements.
    SET NOCOUNT ON;
    -- update statements for procedure here

 

DECLARE @SQL VARCHAR(MAX)
DECLARE @Contractor NVARCHAR(50)
DECLARE  @list nvarchar(MAX)
DECLARE  @i int
SET @i=1
SET @list=(SELECT COUNT([SCHEMA_NAME]) FROM [common].[rest_comp_details] WHERE REST_COMP_ID IN 
(SELECT contractor FROM [common].[association] WHERE host=@Franchisor))

 

DROP TABLE IF EXISTS #temp
CREATE TABLE #temp(ID INT IDENTITY(1,1),Franchisee NVARCHAR(100))
INSERT INTO #temp
SELECT [SCHEMA_NAME] FROM [common].[rest_comp_details] WHERE REST_COMP_ID IN 
(SELECT contractor FROM [common].[association] WHERE host=@Franchisor)

 

WHILE(@i<=@list)

 

BEGIN

 

SET @Contractor = (SELECT [Franchisee] FROM #temp WHERE ID=@i)

 

SET @SQL=N'MERGE '+@Contractor+'.m_taskpack_tasks AS TARGET
USING (SELECT m.task_id,tP.taskpack_id,tp.[source],p.assign_type,
   p.action_required,(select task_action_id from '+@Contractor+'.task_action_configuration where action=p.action_required) as 
   action_id,p.trigger_event,(select event_id from '+@Contractor+'.task_trigger_events where event_name=p.trigger_event) as trigger_event_id,
   p.time_to_complete,p.time_uom,p.task_sequence,
   (case when p.assign_type=''Role'' then (select r.role_id from '+@Contractor+'.m_roles r 
   INNER JOIN '+@FranchisorSchema+'.m_roles fr ON fr.role_name=r.role_name and fr.role_id=p.assign_to)
   else (select d.division_id from '+@Contractor+'.m_divisions d
   INNER JOIN '+@FranchisorSchema+'.m_divisions fd ON fd.division_name=d.division_name and fd.division_id=p.assign_to)end) as assign_to
       FROM '+@Contractor+'.m_tasks as m
       INNER JOIN '+@FranchisorSchema+'.m_tasks as k
       ON k.task_name=m.task_name 
       INNER JOIN '+@FranchisorSchema+'.m_taskpack_tasks as p
           ON K.task_id = p.task_id
       INNER JOIN '+@FranchisorSchema+'.m_taskpacks as c
           ON P.taskpack_id = c.taskpack_id
		INNER JOIN '+@Contractor+'.m_taskpacks as tp
		ON tp.taskpack_name = c.taskpack_name
      ) AS SOURCE
ON 
   TARGET.task_id = [SOURCE].task_id 
   AND TARGET.taskpack_id=[SOURCE].taskpack_id 

 

WHEN MATCHED THEN
       UPDATE SET   TARGET.task_id = SOURCE.task_id
                   ,TARGET.taskpack_id = SOURCE.taskpack_id
                   ,TARGET.[source] = SOURCE.[source]

 

WHEN NOT MATCHED BY TARGET
THEN INSERT ([task_id],[taskpack_id],[Source],[assign_type],assign_to,[action_required],[action_id],[trigger_event],[trigger_event_id],[time_to_complete],[time_uom],[task_sequence])  
     VALUES (SOURCE.task_id,SOURCE.taskpack_id,''Franchisor'',SOURCE.assign_type,SOURCE.assign_to,SOURCE.action_required,SOURCE.action_id,SOURCE.trigger_event,SOURCE.trigger_event_id,SOURCE.time_to_complete,SOURCE.time_uom,SOURCE.task_sequence)

 

WHEN NOT MATCHED BY SOURCE AND TARGET.source=''Franchisor''
THEN DELETE;
'

 

PRINT(@SQL)
EXEC(@SQL)
SET @i=@i+1
END

 

END
GO

GO
