-- =============================================
-- Stored Procedure: [dbo].[franchisor_financial_performance_report_java21]
-- Repeatable Migration - Re-runs when content changes
-- =============================================
CREATE OR ALTER PROCEDURE [dbo].[franchisor_financial_performance_report_java21]
(@Franchisor Varchar(25),@startDate Datetime,@endDate Datetime)
AS
BEGIN
    DECLARE @SQL VARCHAR(MAX) = ''
    DECLARE @listCursor CURSOR
    DECLARE @contractor VARCHAR(25)
	DECLARE @franchisee VARCHAR(255)
    DECLARE @isFirst BIT = 1

    SET @listCursor = CURSOR FOR
   SELECT a.contractor, r.rest_comp_title FROM common.association a INNER JOIN common.rest_comp_details r ON a.contractor = r.rest_comp_id
    WHERE a.host = @Franchisor AND a.status = 'Active'

    OPEN @listCursor
    FETCH NEXT FROM @listCursor INTO @contractor,@franchisee

    WHILE @@FETCH_STATUS = 0
    BEGIN
        IF @isFirst = 0
        BEGIN
            SET @SQL = @SQL + ' UNION ALL '
        END

        SET @SQL = @SQL + '

            SELECT ''' + @franchisee + ''' AS Franchisee,

            (SELECT COUNT(*) FROM ' + QUOTENAME('tenant'+@contractor) + '.job_details WHERE CAST(created_datetime AS DATE) BETWEEN ''' + CONVERT(VARCHAR, @startDate, 23) + ''' AND ''' + CONVERT(VARCHAR, @endDate, 23) + ''') AS jobLeadsReceived,

            (SELECT COUNT(*) FROM ' + QUOTENAME('tenant'+@contractor) + '.job_estimate WHERE CAST(estimated_datetime AS DATE) BETWEEN ''' + CONVERT(VARCHAR, @startDate, 23) + ''' AND ''' + CONVERT(VARCHAR, @endDate, 23) + ''' AND status = ''Active'') AS estimatesWritten,

            (SELECT SUM(estimated_amount) FROM ' + QUOTENAME('tenant'+@contractor) + '.job_estimate WHERE CAST(estimated_datetime AS DATE) BETWEEN ''' + CONVERT(VARCHAR, @startDate, 23) + ''' AND ''' + CONVERT(VARCHAR, @endDate, 23) + ''' AND status = ''Active'') AS estimateValue,

            (SELECT COUNT(*) FROM ' + QUOTENAME('tenant'+@contractor) + '.file_invoice WHERE doc_date BETWEEN ''' + CONVERT(VARCHAR, @startDate, 23) + ''' AND ''' + CONVERT(VARCHAR, @endDate, 23) + ''' AND status = ''Active'' AND doc_type IN (''Invoice'', ''Sales Receipts'', ''Credit Memos'')) AS invoicesWritten,

            (SELECT SUM(doc_amt) FROM ' + QUOTENAME('tenant'+@contractor) + '.file_invoice WHERE doc_date BETWEEN ''' + CONVERT(VARCHAR, @startDate, 23) + ''' AND ''' + CONVERT(VARCHAR, @endDate, 23) + ''' AND status = ''Active'' AND doc_type IN (''Invoice'', ''Sales Receipts'', ''Credit Memos'')) AS invoiceValue,

            (SELECT COUNT(*) FROM ' + QUOTENAME('tenant'+@contractor) + '.file_invoice WHERE doc_date BETWEEN ''' + CONVERT(VARCHAR, @startDate, 23) + ''' AND ''' + CONVERT(VARCHAR, @endDate, 23) + ''' AND status = ''Active'' AND doc_type IN (''Payments'', ''Payment'')) AS paymentsCollected,

            (SELECT SUM(doc_amt) FROM ' + QUOTENAME('tenant'+@contractor) + '.file_invoice WHERE doc_date BETWEEN ''' + CONVERT(VARCHAR, @startDate, 23) + ''' AND ''' + CONVERT(VARCHAR, @endDate, 23) + ''' AND status = ''Active'' AND doc_type IN (''Payments'', ''Payment'')) AS totalCollected
        '

        SET @isFirst = 0

        FETCH NEXT FROM @listCursor INTO @contractor,@franchisee
    END

    CLOSE @listCursor
    DEALLOCATE @listCursor

    EXEC (@SQL)
END
GO

GO
