-- =============================================
CREATE OR ALTER PROCEDURE  [dbo].[franchisor_reports_data_java21]
(@Tenant Varchar(255),@startDate Datetime,@endDate Datetime,@Week INT)
As

DECLARE @SQL VARCHAR(MAX)
DECLARE @weekDay Int = @Week -1;
SET @SQL=N';
SET DATEFIRST ' +cast (@Week as NVARCHAR(10))+ ' SELECT j.jobId,j.subJobCode,j.jobHashCode,j.jobType,j.job_Name,j.firstName,j.lastName
,j.lossAddress,j.city,j.state,j.zip,j.locationId,j.status,j.company,j.mastNumCode,j.mobile,j.workPhone,j.phone1,j.adjuster,
j.insuranceAgent,j.propertyManager,j.publicAdjuster,j.independentAdjuster,j.cycleTime,j.wipTime,j.TotalFinalInvoiceTime,j.daysToStart,j.estimateBidTime,j.finalEstimateUploadTime,
j.onsiteArrivalTime,j.targetCompletion,j.contactCustomerTime,j.daysToSign,j.finalInvoiceDelayTime,';
BEGIN
SET @SQL=@SQL+'j.grossProfit,j.LaborEfficiencyRation,j.cycleTimeTargetVal,j.wipTimeTargetVal,j.TotalFinalInvoiceTimeTargetVal,j.daysToStartTargetVal,
j.estimateBidTimeTargetVal,j.finalEstimateUploadTimeTargetVal,j.onsiteArrivalTimeTargetVal,
j.targetCompletionTargetVal,j.contactCustomerTimeTargetVal,j.daysToSignTargetVal,
j.finalInvoiceDelayTimeTargetVal,j.grossProfitTargetVal,j.LaborEfficiencyRationTargetVal,j.dateofLoss,
j.dateReceived,j.datecontacted,j.dateinspected,j.dateofWorkAuthorization,j.dateEstimatesent,
j.dateEstimateApproved,j.dateinventoried,j.intoProductiondate,j.targetStartDate,j.startdate,
j.dateofmajoritycompletion,j.targetcompletiondate,j.dateOfcOs,j.dateinvoiced,j.finalInvoiceDate,
j.datePaid,j.closeddate,j.createdDatetime,j.fileDate,j.referredSoure,j.tpa,j.customerType,j.customerCompanyName,
j.referenceNumber,j.customerName,j.lastActivity,j.email,j.propertyType,j.programType,j.causeOfLoss,j.insuranceCompany,
j.claimNumber,j.npsScore,j.referredSource,j.referredBy,j.comments,j.reason,j.contractor,j.opportunityId,j.roughEstimate,
j.fileAge,j.ageInCurrentStatus,j.referredByOrganizationName,j.tpaCategory,j.rowId,j.id,j.franchisorId,'
END
BEGIN
SET @SQL=@SQL+'j.franchisorName,j.contractorid,j.totalCost,j.totalCredits,j.totalInvoice,j.totalPayment,j.franchiseeTotalCost,
j.franchiseeTotalCredits,j.franchiseeTotalInvoice,j.franchiseeTotalPayment,j.opportunityName,j.opportunityCode,j.opportunityHashCode,
j.opportunityStatus,j.opportunityReceivedDate,j.opportunityCreatedBy,j.opportunityCreatedDatetime,j.franchiseeAuthToken,j.licenseNumber,
j.restCompPhoneNum,j.marketingCampaign,j.marketingOwner,j.marketingChannel,j.marketingLeadDetails,
j.ownerId,j.territoryId,j.marketingSource,
';
END
BEGIN
SET @SQL=@SQL+'
DATEADD(day, DATEDIFF(day, ' +cast (@weekDay as NVARCHAR(10))+ ',j.createdDatetime) /7*7, ' +cast (@weekDay as NVARCHAR(10))+ ') as createdWeek,
DATEADD(day, DATEDIFF(day, ' +cast (@weekDay as NVARCHAR(10))+ ',j.dateofLoss) /7*7, ' +cast (@weekDay as NVARCHAR(10))+ ') as lossDateWeek,
