DATEADD(day, DATEDIFF(day, ' +cast (@weekDay as NVARCHAR(10))+ ',j.dateinspected) /7*7, ' +cast (@weekDay as NVARCHAR(10))+ ') as dateInspectedWeek,
DATEADD(day, DATEDIFF(day, ' +cast (@weekDay as NVARCHAR(10))+ ',j.dateofWorkAuthorization) /7*7, ' +cast (@weekDay as NVARCHAR(10))+ ') as dateWorkAuthorizationWeek,
