DATEADD(day, DATEDIFF(day, ' +cast (@weekDay as NVARCHAR(10))+ ',j.intoProductiondate) /7*7, ' +cast (@weekDay as NVARCHAR(10))+ ') as intoProductiondateWeek,
DATEADD(day, DATEDIFF(day, ' +cast (@weekDay as NVARCHAR(10))+ ',j.targetStartDate) /7*7, ' +cast (@weekDay as NVARCHAR(10))+ ') as targetStartDateWeek,
DATEADD(day, DATEDIFF(day, ' +cast (@weekDay as NVARCHAR(10))+ ',j.startdate) /7*7, ' +cast (@weekDay as NVARCHAR(10))+ ') as startDateWeek,
