DATEADD(day, DATEDIFF(day, ' +cast (@weekDay as NVARCHAR(10))+ ',j.dateOfcOs) /7*7, ' +cast (@weekDay as NVARCHAR(10))+ ') as dateOfCOsWeek,
DATEADD(day, DATEDIFF(day, ' +cast (@weekDay as NVARCHAR(10))+ ',j.dateinvoiced) /7*7, ' +cast (@weekDay as NVARCHAR(10))+ ') as dateInvoicedWeek,

DATEADD(day, DATEDIFF(day, ' +cast (@weekDay as NVARCHAR(10))+ ',j.finalInvoiceDate) /7*7, ' +cast (@weekDay as NVARCHAR(10))+ ') as finalInvoiceDateWeek,
DATEADD(day, DATEDIFF(day,' +cast (@weekDay as NVARCHAR(10))+ ',j.datePaid) /7*7, ' +cast (@weekDay as NVARCHAR(10))+ ') as datePaidWeek,
DATEADD(day, DATEDIFF(day,' +cast (@weekDay as NVARCHAR(10))+ ',j.closeddate) /7*7, ' +cast (@weekDay as NVARCHAR(10))+ ') as closedDateWeek,
DATEADD(day, DATEDIFF(day,' +cast (@weekDay as NVARCHAR(10))+ ', j.fileDate) /7*7, ' +cast (@weekDay as NVARCHAR(10))+ ') as dashFileCreatedDateWeek';
END
BEGIN
SET @SQL=@SQL+',j.supervisor,j.estimator,j.salesRepresentative,j.coordinator,j.finance,j.administrator,j.role,j.leadTechnician,j.lastScheduledVisit,j.totalEstimate'
END
BEGIN
SET @SQL=@SQL+' from '+QUOTENAME(@Tenant)+'.'+'franchisor_reports j
 where j.createdDatetime>='''+CONVERT(nvarchar, @startDate)+''' and j.status !=''Deleted'' and j.createdDatetime<='''+CONVERT(nvarchar, @endDate)+''' order by j.createdDatetime desc';
END

