            dateOfcOs AS ''COC (Actual Completion Date)'',
            dateinvoiced AS ''Date Invoiced'',
            finalInvoiceDate AS ''Final Invoice Date'',
            datePaid AS ''Date Paid'',
            closeddate AS ''Closed Date'',
            createdDatetime AS ''Created Datetime'',
            fileDate AS ''File Date'',
            tpa AS ''TPA'',
            lastActivity AS ''Days Since Last Activity'',
            email AS ''Email'',
