            programType AS ''Program Type'',
            causeOfLoss AS ''Cause of Loss'',
            insuranceCompany AS ''Insurance Company'',
            claimNumber AS ''Claim Number'',
            referredSource AS ''Referred Source'',
            referredBy AS ''Referred By'',
            opportunityId AS ''Opportunity ID'',
            roughEstimate AS ''Rough Estimate'',
            fileAge AS ''File Age'',
            ageInCurrentStatus AS ''Age in Current Status'',
            referredByOrganizationName AS ''Referred By Organization'',
            tpaCategory AS ''TPA Category'',
