            franchiseeTotalCost AS ''Franchisee Total Cost'',
            franchiseeTotalCredits AS ''Franchisee Total Credits'',
            franchiseeTotalInvoice AS ''Franchisee Total Invoice'',
            franchiseeTotalPayment AS ''Franchisee Total Payment'',
            opportunityName AS ''Opportunity Name'',
            opportunityCode AS ''Opportunity Number'',
            opportunityStatus AS ''Status'',
            opportunityReceivedDate AS ''Opportunity Received Date'',
            licenseNumber AS ''License Number'',
            restCompPhoneNum AS ''Contractor Phone Number'',
            ownerId AS ''Owner'',
            marketingCampaign AS ''Marketing Campaign'',
            marketingOwner AS ''Marketing Owner'',
            marketingChannel AS ''Marketing Channel'',
            marketingSource AS ''Marketing Source'',
            marketingLeadDetails AS ''Marketing Lead Details'',
            supervisor AS ''Supervisor'',
            estimator AS ''Estimator'',
            salesRepresentative AS ''Sales Representative'',
            coordinator AS ''Coordinator'',
            finance AS ''Finance'',
            administrator AS ''Administrator'',
            role AS ''Role'',
            leadTechnician AS ''Lead Technician'',
            totalEstimate AS ''Total Estimate'',
            CASE
                WHEN status IN (''New'', ''Estimating (Initial)'', ''Sales'', ''On Hold'') THEN ''Pending''
                WHEN status = ''Rejected'' THEN ''Not Sold''
                ELSE ''Sold''
            END AS ''Sold Status''
        ';

    -- Add specific columns for tenant351
    IF @Tenant = 'tenant351'
        BEGIN
            SET @SQL += N',
            contractor_hashcode AS ''Contractor Hashcode'',
            CURRENT_TIMESTAMP AS ''DataGeneratedDate''';
        END;

    -- Complete the dynamic SQL with the FROM clause
    SET @SQL += N' FROM ' + QUOTENAME(@Tenant) + '.franchisor_reports';

    -- Execute the dynamic SQL
    EXEC sp_executesql @SQL;
END;
