-- =============================================
-- Stored Procedure: [dbo].[Franchisor_task_list]
-- Repeatable Migration - Re-runs when content changes
-- =============================================
CREATE OR ALTER PROCEDURE [dbo].[Franchisor_task_list]
(@Tenant VARCHAR(90),@franchisee VARCHAR(90),@opportunityType VARCHAR(90),@opportunityId INT)
AS


DECLARE @SQL VARCHAR(MAX)

SET @SQL=N';
select c.task_id,c.task_title,c.source,c.source_id,c.assigned_to,c.assigned_to_role,c.expected_start_datetime,
c.expected_end_datetime,c.actual_start_datetime,c.actual_end_datetime,c.assign_type,
case when c.status =''To Do'' then
''Upcoming''
else c.status end as status,
case when c.assign_type = ''User'' then
(select concat(u.first_name,'' '',u.last_name) from '+QUOTENAME(@franchisee)+'.'+'user_user_details u where u.user_id=ct.assigned_to and u.status=''Active'')
 when c.assign_type = ''Corporate User'' then
(select concat(u.first_name,'' '',u.last_name) from '+QUOTENAME(@Tenant)+'.'+'user_user_details u where u.user_id=c.assigned_to and u.status=''Active'')
when c.assign_type =''Role'' and c.status !=''Completed'' and c.status !=''Rejected'' then
	concat(c.assigned_to_role ,'' Role'')  
when c.assign_type =''Division'' and c.status !=''Completed'' and c.status !=''Rejected'' then
	 (select concat(division_name,'' Division'') from '+QUOTENAME(@franchisee)+'.'+'m_divisions m where m.division_id=ct.assigned_to and m.status = ''Active'') 
else
	case when c.assign_type = ''Corporate'' and (c.status  = ''Completed'' or c.status = ''Rejected'') then
	(select concat(u.first_name,'' '',u.last_name) from '+QUOTENAME(@Tenant)+'.'+'user_user_details u where u.user_id=c.assigned_to and u.status=''Active'')
	when (c.assign_type = ''Role'' or c.assign_type = ''Division'' ) and (c.status  = ''Completed'' or c.status = ''Rejected'') then
	case when ct.task_completed_by is not null then ct.task_completed_by else
	(select concat(u.first_name,'' '',u.last_name) from '+QUOTENAME(@franchisee)+'.'+'user_user_details u where u.user_id=ct.assigned_to and u.status=''Active'')
	end
	else concat(c.assigned_to_role ,'' Role'')  end
	 
END as ownerName,c.closed_reason,c.delay_reason,c.comments,c.time_to_complete,c.time_uom,c.task_approval_status,c.zapier_updated_by,
c.updated_by,c.updated_datetime,c.action_required,c.action_type,c.action_value,c.event_type,c.rejected_reason,c.previous_status,
c.trigger_event,c.action_required_doc_type,c.task_type,c.task_desc,ct.task_id as franchisee_task_id,c.mark_milestone,
c.change_status_upon_completion,
c.change_corporate_status_upon_completion,
c.assignment_notification,
c.icon_id

from '+QUOTENAME(@Tenant)+'.'+'common_tasks c 
left join '+QUOTENAME(@franchisee)+'.'+'common_tasks ct on ct.ref_task_id=c.task_id 
where c.source_id = '+ cast (@opportunityId as NVARCHAR(10))+'  and c.source='''+@opportunityType+'''
order by c.task_sequence '


EXEC (@SQL)
print  (@SQL)
GO

