-- =============================================
-- Stored Procedure: [dbo].[Franchisor_task_summary_list]
-- Repeatable Migration - Re-runs when content changes
-- =============================================
CREATE OR ALTER PROCEDURE [dbo].[Franchisor_task_summary_list]
(@Tenant VARCHAR(90),@franchisor VARCHAR(90),@opportunityType VARCHAR(90),@type NVARCHAR(20),@userId INT,@currentDate Datetime)
AS


DECLARE @SQL VARCHAR(MAX)
--SET @Tenant='tenant';

SET @SQL=N';
select c.task_id,c.task_title,c.task_desc,c.source,c.source_id,c.assigned_to,c.assigned_to_role,c.expected_start_datetime,
c.expected_end_datetime,c.actual_start_datetime,c.actual_end_datetime,c.assign_type,
case when c.status =''To Do'' then
''Upcoming''
else c.status end as status,'

IF(@Type = 'MyFiles')
BEGIN
SET @SQL=@SQL+'( select concat(u.first_name,'' '',u.last_name) from '+QUOTENAME(@Tenant)+'.'+'user_user_details u 
where u.user_id=c.assigned_to and u.status=''Active'' and c.assign_type = ''Corporate'' )'
END

ELSE
BEGIN
SET @SQL = @SQL+ '
case when c.assign_type = ''User'' then
(select concat(u.first_name,'' '',u.last_name) from '+QUOTENAME(@Tenant)+'.'+'user_user_details u where u.user_id=c.assigned_to and u.status=''Active'')
when c.assign_type =''Role'' then
	concat(c.assigned_to_role ,'' Role'')  
when c.assign_type =''Division'' then
	 (select concat(division_name,'' Division'') from '+QUOTENAME(@Tenant)+'.'+'m_divisions m where m.division_id=c.assigned_to and m.status = ''Active'') 
else
	case when status  = ''Completed'' or status = ''Rejected'' then
	(select concat(u.first_name,u.last_name) from '+QUOTENAME(@franchisor)+'.'+'user_user_details u where u.user_id=c.assigned_to and u.status=''Active'')
	else concat(c.assigned_to_role ,'' Role'')  end
	 
END '
END
BEGIN
	SET @SQL = @SQL+ ' as ownerName,

	c.closed_reason,c.delay_reason,c.comments,c.time_to_complete,c.time_uom,c.task_approval_status,c.zapier_updated_by,
	c.updated_by,c.updated_datetime,c.action_required,c.action_type,c.action_value,c.event_type,c.rejected_reason,c.previous_status,
	c.trigger_event,c.action_required_doc_type,
	 o.tpa_name  as tpa,
	(select concat(u.first_name,'' '',u.last_name) from '+QUOTENAME(@Tenant)+'.'+'opportunity_roles r,'+QUOTENAME(@Tenant)+'.'+'user_user_details u
	where r.opportunity_id =c.source_id and r.role_name=''Administrator''  and u.user_id=r.user_id and u.status=''Active'') as administrator,
	 o.tpa_category_name as tpaCategoryName,o.mast_num_code as mast_num_code,o.job_code as jobCode,o.job_hash_code as jobHashCode,
	 o.opportunity_name as opportunityName,
	 (select r.rest_comp_auth_token from common.rest_comp_details r where r.rest_comp_id=o.association_id and r.rest_comp_status=''Active'')
	 as restCompAuthToken,o.association_id as contractor,o.reference_file_number as referenceFileNumber,
	 (select r.rest_comp_name from common.rest_comp_details r where r.rest_comp_id=o.association_id and r.rest_comp_status=''Active'') as
	 contractorName,
	 o.opportunity_id,
     o.opportunity_hash_code,
     o.opportunity_code,
     o.job_type,
	 c.change_status_upon_completion,
	 c.change_corporate_status_upon_completion,
	 c.assignment_notification,
	 c.icon_id,
	 c.task_type,
	 (case when c.expected_end_datetime<'''+CONVERT(nvarchar, @currentDate)+''' and c.status != ''Completed'' and c.status!=''Rejected'' then ''true'' else ''false'' end) as overDue
	from '+QUOTENAME(@Tenant)+'.'+'common_tasks c
	Join '+QUOTENAME(@franchisor)+'.'+'opportunity_details o on o.opportunity_id=c.source_id
	where c.source='''+@opportunityType+''' '

	IF(@Type = 'MyTasks')
		BEGIN
			SET @SQL=@SQL+'  and c.source_id in (select opportunity_id from '+QUOTENAME(@Tenant)+'.'+'opportunity_roles where user_id='+ cast (@userId as NVARCHAR(10))+') ';
		END

	SET @SQL=@SQL+' order by c.task_id desc'
END

EXEC (@SQL)
print  (@SQL)
GO

