CREATE OR ALTER PROCEDURE [dbo].[GetEntry_Franchisor]
(
@franchisor NVARCHAR(50),
@franchisee NVARCHAR(50),
@opportunity_id NVARCHAR(50),
@assignmentDate Datetime,
@franchisee_name VARCHAR(250),
@franchiseeId NVARCHAR(50),
@oppHashCode NVARCHAR(50))

AS
BEGIN
-- SET NOCOUNT ON added to prevent extra result sets from
	-- interfering with SELECT statements.
	SET NOCOUNT OFF;
    -- Insert statements for procedure here

DECLARE @SQL NVARCHAR(MAX)

--INSERT INTO [tenant1].[opportunity_details] SELECT * FROM [tenant70].[opportunity_details]
--WHERE opportunity_id=@opportunity_id;

SET @SQL=N'INSERT INTO '+@franchisor+'.'+'[opportunity_details] 
           (
           [rest_comp_location_id]
           ,[opportunity_desc]
           ,[is_insured]
           ,[is_duplicate]
           ,[job_type]
           ,[payment_terms_id]
           ,[loss_address]
           ,[loss_address_city]
           ,[loss_address_state]
           ,[loss_address_zip]
           ,[billing_address]
           ,[billing_address_city]
           ,[billing_address_state]
           ,[billing_address_zip]
           ,[is_billing_address_same]
           ,[geo_location]
           ,[current_opportunity_status]
           ,[referred_source]
           ,[property_type]
		   ,[program_type]
		   ,[cause_of_loss]
		   ,[year_built]
           ,[created_by]
           ,[created_datetime]
		   ,[updated_by]
           ,[updated_datetime]
           ,[source]
           ,[loss_date]
           ,[first_name]
           ,[last_name]
           ,[email]
           ,[mobile]
           ,[work_phone]
           ,[phone]
           ,[customer_type]
		   ,[customer_company]
           ,[customer_company_name]
		   ,[company_id]
		   ,[company]
           ,[last_activity]
           ,[scratchpad]
           ,[scratchpad_date]
           ,[opportunity_name]
           ,[unit_number]
           ,[loss_address_country]
           ,[loss_address_lat]
           ,[loss_address_lan]
           ,[loss_address_formatted]
           ,[billing_address_country]
           ,[billing_address_lat]
           ,[billing_address_lan]
           ,[billing_address_formatted]
           ,[gate_code]
           ,[communication_type]
           ,[rooms_affected]
           ,[wage_rate]
           ,[billing_address_unit]
           ,[association_id]
           ,[referred_by]
           ,[referred_type]
		   ,[opportunity_received_date]
		   ,[responsible_party]
		   ,[emergency_loss]
		   ,[tpa_category]
		   ,[reference_file_number]
		   ,[tpa_category_name]
		   )'
END

BEGIN
SET @SQL=@SQL+ 'SELECT 
       [rest_comp_location_id]
      ,[opportunity_desc]
      ,[is_insured]
      ,[is_duplicate]
      ,[job_type]
      ,[payment_terms_id]
      ,[loss_address]
      ,[loss_address_city]
      ,[loss_address_state]
      ,[loss_address_zip]
      ,[billing_address]
      ,[billing_address_city]
      ,[billing_address_state]
      ,[billing_address_zip]
      ,[is_billing_address_same]
      ,[geo_location]
      ,[current_opportunity_status]
      ,[referred_source]
	  ,[property_type]
	  ,(select mp.program_type_id from '+@franchisee+'.'+'m_program m 
left join '+@franchisor+'.'+'m_program mp on mp.program_type = m.program_type  and mp.status=''Active''
where op.program_type = m.program_type_id  and m.status=''Active'') as program_type,

(select mc.config_id from '+@franchisee+'.'+'m_config_data m
left join '+@franchisor+'.'+'m_config_data mc on mc.config_value=m.config_value and mc.status=''Active''
where m.config_name =''Cause of Loss'' and m.config_id = op.cause_of_loss and m.status=''Active''
) as causeOfLoss
	  ,(select mc.config_id from '+@franchisee+'.'+'m_config_data m
left join '+@franchisor+'.'+'m_config_data mc on mc.config_value=m.config_value and mc.status=''Active''
where m.config_name =''Year Built'' and m.config_id = op.year_built and m.status=''Active''
) as yearBuilt 
      ,1
      ,'''+cast ( @assignmentDate as nvarchar(100))+'''
	  ,1
      ,'''+cast ( @assignmentDate as nvarchar(100))+'''
      ,'''+@franchisee_name+'''
      ,[loss_date]
      ,[first_name]
      ,[last_name]
      ,[email]
      ,[mobile]
      ,[work_phone]
      ,[phone]
      ,[customer_type]
	  ,[customer_company]
	  ,[customer_company_name]
	  ,[company_id]
	  ,[company]
      ,[last_activity]
      ,[scratchpad]
      ,[scratchpad_date]
      ,[opportunity_name]
      ,[unit_number]
      ,[loss_address_country]
      ,[loss_address_lat]
      ,[loss_address_lan]
      ,[loss_address_formatted]
      ,[billing_address_country]
      ,[billing_address_lat]
      ,[billing_address_lan]
      ,[billing_address_formatted]
      ,[gate_code]
      ,[communication_type]
      ,[rooms_affected]
      ,[wage_rate]
      ,[billing_address_unit]
      ,'+@franchiseeId+'
      ,(CASE
WHEN op.referred_type =''Organization'' THEN
(select e.external_agency_name from '+@franchisor+'.'+'external_agency_details e where e.external_agency_id=op.referred_by) 
WHEN op.referred_type =''People'' THEN
(select c.contact_first_name+'' ''+c.contact_last_name from '+@franchisor+'.'+'contact_details c where c.contact_id=op.referred_by)
ELSE
op.referred_by
end
)as referredBy
      ,[referred_type]
	  ,[opportunity_received_date]
     ,[responsible_party]
	 ,[emergency_loss]
	 ,(select e.external_agency_category_id from '+@franchisor+'.'+'external_agency_category e where e.category_name = op.tpa_category_name and e.status=''Active'')
	 ,[reference_file_number]
	  ,[tpa_category_name]
	  FROM '+@franchisee+'.'+'[opportunity_details] op
WHERE op.opportunity_id='+@opportunity_id+''

PRINT(@SQL)
EXEC(@SQL)
END

DECLARE @SQL1 NVARCHAR(MAX)
DECLARE @FranchisorOppId NVARCHAR(100)
/***set @FranchisorOppId = 1162;***/
BEGIN

set @FranchisorOppId ='select Max(opportunity_id) from '+@franchisor+'.'+'opportunity_details';
/*** EXEC @FranchisorOppId = (@SQL1);

Set @SQL1 = N'update '+@franchisor+'.'+'opportunity_details set 
opportunity_hash_code=concat('''+@oppHashCode+''','+@FranchisorOppId+'),
opportunity_code = 100000 + '+@FranchisorOppId+' where opportunity_id='+@FranchisorOppId;***/
BEGIN
Set @SQL1 = N'update '+@franchisor+'.'+'opportunity_details set 
opportunity_hash_code=concat('''+@oppHashCode+''',('+@FranchisorOppId+')),
opportunity_code =concat(''O-'', 100000 + ('+@FranchisorOppId+')) where opportunity_id=('+@FranchisorOppId+')';

PRINT(@SQL1)
Exec(@SQL1)
END

DECLARE @SQL2 NVARCHAR(MAX)
BEGIN
set @SQL2 =N'update '+@franchisee+'.'+'opportunity_details set
actual_opportunity_id=('+@FranchisorOppId+') where opportunity_id ='+@opportunity_id;
PRINT(@SQL2)
Exec(@SQL2)
END

PRINT(@FranchisorOppId)
Exec(@FranchisorOppId)
END
