-- =============================================
-- Stored Procedure: [dbo].[all_jobs_report_adr]
-- Repeatable Migration - Re-runs when content changes
-- =============================================
CREATE OR ALTER PROCEDURE  [dbo].[all_jobs_report_adr]
(@Tenant Varchar(255),@locationId INT)
As

DECLARE @SQL VARCHAR(MAX)
SET @SQL=N';With cte as
(select jr.job_id,u.first_name+'' ''+u.last_name as supervisor from '+QUOTENAME(@Tenant)+'.'+'user_user_details u 
inner join '+QUOTENAME(@Tenant)+'.'+'job_roles jr on u.user_id=jr.user_id
where jr.role_name=''Supervisor'' and jr.job_role_status=''Active''),
cte2 as 
(select jr.job_id,u.first_name+'' ''+u.last_name as estimator from '+QUOTENAME(@Tenant)+'.'+'user_user_details u 
inner join '+QUOTENAME(@Tenant)+'.'+'job_roles jr on u.user_id=jr.user_id
where jr.role_name=''Estimator'' and jr.job_role_status=''Active''),
cte3 as
(select jr.job_id,u.first_name+'' ''+u.last_name as salesRepresentative from '+QUOTENAME(@Tenant)+'.'+'user_user_details u 
inner join '+QUOTENAME(@Tenant)+'.'+'job_roles jr on u.user_id=jr.user_id
where jr.role_name=''Sales Representative'' and jr.job_role_status=''Active''),
cte4 as
(select jr.job_id,u.first_name+'' ''+u.last_name as coordinator from '+QUOTENAME(@Tenant)+'.'+'user_user_details u 
inner join '+QUOTENAME(@Tenant)+'.'+'job_roles jr on u.user_id=jr.user_id
where jr.role_name=''Coordinator'' and jr.job_role_status=''Active''),
cte5 as
(select jr.job_id,u.first_name+'' ''+u.last_name as finance from '+QUOTENAME(@Tenant)+'.'+'user_user_details u  
inner join '+QUOTENAME(@Tenant)+'.'+'job_roles jr on u.user_id=jr.user_id
where jr.role_name=''Finance'' and jr.job_role_status=''Active''),
cte6 as
(select jr.job_id,u.first_name+'' ''+u.last_name as administrator from '+QUOTENAME(@Tenant)+'.'+'user_user_details u 
inner join '+QUOTENAME(@Tenant)+'.'+'job_roles jr on u.user_id=jr.user_id
where jr.role_name=''Administrator'' and jr.job_role_status=''Active''),
cte7 as
(select jr.job_id,u.first_name+'' ''+u.last_name as role from '+QUOTENAME(@Tenant)+'.'+'user_user_details u  
inner join '+QUOTENAME(@Tenant)+'.'+'job_roles jr on u.user_id=jr.user_id
where jr.role_name=''Role'' and jr.job_role_status=''Active''),
cte8 as
(select jc.job_id,jc.contact_id,cd.contact_first_name+'' ''+cd.contact_last_name as adjuster from '+QUOTENAME(@Tenant)+'.'+'contact_details cd
inner join '+QUOTENAME(@Tenant)+'.'+'job_contacts jc on cd.contact_id= jc.contact_id
where jc.contact_work_type=''Adjuster'' and jc.status=''Active'' and contact_category=''Common''),
cte9 as
(select jc.job_id,jc.contact_id,cd.contact_first_name+'' ''+cd.contact_last_name  as insuranceAgent from '+QUOTENAME(@Tenant)+'.'+'contact_details cd 
inner join '+QUOTENAME(@Tenant)+'.'+'job_contacts jc on cd.contact_id= jc.contact_id
where jc.contact_work_type=''Insurance Agent'' and jc.status=''Active'' and contact_category=''Common''),
cte10 as
(select jc.job_id,jc.contact_id,cd.contact_first_name+'' ''+cd.contact_last_name as propertyManager from '+QUOTENAME(@Tenant)+'.'+'contact_details cd 
inner join '+QUOTENAME(@Tenant)+'.'+'job_contacts jc on cd.contact_id= jc.contact_id
where jc.contact_work_type=''Property Manager'' and jc.status=''Active'' and contact_category=''Common''),
cte11 as
(select jc.job_id,jc.contact_id,cd.contact_first_name+'' ''+cd.contact_last_name as publicAdjuster from '+QUOTENAME(@Tenant)+'.'+'contact_details cd
inner join '+QUOTENAME(@Tenant)+'.'+'job_contacts jc on cd.contact_id= jc.contact_id
where jc.contact_work_type=''Public Adjuster'' and jc.status=''Active'' and contact_category=''Common''),
cte12 as
(select jc.job_id,jc.contact_id,cd.contact_first_name+'' ''+cd.contact_last_name as independentAdjuster from '+QUOTENAME(@Tenant)+'.'+'contact_details cd 
inner join '+QUOTENAME(@Tenant)+'.'+'job_contacts jc on cd.contact_id= jc.contact_id
where jc.contact_work_type=''Independent Adjuster'' and jc.status=''Active'' and contact_category=''Common'')

select j.job_id AS jobId,j.job_code AS subJobCode,j.job_hash_code AS jobHashCode,j.job_type AS jobType,
j.first_name As firstName, j.last_name As lastName,j.loss_address AS lossAddress,j.loss_address_city AS city,
j.loss_address_state AS state,j.loss_address_zip AS zip,j.rest_comp_location_id as locationId,j.current_job_status as status,
n.company as company,n.mast_num_code as mastNumCode,j.mobile AS mobile,j.work_phone AS workPhone,j.phone1 AS phone1,
cte.supervisor,cte2.estimator,cte3.salesRepresentative,cte4.coordinator,cte5.finance,cte6.administrator,cte7.Role,cte8.adjuster,
cte9.insuranceAgent,cte10.propertyManager,cte11.publicAdjuster,cte12.independentAdjuster,'

/**** Kpi Target******/
BEGIN
SET @SQL=@SQL+
'(select Top 1 jk.kpi_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Cycle Time'' and jk.kpi_value>=0) As cycleTime,
(select Top 1 jk.kpi_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''WIP Time'' and jk.kpi_value>=0) As wipTime,
(select Top 1 jk.kpi_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Total Final Invoice Time'' and jk.kpi_value>=0) As TotalFinalInvoiceTime,
(select Top 1 jk.kpi_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Days to Start'' and jk.kpi_value>=0) As daysToStart,
(select Top 1 jk.kpi_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Estimate Bid Time'' and jk.kpi_value>=0) As estimateBidTime,
(select Top 1 jk.kpi_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Final Estimate Upload Time'' and jk.kpi_value>=0) As finalEstimateUploadTime,
(select Top 1 jk.kpi_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Onsite Arrival Time'' and jk.kpi_value>=0) As onsiteArrivalTime,
(select Top 1 jk.kpi_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Target Completion Accuracy'' and jk.kpi_value>=0) As targetCompletion,
(select Top 1 jk.kpi_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Contact Customer Time'' and jk.kpi_value>=0) As contactCustomerTime,
(select Top 1 jk.kpi_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Days to Sign'' and jk.kpi_value>=0) As daysToSign,
(select Top 1 jk.kpi_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Final Invoice Delay Time'' and jk.kpi_value>=0) As finalInvoiceDelayTime,
(select Top 1 jk.kpi_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Gross Profit %'' and jk.kpi_value>=0) As grossProfit,
(select Top 1 jk.kpi_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Labor Efficiency Ratio'' and jk.kpi_value>=0) As LaborEfficiencyRation,
'
END

/**** Kpi Target ******/
BEGIN
SET @SQL=@SQL+
'(select Top 1 jk.kpi_target_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Cycle Time'') As cycleTimeTargetVal,
(select Top 1 jk.kpi_target_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''WIP Time'') As wipTimeTargetVal,
(select Top 1 jk.kpi_target_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Total Final Invoice Time'') As TotalFinalInvoiceTimeTargetVal,
(select Top 1 jk.kpi_target_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Days to Start'') As daysToStartTargetVal,
(select Top 1 jk.kpi_target_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Estimate Bid Time'') As estimateBidTimeTargetVal,
(select Top 1 jk.kpi_target_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Final Estimate Upload Time'') As finalEstimateUploadTimeTargetVal,
(select Top 1 jk.kpi_target_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Onsite Arrival Time'') As onsiteArrivalTimeTargetVal,
(select Top 1 jk.kpi_target_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Target Completion Accuracy'') As targetCompletionTargetVal,
(select Top 1 jk.kpi_target_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Contact Customer Time'') As contactCustomerTimeTargetVal,
(select Top 1 jk.kpi_target_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Days to Sign'') As daysToSignTargetVal,
(select Top 1 jk.kpi_target_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Final Invoice Delay Time'') As finalInvoiceDelayTimeTargetVal,
(select Top 1 jk.kpi_target_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Gross Profit %'') As grossProfitTargetVal,
(select Top 1 jk.kpi_target_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Labor Efficiency Ratio'') As LaborEfficiencyRationTargetVal,
'
END


BEGIN
SET @SQL=@SQL+'m.dateofLoss AS dateofLoss,m.dateReceived AS dateReceived,m.datecontacted AS datecontacted,
m.dateinspected AS dateinspected,m.dateofWorkAuthorization AS dateofWorkAuthorization,m.dateEstimatesent AS dateEstimatesent,
m.dateEstimateApproved AS dateEstimateApproved,m.dateinventoried AS dateinventoried,m.intoProductiondate AS intoProductiondate,
m.target_start_date AS targetStartDate,m.startdate AS startdate,m.dateofmajoritycompletion AS dateofmajoritycompletion,
m.targetcompletiondate AS targetcompletiondate,m.dateOfcOs AS dateOfcOs,m.dateinvoiced AS dateinvoiced,m.final_invoice_date AS finalInvoiceDate,
m.datePaid AS datePaid,m.closeddate AS closeddate,
j.created_datetime AS createdDatetime,j.dash_file_created_date AS fileDate,
j.referred_source as referredSoure,j.tpa_name as tpa,
case when (select count(*) from '+QUOTENAME(@Tenant)+'.'+'job_estimate e where e.job_id=j.job_id)>0 then ''Yes'' else ''No'' end as estimate,
(select sum(e.estimated_amount) from '+QUOTENAME(@Tenant)+'.'+'job_estimate e where e.job_id=j.job_id) as TotalEstimateAmount,
(select sum(f.doc_amt) from '+QUOTENAME(@Tenant)+'.'+'file_invoice f where f.file_number=j.job_code and f.doc_type=''Invoice'') as TotalInvoice,
((select sum(c.doc_amt) from '+QUOTENAME(@Tenant)+'.'+'file_cost c where c.file_number=j.job_code and c.tran_type NOT IN(''Vendor Credits'',''Credit Card Credits'',''VendorCredits'',''CreditCardCredits'',''Vendor Credit'') and (c.status=''Active'' or c.status is null)) - 
(select case when sum(c.doc_amt) is null then 0 else sum(c.doc_amt) end from '+QUOTENAME(@Tenant)+'.'+'file_cost c where c.file_number=j.job_code and c.tran_type IN(''Vendor Credits'',''Credit Card Credits'',''VendorCredits'',''CreditCardCredits'',''Vendor Credit'') and (c.status=''Active'' or c.status is null))) as totalVendorCost,
(select sum(l.total_cost) from '+QUOTENAME(@Tenant)+'.'+'user_payroll_details l where l.job_id=j.job_id and l.labor_type = ''Labor'' and  (l.status=''Active'' or l.status is null)) as jobCostLabor,
(select sum(l.total_cost) from '+QUOTENAME(@Tenant)+'.'+'user_payroll_details l where l.job_id=j.job_id and l.labor_type = ''Travel Time'' and  (l.status=''Active'' or l.status is null)) as jobCostTravel,
(select case when sum(l.total_cost) is null then 0 else sum(l.total_cost) end from '+QUOTENAME(@Tenant)+'.'+'user_payroll_details l where l.job_id=j.job_id and l.labor_type in (''Labor'',''Travel Time'') and  (l.status=''Active'' or l.status is null)) as TotalLabor,
(select sum(f.doc_amt) from '+QUOTENAME(@Tenant)+'.'+'file_invoice f where f.file_number=j.job_code and f.doc_type=''Payment'') as TotalCollected,
j.customer_type AS customerType,j.customer_company_name AS customerCompanyName,j.dash_file_number as referenceNumber,'''' as customerName,j.last_activity as lastActivity,
j.email as email,j.property_type as propertyType,
(select mc.config_value from '+QUOTENAME(@Tenant)+'.'+'m_config_data mc where mc.config_id=j.program_type and config_name=''Program Type'' and mc.status=''Active'') as programType,
(select mc.config_value from '+QUOTENAME(@Tenant)+'.'+'m_config_data mc where mc.config_id=j.cause_of_loss and config_name=''Cause of Loss'' and mc.status=''Active'') as causeOfLoss,
(select ic.insurance_company_name from '+QUOTENAME(@Tenant)+'.'+'job_insurance_details ic where ic.job_id=j.job_id ) as insuranceCompany,
(select ic.claim_number from '+QUOTENAME(@Tenant)+'.'+'job_insurance_details ic where ic.job_id=j.job_id ) as claimNumber,
j.nps_score as npsScore,j.referred_source as referredSource,
CASE
WHEN j.referred_type =''Organization'' THEN
(select e.external_agency_name from '+QUOTENAME(@Tenant)+'.'+'external_agency_details e where e.external_agency_id=j.referred_by) 
WHEN j.referred_type =''People'' THEN
(select c.contact_first_name+'' ''+c.contact_last_name from '+QUOTENAME(@Tenant)+'.'+'contact_details c where c.contact_id=j.referred_by)
ELSE
j.referred_by
end
as referredBy
from '+QUOTENAME(@Tenant)+'.'+'job_details j 
left join '+QUOTENAME(@Tenant)+'.'+'mast_num_details n on n.mast_num_id=j.mast_num_id
left join '+QUOTENAME(@Tenant)+'.'+'common_milestones m on j.job_id = m.source_id
left join cte on j.job_id=cte.job_id
left join cte2 on j.job_id=cte2.job_id
left join cte3 on j.job_id=cte3.job_id
left join cte4 on j.job_id=cte4.job_id
left join cte5 on j.job_id=cte5.job_id
left join cte6 on j.job_id=cte6.job_id
left join cte7 on j.job_id=cte7.job_id
left join cte8 on j.job_id=cte8.job_id
left join cte9 on j.job_id=cte9.job_id
left join cte10 on j.job_id=cte10.job_id
left join cte11 on j.job_id=cte11.job_id
left join cte12 on j.job_id=cte12.job_id
where j.rest_comp_location_id='+ cast (@locationId as NVARCHAR(10))+' 
and CONVERT(VARCHAR(8), j.created_datetime, 112)>CONVERT(VARCHAR(8), ''2017-01-01 00:00:00'', 112) order by j.job_id desc';
END

EXEC (@SQL)
PRINT (@SQL)
GO

GO
