-- Stored Procedure: [dbo].[all_jobs_report_date_filter]
-- Repeatable Migration - Re-runs when content changes
-- =============================================
CREATE OR ALTER PROCEDURE  [dbo].[all_jobs_report_date_filter]
(@Tenant Varchar(255),@startDate Datetime,@endDate Datetime,@Week INT)
As

DECLARE @SQL VARCHAR(MAX)
DECLARE @weekDay Int = @Week -1;
SET @SQL=N';
SET DATEFIRST ' +cast (@Week as NVARCHAR(10))+ ' Select  DATEADD(day, DATEDIFF(day, ' +cast (@weekDay as NVARCHAR(10))+ ' , j.created_datetime) /7*7, ' +cast (@weekDay as NVARCHAR(10))+ ') as weekDay, 
j.job_id AS jobId,j.job_code AS subJobCode,j.job_hash_code AS jobHashCode,j.job_type AS jobType,
j.first_name As firstName, j.last_name As lastName,j.loss_address AS lossAddress,j.loss_address_city AS city,
j.loss_address_state AS state,j.loss_address_zip AS zip,j.rest_comp_location_id as locationId,j.current_job_status as status,
(select m.company from '+QUOTENAME(@Tenant)+'.'+'mast_num_details m where m.mast_num_id=j.mast_num_id) as company,
(select m.mast_num_code from '+QUOTENAME(@Tenant)+'.'+'mast_num_details m where m.mast_num_id=j.mast_num_id) as mastNumCode,
j.mobile AS mobile,j.work_phone AS workPhone,j.phone1 AS phone1,
(select u.first_name+'' ''+u.last_name from '+QUOTENAME(@Tenant)+'.'+'user_user_details u where u.user_id=(select jr.user_id from '+QUOTENAME(@Tenant)+'.'+'job_roles jr 
where jr.job_id=j.job_id and jr.role_name=''Supervisor'' and jr.job_role_status=''Active'')) As supervisor,
(select u.first_name+'' ''+u.last_name from '+QUOTENAME(@Tenant)+'.'+'user_user_details u where u.user_id=(select jr.user_id from '+QUOTENAME(@Tenant)+'.'+'job_roles jr 
where jr.job_id=j.job_id and jr.role_name=''Estimator'' and jr.job_role_status=''Active'')) As estimator,
(select u.first_name+'' ''+u.last_name from '+QUOTENAME(@Tenant)+'.'+'user_user_details u where u.user_id=(select jr.user_id from '+QUOTENAME(@Tenant)+'.'+'job_roles jr 
where jr.job_id=j.job_id and jr.role_name=''Sales Representative'' and jr.job_role_status=''Active'')) As salesRepresentative,
(select u.first_name+'' ''+u.last_name from '+QUOTENAME(@Tenant)+'.'+'user_user_details u where u.user_id=(select jr.user_id from '+QUOTENAME(@Tenant)+'.'+'job_roles jr 
where jr.job_id=j.job_id and jr.role_name=''Coordinator'' and jr.job_role_status=''Active'')) As coordinator,
(select u.first_name+'' ''+u.last_name from '+QUOTENAME(@Tenant)+'.'+'user_user_details u where u.user_id=(select jr.user_id from '+QUOTENAME(@Tenant)+'.'+'job_roles jr 
where jr.job_id=j.job_id and jr.role_name=''Finance'' and jr.job_role_status=''Active'')) As finance,
(select u.first_name+'' ''+u.last_name from '+QUOTENAME(@Tenant)+'.'+'user_user_details u where u.user_id=(select jr.user_id from '+QUOTENAME(@Tenant)+'.'+'job_roles jr 
where jr.job_id=j.job_id and jr.role_name=''Administrator'' and jr.job_role_status=''Active'')) As administrator,
(select u.first_name+'' ''+u.last_name from '+QUOTENAME(@Tenant)+'.'+'user_user_details u where u.user_id=(select jr.user_id from '+QUOTENAME(@Tenant)+'.'+'job_roles jr 
where jr.job_id=j.job_id and jr.role_name=''Role'' and jr.job_role_status=''Active'')) As Role,
(select u.first_name+'' ''+u.last_name from '+QUOTENAME(@Tenant)+'.'+'user_user_details u where u.user_id=(select jr.user_id from '+QUOTENAME(@Tenant)+'.'+'job_roles jr 
where jr.job_id=j.job_id and jr.role_name=''Lead Technician'' and jr.job_role_status=''Active'')) As leadTechnician,
(SELECT MAX(e.schedule_date) FROM '+QUOTENAME(@Tenant) +'.'+'ems_schedule e WHERE e.job_id = j.job_id AND e.status= ''Active'') AS lastScheduledVisit,'	


/** Contact Details ****/
BEGIN
SET @SQL=@SQL+'(select cd.contact_first_name+'' ''+cd.contact_last_name from '+QUOTENAME(@Tenant)+'.'+'contact_details cd where cd.contact_id=(select Top 1jc.contact_id from '+QUOTENAME(@Tenant)+'.'+'job_contacts jc 
where jc.job_id=j.job_id and jc.contact_work_type=''Adjuster'' and jc.status=''Active'' and contact_category=''Common'')) As adjuster,
(select cd.contact_first_name+'' ''+cd.contact_last_name from '+QUOTENAME(@Tenant)+'.'+'contact_details cd where cd.contact_id=(select Top 1 jc.contact_id from '+QUOTENAME(@Tenant)+'.'+'job_contacts jc 
where jc.job_id=j.job_id and jc.contact_work_type=''Insurance Agent'' and jc.status=''Active'' and contact_category=''Common'')) As insuranceAgent,
(select cd.contact_first_name+'' ''+cd.contact_last_name from '+QUOTENAME(@Tenant)+'.'+'contact_details cd where cd.contact_id=(select Top 1 jc.contact_id from '+QUOTENAME(@Tenant)+'.'+'job_contacts jc 
where jc.job_id=j.job_id and jc.contact_work_type=''Property Manager'' and jc.status=''Active'' and contact_category=''Common'')) As propertyManager,
(select cd.contact_first_name+'' ''+cd.contact_last_name from '+QUOTENAME(@Tenant)+'.'+'contact_details cd where cd.contact_id=(select Top 1 jc.contact_id from '+QUOTENAME(@Tenant)+'.'+'job_contacts jc 
where jc.job_id=j.job_id and jc.contact_work_type=''Public Adjuster'' and jc.status=''Active'' and contact_category=''Common'')) As publicAdjuster,
(select cd.contact_first_name+'' ''+cd.contact_last_name from '+QUOTENAME(@Tenant)+'.'+'contact_details cd where cd.contact_id=(select Top 1 jc.contact_id from '+QUOTENAME(@Tenant)+'.'+'job_contacts jc 
where jc.job_id=j.job_id and jc.contact_work_type=''Independent Adjuster'' and jc.status=''Active'' and contact_category=''Common'')) As independentAdjuster,'
END
/**** Kpi Target******/
BEGIN
SET @SQL=@SQL+
'(select Top 1 jk.kpi_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Cycle Time'' and jk.kpi_value>=0) As cycleTime,
(select Top 1 jk.kpi_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''WIP Time'' and jk.kpi_value>=0) As wipTime,
(select Top 1 jk.kpi_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Total Final Invoice Time'' and jk.kpi_value>=0) As TotalFinalInvoiceTime,
(select Top 1 jk.kpi_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Days to Start'' and jk.kpi_value>=0) As daysToStart,
(select Top 1 jk.kpi_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Estimate Bid Time'' and jk.kpi_value>=0) As estimateBidTime,
(select Top 1 jk.kpi_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Final Estimate Upload Time'' and jk.kpi_value>=0) As finalEstimateUploadTime,
(select Top 1 jk.kpi_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Onsite Arrival Time'' and jk.kpi_value>=0) As onsiteArrivalTime,
(select Top 1 jk.kpi_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Target Completion Accuracy'' and jk.kpi_value>=0) As targetCompletion,
(select Top 1 jk.kpi_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Contact Customer Time'' and jk.kpi_value>=0) As contactCustomerTime,
(select Top 1 jk.kpi_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Days to Sign'' and jk.kpi_value>=0) As daysToSign,
(select Top 1 jk.kpi_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Final Invoice Delay Time'' and jk.kpi_value>=0) As finalInvoiceDelayTime,
(select Top 1 jk.kpi_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Gross Profit %'' and jk.kpi_value>=0) As grossProfit,
(select Top 1 jk.kpi_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Labor Efficiency Ratio'' and jk.kpi_value>=0) As LaborEfficiencyRation,
'
END

/**** Kpi Target ******/
BEGIN
SET @SQL=@SQL+
'
(select 
    CASE j.job_type 
	WHEN ''Water'' THEN jt.water 
    WHEN ''Reconstruction'' THEN jt.recon
	WHEN ''Content'' THEN jt.content
	WHEN ''Mold'' THEN jt.mold
	WHEN ''Asbestos'' THEN jt.asbestos
	WHEN ''Board Up'' THEN jt.board_up
	WHEN ''Consulting'' THEN jt.consulting
	WHEN ''Bio'' THEN jt.bio
	WHEN ''Structure Cleaning'' THEN jt.structure_cleaning
	WHEN ''Roofing'' THEN jt.roofing
	WHEN ''Other'' THEN jt.others
    END
from '+QUOTENAME(@Tenant)+'.'+'job_kpi_targets jt where jt.kpi_name like ''%Cycle Time%'') as cycleTimeTargetVal,
(select 
    CASE j.job_type 
	WHEN ''Water'' THEN jt.water 
    WHEN ''Reconstruction'' THEN jt.recon
	WHEN ''Content'' THEN jt.content
	WHEN ''Mold'' THEN jt.mold
	WHEN ''Asbestos'' THEN jt.asbestos
	WHEN ''Board Up'' THEN jt.board_up
	WHEN ''Consulting'' THEN jt.consulting
	WHEN ''Bio'' THEN jt.bio
	WHEN ''Structure Cleaning'' THEN jt.structure_cleaning
	WHEN ''Roofing'' THEN jt.roofing
	WHEN ''Other'' THEN jt.others
    END
from '+QUOTENAME(@Tenant)+'.'+'job_kpi_targets jt where jt.kpi_name like ''%WIP Time%'') as wipTimeTargetVal,
(select 
    CASE j.job_type 
	WHEN ''Water'' THEN jt.water 
    WHEN ''Reconstruction'' THEN jt.recon
	WHEN ''Content'' THEN jt.content
	WHEN ''Mold'' THEN jt.mold
	WHEN ''Asbestos'' THEN jt.asbestos
	WHEN ''Board Up'' THEN jt.board_up
	WHEN ''Consulting'' THEN jt.consulting
	WHEN ''Bio'' THEN jt.bio
	WHEN ''Structure Cleaning'' THEN jt.structure_cleaning
	WHEN ''Roofing'' THEN jt.roofing
	WHEN ''Other'' THEN jt.others
    END
from '+QUOTENAME(@Tenant)+'.'+'job_kpi_targets jt where jt.kpi_name like ''%Total Final Invoice Time%'') as TotalFinalInvoiceTimeTargetVal,
(select 
    CASE j.job_type 
	WHEN ''Water'' THEN jt.water 
    WHEN ''Reconstruction'' THEN jt.recon
	WHEN ''Content'' THEN jt.content
	WHEN ''Mold'' THEN jt.mold
	WHEN ''Asbestos'' THEN jt.asbestos
	WHEN ''Board Up'' THEN jt.board_up
	WHEN ''Consulting'' THEN jt.consulting
	WHEN ''Bio'' THEN jt.bio
	WHEN ''Structure Cleaning'' THEN jt.structure_cleaning
	WHEN ''Roofing'' THEN jt.roofing
	WHEN ''Other'' THEN jt.others
    END
from '+QUOTENAME(@Tenant)+'.'+'job_kpi_targets jt where jt.kpi_name like ''%Days to Start%'') as daysToStartTargetVal,
(select 
    CASE j.job_type 
	WHEN ''Water'' THEN jt.water 
    WHEN ''Reconstruction'' THEN jt.recon
	WHEN ''Content'' THEN jt.content
	WHEN ''Mold'' THEN jt.mold
	WHEN ''Asbestos'' THEN jt.asbestos
	WHEN ''Board Up'' THEN jt.board_up
	WHEN ''Consulting'' THEN jt.consulting
	WHEN ''Bio'' THEN jt.bio
	WHEN ''Structure Cleaning'' THEN jt.structure_cleaning
	WHEN ''Roofing'' THEN jt.roofing
	WHEN ''Other'' THEN jt.others
    END
from '+QUOTENAME(@Tenant)+'.'+'job_kpi_targets jt where jt.kpi_name like ''%Estimate Bid Time%'') as estimateBidTimeTargetVal,
(select 
    CASE j.job_type 
	WHEN ''Water'' THEN jt.water 
    WHEN ''Reconstruction'' THEN jt.recon
	WHEN ''Content'' THEN jt.content
	WHEN ''Mold'' THEN jt.mold
	WHEN ''Asbestos'' THEN jt.asbestos
	WHEN ''Board Up'' THEN jt.board_up
	WHEN ''Consulting'' THEN jt.consulting
	WHEN ''Bio'' THEN jt.bio
	WHEN ''Structure Cleaning'' THEN jt.structure_cleaning
	WHEN ''Roofing'' THEN jt.roofing
	WHEN ''Other'' THEN jt.others
    END
from '+QUOTENAME(@Tenant)+'.'+'job_kpi_targets jt where jt.kpi_name like ''Final Estimate Upload Time%'') as finalEstimateUploadTimeTargetVal,
(select 
    CASE j.job_type 
	WHEN ''Water'' THEN jt.water 
    WHEN ''Reconstruction'' THEN jt.recon
	WHEN ''Content'' THEN jt.content
	WHEN ''Mold'' THEN jt.mold
	WHEN ''Asbestos'' THEN jt.asbestos
	WHEN ''Board Up'' THEN jt.board_up
	WHEN ''Consulting'' THEN jt.consulting
	WHEN ''Bio'' THEN jt.bio
	WHEN ''Structure Cleaning'' THEN jt.structure_cleaning
	WHEN ''Roofing'' THEN jt.roofing
	WHEN ''Other'' THEN jt.others
    END
from '+QUOTENAME(@Tenant)+'.'+'job_kpi_targets jt where jt.kpi_name like ''%Onsite Arrival Time%'') as onsiteArrivalTimeTargetVal,
(select 
    CASE j.job_type 
	WHEN ''Water'' THEN jt.water 
    WHEN ''Reconstruction'' THEN jt.recon
	WHEN ''Content'' THEN jt.content
	WHEN ''Mold'' THEN jt.mold
	WHEN ''Asbestos'' THEN jt.asbestos
	WHEN ''Board Up'' THEN jt.board_up
	WHEN ''Consulting'' THEN jt.consulting
	WHEN ''Bio'' THEN jt.bio
	WHEN ''Structure Cleaning'' THEN jt.structure_cleaning
	WHEN ''Roofing'' THEN jt.roofing
	WHEN ''Other'' THEN jt.others
    END
from '+QUOTENAME(@Tenant)+'.'+'job_kpi_targets jt where jt.kpi_name like ''%Target Completion Accuracy%'') as targetCompletionTargetVal,
(select 
    CASE j.job_type 
	WHEN ''Water'' THEN jt.water 
    WHEN ''Reconstruction'' THEN jt.recon
	WHEN ''Content'' THEN jt.content
	WHEN ''Mold'' THEN jt.mold
	WHEN ''Asbestos'' THEN jt.asbestos
	WHEN ''Board Up'' THEN jt.board_up
	WHEN ''Consulting'' THEN jt.consulting
	WHEN ''Bio'' THEN jt.bio
	WHEN ''Structure Cleaning'' THEN jt.structure_cleaning
	WHEN ''Roofing'' THEN jt.roofing
	WHEN ''Other'' THEN jt.others
    END
from '+QUOTENAME(@Tenant)+'.'+'job_kpi_targets jt where jt.kpi_name like ''%Contact Customer Time%'') as contactCustomerTimeTargetVal,
(select 
    CASE j.job_type 
	WHEN ''Water'' THEN jt.water 
    WHEN ''Reconstruction'' THEN jt.recon
	WHEN ''Content'' THEN jt.content
	WHEN ''Mold'' THEN jt.mold
	WHEN ''Asbestos'' THEN jt.asbestos
	WHEN ''Board Up'' THEN jt.board_up
	WHEN ''Consulting'' THEN jt.consulting
	WHEN ''Bio'' THEN jt.bio
	WHEN ''Structure Cleaning'' THEN jt.structure_cleaning
	WHEN ''Roofing'' THEN jt.roofing
	WHEN ''Other'' THEN jt.others
    END
from '+QUOTENAME(@Tenant)+'.'+'job_kpi_targets jt where jt.kpi_name like ''%Days to Sign%'') as daysToSignTargetVal,
(select 
    CASE j.job_type 
	WHEN ''Water'' THEN jt.water 
    WHEN ''Reconstruction'' THEN jt.recon
	WHEN ''Content'' THEN jt.content
	WHEN ''Mold'' THEN jt.mold
	WHEN ''Asbestos'' THEN jt.asbestos
	WHEN ''Board Up'' THEN jt.board_up
	WHEN ''Consulting'' THEN jt.consulting
	WHEN ''Bio'' THEN jt.bio
	WHEN ''Structure Cleaning'' THEN jt.structure_cleaning
	WHEN ''Roofing'' THEN jt.roofing
	WHEN ''Other'' THEN jt.others
    END
from '+QUOTENAME(@Tenant)+'.'+'job_kpi_targets jt where jt.kpi_name like ''%Final Invoice Delay Time%'') as finalInvoiceDelayTimeTargetVal,
(select 
    CASE j.job_type 
	WHEN ''Water'' THEN jt.water 
    WHEN ''Reconstruction'' THEN jt.recon
	WHEN ''Content'' THEN jt.content
	WHEN ''Mold'' THEN jt.mold
	WHEN ''Asbestos'' THEN jt.asbestos
	WHEN ''Board Up'' THEN jt.board_up
	WHEN ''Consulting'' THEN jt.consulting
	WHEN ''Bio'' THEN jt.bio
	WHEN ''Structure Cleaning'' THEN jt.structure_cleaning
	WHEN ''Roofing'' THEN jt.roofing
	WHEN ''Other'' THEN jt.others
    END
from '+QUOTENAME(@Tenant)+'.'+'job_kpi_targets jt where jt.kpi_name like ''%Gross Profit %%'') as grossProfitTargetVal,
(select 
    CASE j.job_type 
	WHEN ''Water'' THEN jt.water 
    WHEN ''Reconstruction'' THEN jt.recon
	WHEN ''Content'' THEN jt.content
	WHEN ''Mold'' THEN jt.mold
	WHEN ''Asbestos'' THEN jt.asbestos
	WHEN ''Board Up'' THEN jt.board_up
	WHEN ''Consulting'' THEN jt.consulting
	WHEN ''Bio'' THEN jt.bio
	WHEN ''Structure Cleaning'' THEN jt.structure_cleaning
	WHEN ''Roofing'' THEN jt.roofing
	WHEN ''Other'' THEN jt.others
    END
from '+QUOTENAME(@Tenant)+'.'+'job_kpi_targets jt where jt.kpi_name like ''%Labor Efficiency Ratio%'') as LaborEfficiencyRationTargetVal,
'    
END


BEGIN
SET @SQL=@SQL+'m.dateofLoss AS dateofLoss,m.dateReceived AS dateReceived,m.datecontacted AS datecontacted,
m.dateinspected AS dateinspected,m.dateofWorkAuthorization AS dateofWorkAuthorization,m.dateEstimatesent AS dateEstimatesent,
m.dateEstimateApproved AS dateEstimateApproved,m.dateinventoried AS dateinventoried,m.intoProductiondate AS intoProductiondate,
m.target_start_date AS targetStartDate,m.startdate AS startdate,m.dateofmajoritycompletion AS dateofmajoritycompletion,
m.targetcompletiondate AS targetcompletiondate,m.dateOfcOs AS dateOfcOs,m.dateinvoiced AS dateinvoiced,m.final_invoice_date AS finalInvoiceDate,
m.datePaid AS datePaid,m.closeddate AS closeddate,
j.created_datetime AS createdDatetime,j.dash_file_created_date AS fileDate,
j.referred_source as referredSoure,j.tpa_name as tpa,
case when (select count(*) from '+QUOTENAME(@Tenant)+'.'+'job_estimate e where e.job_id=j.job_id)>0 then ''Yes'' else ''No'' end as estimate,
(select sum(e.estimated_amount) from '+QUOTENAME(@Tenant)+'.'+'job_estimate e where e.job_id=j.job_id) as TotalEstimateAmount,
j.total_invoice as TotalInvoice,
j.total_cost as totalVendorCost,j.total_credits as totalCredits,
(select sum(l.total_cost) from '+QUOTENAME(@Tenant)+'.'+'user_payroll_details l where l.job_id=j.job_id and l.labor_type = ''Labor'' and  (l.status=''Active'' or l.status is null)) as jobCostLabor,
(select sum(l.total_cost) from '+QUOTENAME(@Tenant)+'.'+'user_payroll_details l where l.job_id=j.job_id and l.labor_type = ''Travel Time'' and  (l.status=''Active'' or l.status is null)) as jobCostTravel,
(select case when sum(l.total_cost) is null then 0 else sum(l.total_cost) end from '+QUOTENAME(@Tenant)+'.'+'user_payroll_details l where l.job_id=j.job_id and l.labor_type in (''Labor'',''Travel Time'') and  (l.status=''Active'' or l.status is null)) as TotalLabor,
j.total_payment as TotalCollected,
j.customer_type AS customerType,j.customer_company_name AS customerCompanyName,j.dash_file_number as referenceNumber,'''' as customerName,j.last_activity as lastActivity,
j.email as email,j.property_type as propertyType,
(select mp.program_type from '+QUOTENAME(@Tenant)+'.'+'m_program mp where mp.program_type_id=j.program_type and mp.status=''Active'') as programType,
(select mc.config_value from '+QUOTENAME(@Tenant)+'.'+'m_config_data mc where mc.config_id=j.cause_of_loss and config_name=''Cause of Loss'' and mc.status=''Active'') as causeOfLoss,
(select ic.insurance_company_name from '+QUOTENAME(@Tenant)+'.'+'job_insurance_details ic where ic.job_id=j.job_id ) as insuranceCompany,
(select ic.claim_number from '+QUOTENAME(@Tenant)+'.'+'job_insurance_details ic where ic.job_id=j.job_id ) as claimNumber,
j.nps_score as npsScore,j.referred_source as referredSource,
CASE
WHEN j.referred_type =''Organization'' THEN
(select e.external_agency_name from '+QUOTENAME(@Tenant)+'.'+'external_agency_details e where cast(e.external_agency_id AS CHAR)=j.referred_by) 
WHEN j.referred_type =''People'' THEN
(select c.contact_first_name+'' ''+c.contact_last_name from '+QUOTENAME(@Tenant)+'.'+'contact_details c where cast(c.contact_id AS CHAR)=j.referred_by)
ELSE
j.referred_by
end
as referredBy,j.comment as comments,j.reason as reason,j.rough_estimate as roughEstimate,j.job_name as jobName,DATEDIFF(day, j.created_datetime, (SELECT GETDATE())) as fileAge,DATEDIFF(day, j.status_change_datetime, (SELECT GETDATE())) as ageInCurrentStatus,
CASE WHEN j.referred_type =''Organization'' THEN (select e.external_agency_name from '+QUOTENAME(@Tenant)+'.'+'external_agency_details e where cast(e.external_agency_id AS CHAR)=j.referred_by) 
WHEN j.referred_type =''People'' THEN (select e.external_agency_name from 
'+QUOTENAME(@Tenant)+'.'+'external_agency_details e where e.external_agency_id=(select external_agency_id from '+QUOTENAME(@Tenant)+'.'+'contact_details c where contact_id=j.referred_by and c.contact_status=''Active''))
ELSE NULL END as referredByOrganizationName, (select l.location_code from '+QUOTENAME(@Tenant)+'.'+'rest_comp_location l where l.rest_comp_location_id=j.rest_comp_location_id) as locationName,
(select m.status_category from '+QUOTENAME(@Tenant)+'.'+'m_status_configuration m where  m.additional_status = j.current_job_status and m.status=''Active'') as statusCategory,'

END




BEGIN
SET @SQL=@SQL+'
DATEADD(day, DATEDIFF(day, ' +cast (@weekDay as NVARCHAR(10))+ ', m.dateofLoss) /7*7, ' +cast (@weekDay as NVARCHAR(10))+ ') as dataLossWeek,
DATEADD(day, DATEDIFF(day, ' +cast (@weekDay as NVARCHAR(10))+ ', m.dateReceived) /7*7, ' +cast (@weekDay as NVARCHAR(10))+ ') as dataReceivedWeek,
DATEADD(day, DATEDIFF(day, ' +cast (@weekDay as NVARCHAR(10))+ ', m.datecontacted) /7*7, ' +cast (@weekDay as NVARCHAR(10))+ ') as dataContactedWeek,
DATEADD(day, DATEDIFF(day, ' +cast (@weekDay as NVARCHAR(10))+ ', m.dateinspected) /7*7, ' +cast (@weekDay as NVARCHAR(10))+ ') as dataInspectedWeek,
DATEADD(day, DATEDIFF(day, ' +cast (@weekDay as NVARCHAR(10))+ ', m.dateofWorkAuthorization) /7*7, ' +cast (@weekDay as NVARCHAR(10))+ ') as dataWorkAuthorizationWeek,
DATEADD(day, DATEDIFF(day, ' +cast (@weekDay as NVARCHAR(10))+ ', m.dateEstimatesent) /7*7, ' +cast (@weekDay as NVARCHAR(10))+ ') as dateEstimateSentWeek,
DATEADD(day, DATEDIFF(day, ' +cast (@weekDay as NVARCHAR(10))+ ', m.dateEstimateApproved) /7*7, ' +cast (@weekDay as NVARCHAR(10))+ ') as dateEstimateApprovedWeek,
DATEADD(day, DATEDIFF(day, ' +cast (@weekDay as NVARCHAR(10))+ ', m.dateinventoried) /7*7, ' +cast (@weekDay as NVARCHAR(10))+ ') as dateinventoriedWeek,
DATEADD(day, DATEDIFF(day, ' +cast (@weekDay as NVARCHAR(10))+ ', m.intoProductiondate) /7*7, ' +cast (@weekDay as NVARCHAR(10))+ ') as intoProductiondateWeek,
DATEADD(day, DATEDIFF(day, ' +cast (@weekDay as NVARCHAR(10))+ ', m.target_start_date) /7*7, ' +cast (@weekDay as NVARCHAR(10))+ ') as targetStartDateWeek,
DATEADD(day, DATEDIFF(day, ' +cast (@weekDay as NVARCHAR(10))+ ', m.startdate) /7*7, ' +cast (@weekDay as NVARCHAR(10))+ ') as startDateWeek,
DATEADD(day, DATEDIFF(day, ' +cast (@weekDay as NVARCHAR(10))+ ', m.dateofmajoritycompletion) /7*7, ' +cast (@weekDay as NVARCHAR(10))+ ') as dateOfMajorityCompletionWeek,
DATEADD(day, DATEDIFF(day, ' +cast (@weekDay as NVARCHAR(10))+ ', m.targetcompletiondate) /7*7, ' +cast (@weekDay as NVARCHAR(10))+ ') as targetCompletionDateWeek,
DATEADD(day, DATEDIFF(day, ' +cast (@weekDay as NVARCHAR(10))+ ', m.dateOfcOs) /7*7, ' +cast (@weekDay as NVARCHAR(10))+ ') as dateOfCOsWeek,
DATEADD(day, DATEDIFF(day, ' +cast (@weekDay as NVARCHAR(10))+ ', m.dateinvoiced) /7*7, ' +cast (@weekDay as NVARCHAR(10))+ ') as dateInvoicedWeek,

DATEADD(day, DATEDIFF(day, ' +cast (@weekDay as NVARCHAR(10))+ ', m.final_invoice_date) /7*7, ' +cast (@weekDay as NVARCHAR(10))+ ') as finalInvoiceDateWeek,
DATEADD(day, DATEDIFF(day,' +cast (@weekDay as NVARCHAR(10))+ ', m.datePaid) /7*7, ' +cast (@weekDay as NVARCHAR(10))+ ') as datePaidWeek,
DATEADD(day, DATEDIFF(day,' +cast (@weekDay as NVARCHAR(10))+ ', m.closeddate) /7*7, ' +cast (@weekDay as NVARCHAR(10))+ ') as closedDateWeek,
DATEADD(day, DATEDIFF(day,' +cast (@weekDay as NVARCHAR(10))+ ', j.dash_file_created_date) /7*7, ' +cast (@weekDay as NVARCHAR(10))+ ') as dashFileCreatedDateWeek'


END
BEGIN
SET @SQL=@SQL+',j.owner_id as ownerId,j.territory_id as territoryId,j.marketing_campaign as marketingCampaign,
j.marketing_owner as marketingOwner,j.marketing_channel as marketingChannel,
j.marketing_source as marketingSource,j.marketing_lead_details as marketingLeadDetails'
END

BEGIN
SET @SQL=@SQL+' from '+QUOTENAME(@Tenant)+'.'+'job_details j
 left join '+QUOTENAME(@Tenant)+'.'+'common_milestones m on j.job_id = m.source_id
 where j.created_datetime>='''+CONVERT(nvarchar, @startDate)+''' and j.current_job_status !=''Deleted'' and j.created_datetime<='''+CONVERT(nvarchar, @endDate)+''' order by j.job_id desc';
END

EXEC (@SQL)
print  (@SQL)
GO

GO
-- =============================================
-- Stored Procedure: [dbo].[all_jobs_report_export_java21]
-- Repeatable Migration - Re-runs when content changes
-- =============================================
CREATE OR ALTER PROCEDURE  [dbo].[all_jobs_report_export_java21]
(@Tenant Varchar(255),@startDate Datetime,@endDate Datetime,@Week INT)
As

DECLARE @SQL VARCHAR(MAX)
DECLARE @weekDay Int = @Week -1;
SET @SQL=N';

SET DATEFIRST ' +cast (@Week as NVARCHAR(10))+ ' Select  DATEADD(day, DATEDIFF(day, ' +cast (@weekDay as NVARCHAR(10))+ ' , j.created_datetime) /7*7, ' +cast (@weekDay as NVARCHAR(10))+ ') as Week_Day,
 (select l.location_code from '+QUOTENAME(@Tenant)+'.'+'rest_comp_location l where l.rest_comp_location_id=j.rest_comp_location_id) as Location,
 (select m.mast_num_code from '+QUOTENAME(@Tenant)+'.'+'mast_num_details m where m.mast_num_id=j.mast_num_id) as Master_Job_Number,
j.job_id as jobID#,j.job_code AS File_Number,j.job_type AS Division,
j.loss_address AS Loss_Address,j.loss_address_city AS City,
j.loss_address_state AS State,j.loss_address_zip AS Zip,j.current_job_status as Status,
j.mobile AS Cell_Number,j.work_phone AS Work_Number,j.phone1 AS Home_Number,

(select u.first_name+'' ''+u.last_name from '+QUOTENAME(@Tenant)+'.'+'user_user_details u where u.user_id=(select jr.user_id from '+QUOTENAME(@Tenant)+'.'+'job_roles jr
where jr.job_id=j.job_id and jr.role_name=''Supervisor'' and jr.job_role_status=''Active'')) As Supervisor,
(select u.first_name+'' ''+u.last_name from '+QUOTENAME(@Tenant)+'.'+'user_user_details u where u.user_id=(select jr.user_id from '+QUOTENAME(@Tenant)+'.'+'job_roles jr
where jr.job_id=j.job_id and jr.role_name=''Estimator'' and jr.job_role_status=''Active'')) As Estimator,
(select u.first_name+'' ''+u.last_name from '+QUOTENAME(@Tenant)+'.'+'user_user_details u where u.user_id=(select jr.user_id from '+QUOTENAME(@Tenant)+'.'+'job_roles jr
where jr.job_id=j.job_id and jr.role_name=''Sales Representative'' and jr.job_role_status=''Active'')) As Sales_Representative,
(select u.first_name+'' ''+u.last_name from '+QUOTENAME(@Tenant)+'.'+'user_user_details u where u.user_id=(select jr.user_id from '+QUOTENAME(@Tenant)+'.'+'job_roles jr
where jr.job_id=j.job_id and jr.role_name=''Coordinator'' and jr.job_role_status=''Active'')) As Coordinator,
(select u.first_name+'' ''+u.last_name from '+QUOTENAME(@Tenant)+'.'+'user_user_details u where u.user_id=(select jr.user_id from '+QUOTENAME(@Tenant)+'.'+'job_roles jr
where jr.job_id=j.job_id and jr.role_name=''Finance'' and jr.job_role_status=''Active'')) As Finance,
(select u.first_name+'' ''+u.last_name from '+QUOTENAME(@Tenant)+'.'+'user_user_details u where u.user_id=(select jr.user_id from '+QUOTENAME(@Tenant)+'.'+'job_roles jr
where jr.job_id=j.job_id and jr.role_name=''Administrator'' and jr.job_role_status=''Active'')) As Administrator,
(select u.first_name+'' ''+u.last_name from '+QUOTENAME(@Tenant)+'.'+'user_user_details u where u.user_id=(select jr.user_id from '+QUOTENAME(@Tenant)+'.'+'job_roles jr
where jr.job_id=j.job_id and jr.role_name=''Role'' and jr.job_role_status=''Active'')) As Role,
(select u.first_name+'' ''+u.last_name from '+QUOTENAME(@Tenant)+'.'+'user_user_details u where u.user_id=(select jr.user_id from '+QUOTENAME(@Tenant)+'.'+'job_roles jr
where jr.job_id=j.job_id and jr.role_name=''Lead Technician'' and jr.job_role_status=''Active'')) As Lead_Technician,'

/** Contact Details ****/
BEGIN
SET @SQL=@SQL+'(select cd.contact_first_name+'' ''+cd.contact_last_name from '+QUOTENAME(@Tenant)+'.'+'contact_details cd where cd.contact_id=(select Top 1jc.contact_id from '+QUOTENAME(@Tenant)+'.'+'job_contacts jc
where jc.job_id=j.job_id and jc.contact_work_type=''Adjuster'' and jc.status=''Active'' and contact_category=''Common'')) As Assigned_Adjuster,
(select cd.contact_first_name+'' ''+cd.contact_last_name from '+QUOTENAME(@Tenant)+'.'+'contact_details cd where cd.contact_id=(select Top 1 jc.contact_id from '+QUOTENAME(@Tenant)+'.'+'job_contacts jc
where jc.job_id=j.job_id and jc.contact_work_type=''Insurance Agent'' and jc.status=''Active'' and contact_category=''Common'')) As Assigned_Agent,
(select cd.contact_first_name+'' ''+cd.contact_last_name from '+QUOTENAME(@Tenant)+'.'+'contact_details cd where cd.contact_id=(select Top 1 jc.contact_id from '+QUOTENAME(@Tenant)+'.'+'job_contacts jc
where jc.job_id=j.job_id and jc.contact_work_type=''Property Manager'' and jc.status=''Active'' and contact_category=''Common'')) As Property_Manager,
(select cd.contact_first_name+'' ''+cd.contact_last_name from '+QUOTENAME(@Tenant)+'.'+'contact_details cd where cd.contact_id=(select Top 1 jc.contact_id from '+QUOTENAME(@Tenant)+'.'+'job_contacts jc
where jc.job_id=j.job_id and jc.contact_work_type=''Public Adjuster'' and jc.status=''Active'' and contact_category=''Common'')) As Public_Adjuster,
(select cd.contact_first_name+'' ''+cd.contact_last_name from '+QUOTENAME(@Tenant)+'.'+'contact_details cd where cd.contact_id=(select Top 1 jc.contact_id from '+QUOTENAME(@Tenant)+'.'+'job_contacts jc
where jc.job_id=j.job_id and jc.contact_work_type=''Independent Adjuster'' and jc.status=''Active'' and contact_category=''Common'')) As Independent_Adjuster,'
END
/**** Kpi Target******/
BEGIN
SET @SQL=@SQL+
'(select Top 1 jk.kpi_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Cycle Time'' and jk.kpi_value>=0) As Cycle_Time,
(select Top 1 jk.kpi_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''WIP Time'' and jk.kpi_value>=0) As WIP_Time,
(select Top 1 jk.kpi_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Total Final Invoice Time'' and jk.kpi_value>=0) As Total_Final_Invoice_Time,
(select Top 1 jk.kpi_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Days to Start'' and jk.kpi_value>=0) As Days_to_Start,
(select Top 1 jk.kpi_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Estimate Bid Time'' and jk.kpi_value>=0) As Estimate_Bid_Time,
(select Top 1 jk.kpi_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Final Estimate Upload Time'' and jk.kpi_value>=0) As Final_Estimate_Upload_Time,
(select Top 1 jk.kpi_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Onsite Arrival Time'' and jk.kpi_value>=0) As Onsite_Arrival_Time,
(select Top 1 jk.kpi_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Target Completion Accuracy'' and jk.kpi_value>=0) As Target_Completion_Accuracy,
(select Top 1 jk.kpi_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Contact Customer Time'' and jk.kpi_value>=0) As Contact_Customer_Time,
(select Top 1 jk.kpi_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Days to Sign'' and jk.kpi_value>=0) As Days_to_Sign,
(select Top 1 jk.kpi_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Final Invoice Delay Time'' and jk.kpi_value>=0) As Final_Invoice_Delay_Time,
(select Top 1 jk.kpi_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Gross Profit %'' and jk.kpi_value>=0) As Gross_Profit,
(select Top 1 jk.kpi_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Labor Efficiency Ratio'' and jk.kpi_value>=0) As Labor_Efficiency_Ratio,
'
END

/**** Kpi Target ******/
BEGIN
SET @SQL=@SQL+
'(select Top 1 jk.kpi_target_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Cycle Time'') As Cycle_Time_Target_Value,
(select Top 1 jk.kpi_target_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''WIP Time'') As WIP_Time_Target_Value,
(select Top 1 jk.kpi_target_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Total Final Invoice Time'') As Total_Final_Invoice_Time_Target_Value,
(select Top 1 jk.kpi_target_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Days to Start'') As Days_to_Start_Target_Value,
(select Top 1 jk.kpi_target_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Estimate Bid Time'') As Estimate_Bid_Time_Target_Value,
(select Top 1 jk.kpi_target_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Final Estimate Upload Time'') As Final_Estimate_Upload_Time_Target_Value,
(select Top 1 jk.kpi_target_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Onsite Arrival Time'') As Onsite_Arrival_Time_Target_Value,
(select Top 1 jk.kpi_target_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Target Completion Accuracy'') As Target_Completion_Accuracy_Target_Value,
(select Top 1 jk.kpi_target_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Contact Customer Time'') As Contact_Customer_Time_Target_Value,
(select Top 1 jk.kpi_target_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Days to Sign'') As Days_to_Sign_Target_Value,
(select Top 1 jk.kpi_target_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Final Invoice Delay Time'') As Final_Invoice_Delay_Time_Target_Value,
(select Top 1 jk.kpi_target_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Gross Profit %'') As Gross_Profit_Target_Value,
(select Top 1 jk.kpi_target_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Labor Efficiency Ratio'') As Labor_Efficiency_Ratio_Target_Value,
'
END

BEGIN
SET @SQL=@SQL+'m.dateofLoss AS Date_of_Loss,m.dateReceived AS Date_Received,m.datecontacted AS Date_Contacted,
m.dateinspected AS Arrived_onsite,m.dateofWorkAuthorization AS Work_Authorization,m.dateEstimatesent AS Estimate_Uploaded,
m.dateEstimateApproved AS Estimate_Approved,m.dateinventoried AS dateinventoried,m.intoProductiondate AS Assigned_to_Production_or_Into_Production,
m.target_start_date AS Target_Start_Date,m.startdate AS Start_Date,m.dateofmajoritycompletion AS Date_of_Majoritycompletion,
m.targetcompletiondate AS Target_Completion_Date,m.dateOfcOs AS COC_Actual_Completion_Date,m.dateinvoiced AS Date_Invoiced,m.final_invoice_date AS Final_Invoice_Date,
m.datePaid AS Date_Paid,m.closeddate AS Closed_Date,
j.created_datetime AS Created_Datetime,j.dash_file_created_date AS File_Date,
j.tpa_name as TPA,

(select sum(e.estimated_amount) from '+QUOTENAME(@Tenant)+'.'+'job_estimate e where e.job_id=j.job_id and e.status=''Active'') as Total_Estimate_Amount,
j.total_invoice as Total_Invoice,
j.total_cost as Total_Vendor_Cost,j.total_credits as Total_Credits,
(select sum(l.total_cost) from '+QUOTENAME(@Tenant)+'.'+'user_payroll_details l where l.job_id=j.job_id and l.labor_type = ''Labor'' and  (l.status=''Active'' or l.status is null)) as Job_Cost_Labor,
(select sum(l.total_cost) from '+QUOTENAME(@Tenant)+'.'+'user_payroll_details l where l.job_id=j.job_id and l.labor_type = ''Travel Time'' and  (l.status=''Active'' or l.status is null)) as Job_Cost_Travel,
(select case when sum(l.total_cost) is null then 0 else sum(l.total_cost) end from '+QUOTENAME(@Tenant)+'.'+'user_payroll_details l where l.job_id=j.job_id and l.labor_type in (''Labor'',''Travel Time'') and  (l.status=''Active'' or l.status is null)) as Job_Cost_Total_Labor,
j.total_payment as Total_Collected,j.dash_file_number as Ref_No,(CASE WHEN j.customer_type=''Customer'' then concat(j.first_name,'' '',j.last_name) ELSE j.customer_company_name end) as customerName,j.last_activity as Days_since_last_activity,
j.email as Email,j.property_type as Property_Type,
(select mp.program_type from '+QUOTENAME(@Tenant)+'.'+'m_program mp where mp.program_type_id=j.program_type and mp.status=''Active'') as Program_Type,
(select mc.config_value from '+QUOTENAME(@Tenant)+'.'+'m_config_data mc where mc.config_id=j.cause_of_loss and config_name=''Cause of Loss'' and mc.status=''Active'') as Cause_of_Loss,
(select ic.insurance_company_name from '+QUOTENAME(@Tenant)+'.'+'job_insurance_details ic where ic.job_id=j.job_id ) as Insurance_Company,
(select ic.claim_number from '+QUOTENAME(@Tenant)+'.'+'job_insurance_details ic where ic.job_id=j.job_id ) as Claim_Number,
j.referred_source as Referred_Source,j.comment as Closure_Explanation,j.reason as Closure_Reason,j.rough_estimate as Rough_Estimate_Total,
j.job_name as File_Name,DATEDIFF(day, j.created_datetime, (SELECT GETDATE())) as File_Age,DATEDIFF(day, j.status_change_datetime,
(SELECT GETDATE())) as Age_In_Current_Status,
(select m.status_category from '+QUOTENAME(@Tenant)+'.'+'m_status_configuration m where  m.additional_status = j.current_job_status and m.status=''Active'') as Sold_Status,



'

END
BEGIN
SET @SQL=@SQL+'
DATEADD(day, DATEDIFF(day, ' +cast (@weekDay as NVARCHAR(10))+ ', m.dateofLoss) /7*7, ' +cast (@weekDay as NVARCHAR(10))+ ') as Date_of_Loss_Week,
DATEADD(day, DATEDIFF(day, ' +cast (@weekDay as NVARCHAR(10))+ ', m.dateReceived) /7*7, ' +cast (@weekDay as NVARCHAR(10))+ ') as Date_Received_Week,
DATEADD(day, DATEDIFF(day, ' +cast (@weekDay as NVARCHAR(10))+ ', m.datecontacted) /7*7, ' +cast (@weekDay as NVARCHAR(10))+ ') as Data_Contacted_Week,
DATEADD(day, DATEDIFF(day, ' +cast (@weekDay as NVARCHAR(10))+ ', m.dateinspected) /7*7, ' +cast (@weekDay as NVARCHAR(10))+ ') as Data_Inspected_Week,
DATEADD(day, DATEDIFF(day, ' +cast (@weekDay as NVARCHAR(10))+ ', m.dateofWorkAuthorization) /7*7, ' +cast (@weekDay as NVARCHAR(10))+ ') as Data_WorkAuthorization_Week,
DATEADD(day, DATEDIFF(day, ' +cast (@weekDay as NVARCHAR(10))+ ', m.dateEstimatesent) /7*7, ' +cast (@weekDay as NVARCHAR(10))+ ') as Estimate_Uploaded_Sent_Week,
DATEADD(day, DATEDIFF(day, ' +cast (@weekDay as NVARCHAR(10))+ ', m.dateEstimateApproved) /7*7, ' +cast (@weekDay as NVARCHAR(10))+ ') as Estimate_Approved_Week,
DATEADD(day, DATEDIFF(day, ' +cast (@weekDay as NVARCHAR(10))+ ', m.dateinventoried) /7*7, ' +cast (@weekDay as NVARCHAR(10))+ ') as Date_Inventoried_Week,
DATEADD(day, DATEDIFF(day, ' +cast (@weekDay as NVARCHAR(10))+ ', m.intoProductiondate) /7*7, ' +cast (@weekDay as NVARCHAR(10))+ ') as Assigned_to_Production_or_Into_Production_Week,
DATEADD(day, DATEDIFF(day, ' +cast (@weekDay as NVARCHAR(10))+ ', m.target_start_date) /7*7, ' +cast (@weekDay as NVARCHAR(10))+ ') as Target_Start_Date_Week,
DATEADD(day, DATEDIFF(day, ' +cast (@weekDay as NVARCHAR(10))+ ', m.startdate) /7*7, ' +cast (@weekDay as NVARCHAR(10))+ ') as Start_Date_Week,
DATEADD(day, DATEDIFF(day, ' +cast (@weekDay as NVARCHAR(10))+ ', m.targetcompletiondate) /7*7, ' +cast (@weekDay as NVARCHAR(10))+ ') as Target_Completion_Date_Week,
DATEADD(day, DATEDIFF(day, ' +cast (@weekDay as NVARCHAR(10))+ ', m.dateOfcOs) /7*7, ' +cast (@weekDay as NVARCHAR(10))+ ') as COC_Actual_Completion_Date_Week,
DATEADD(day, DATEDIFF(day, ' +cast (@weekDay as NVARCHAR(10))+ ', m.dateinvoiced) /7*7, ' +cast (@weekDay as NVARCHAR(10))+ ') as Date_Invoiced_Week,

DATEADD(day, DATEDIFF(day, ' +cast (@weekDay as NVARCHAR(10))+ ', m.final_invoice_date) /7*7, ' +cast (@weekDay as NVARCHAR(10))+ ') as Final_Invoice_Date_Week,
DATEADD(day, DATEDIFF(day,' +cast (@weekDay as NVARCHAR(10))+ ', m.datePaid) /7*7, ' +cast (@weekDay as NVARCHAR(10))+ ') as Date_Paid_Week,
DATEADD(day, DATEDIFF(day,' +cast (@weekDay as NVARCHAR(10))+ ', m.closeddate) /7*7, ' +cast (@weekDay as NVARCHAR(10))+ ') as Closed_Date_Week,
DATEADD(day, DATEDIFF(day,' +cast (@weekDay as NVARCHAR(10))+ ', j.dash_file_created_date) /7*7, ' +cast (@weekDay as NVARCHAR(10))+ ') as File_Created_Date_Week'


END
BEGIN
SET @SQL=@SQL+',j.marketing_campaign as Marketing_Campaign,
j.marketing_owner as Marketing_Owner,j.marketing_channel as Marketing_Channel,
j.marketing_source as Marketing_Source,j.marketing_lead_details as Marketing_Lead_Details,j.budget_gp_amount as Budget_Gp_Amount,j.budget_gp_percentage as Budget_GP_percentage,
(coalesce( j.total_cost,0) + (select case when sum(l.total_cost) is null then 0 else sum(l.total_cost) end from '+QUOTENAME(@Tenant)+'.'+'user_payroll_details l where l.job_id=j.job_id and l.labor_type in (''Labor'',''Travel Time'') and  (l.status=''Active'' or l.status is null))) as Total_Cost,
j.scratchpad as Scratchpad,j.scratchpad_date as Scratchpad_Date,CASE
WHEN j.referred_type =''Organization'' THEN
(select e.external_agency_name from '+QUOTENAME(@Tenant)+'.'+'external_agency_details e where cast(e.external_agency_id AS CHAR)=j.referred_by)
WHEN j.referred_type =''People'' THEN
(select c.contact_first_name+'' ''+c.contact_last_name from '+QUOTENAME(@Tenant)+'.'+'contact_details c where cast(c.contact_id AS CHAR)=j.referred_by)
ELSE
j.referred_by
end
as Referred_By,CASE WHEN j.referred_type =''Organization'' THEN (select e.external_agency_name from '+QUOTENAME(@Tenant)+'.'+'external_agency_details e where cast(e.external_agency_id AS CHAR)=j.referred_by)
WHEN j.referred_type =''People'' THEN (select e.external_agency_name from
'+QUOTENAME(@Tenant)+'.'+'external_agency_details e where e.external_agency_id=(select external_agency_id from '+QUOTENAME(@Tenant)+'.'+'contact_details c where contact_id=j.referred_by and c.contact_status=''Active''))
ELSE NULL END as Referred_By_Organization_Name'
END

BEGIN
SET @SQL=@SQL+' from '+QUOTENAME(@Tenant)+'.'+'job_details j
left join '+QUOTENAME(@Tenant)+'.'+'common_milestones m on j.job_id = m.source_id
 where j.created_datetime>='''+CONVERT(nvarchar, @startDate)+''' and j.created_datetime<='''+CONVERT(nvarchar, @endDate)+'''
 and j.current_job_status !=''Deleted'' order by j.job_id desc';
END

EXEC (@SQL)
print  (@SQL)
GO

GO
-- =============================================
-- Stored Procedure: [dbo].[all_jobs_report_export_test_SP]
-- Repeatable Migration - Re-runs when content changes
-- =============================================
CREATE OR ALTER PROCEDURE  [dbo].[all_jobs_report_export_test_SP]
(@Tenant Varchar(255),@startDate Datetime,@endDate Datetime,@Week INT)
As

DECLARE @SQL VARCHAR(MAX)
DECLARE @weekDay Int = @Week -1;
SET @SQL=N';

SET DATEFIRST ' +cast (@Week as NVARCHAR(10))+ ' Select  DATEADD(day, DATEDIFF(day, ' +cast (@weekDay as NVARCHAR(10))+ ' , j.created_datetime) /7*7, ' +cast (@weekDay as NVARCHAR(10))+ ') as Week_Day,
 (select l.location_code from '+QUOTENAME(@Tenant)+'.'+'rest_comp_location l where l.rest_comp_location_id=j.rest_comp_location_id) as Location,
 (select m.mast_num_code from '+QUOTENAME(@Tenant)+'.'+'mast_num_details m where m.mast_num_id=j.mast_num_id) as Master_Job_Number,
 (select m.company from '+QUOTENAME(@Tenant)+'.'+'mast_num_details m where m.mast_num_id=j.mast_num_id) as PropertyManagementCompany,
j.job_id as jobID#,j.job_code AS File_Number,j.job_type AS Division,
j.loss_address AS Loss_Address,j.loss_address_city AS City,
j.loss_address_state AS State,j.loss_address_zip AS Zip,j.current_job_status as Status,
j.mobile AS Cell_Number,j.work_phone AS Work_Number,j.phone1 AS Home_Number,

(select TOP 1 u.first_name +'' ''+u.last_name from ' + QUOTENAME(@Tenant) + '.job_roles jr join ' + QUOTENAME(@Tenant) + '.user_user_details u on u.user_id = jr.user_id
where jr.job_id = j.job_id and jr.role_name = ''Supervisor'' and jr.job_role_status = ''Active'') As Supervisor,
(select TOP 1 u.first_name +'' ''+u.last_name from ' + QUOTENAME(@Tenant) + '.job_roles jr join ' + QUOTENAME(@Tenant) + '.user_user_details u on u.user_id = jr.user_id
where jr.job_id = j.job_id and jr.role_name = ''Estimator'' and jr.job_role_status = ''Active'') As Estimator,
(select TOP 1 u.first_name +'' ''+u.last_name from ' + QUOTENAME(@Tenant) + '.job_roles jr join ' + QUOTENAME(@Tenant) + '.user_user_details u on u.user_id = jr.user_id
where jr.job_id = j.job_id and jr.role_name = ''Sales Representative'' and jr.job_role_status = ''Active'') As Sales_Representative,
(select TOP 1 u.first_name +'' ''+u.last_name from ' + QUOTENAME(@Tenant) + '.job_roles jr join ' + QUOTENAME(@Tenant) + '.user_user_details u on u.user_id = jr.user_id
where jr.job_id = j.job_id and jr.role_name = ''Coordinator'' and jr.job_role_status = ''Active'') As Coordinator,
(select TOP 1 u.first_name +'' ''+u.last_name from ' + QUOTENAME(@Tenant) + '.job_roles jr join ' + QUOTENAME(@Tenant) + '.user_user_details u on u.user_id = jr.user_id
where jr.job_id = j.job_id and jr.role_name = ''Finance'' and jr.job_role_status = ''Active'') As Finance,
(select TOP 1 u.first_name +'' ''+u.last_name from ' + QUOTENAME(@Tenant) + '.job_roles jr join ' + QUOTENAME(@Tenant) + '.user_user_details u on u.user_id = jr.user_id
where jr.job_id = j.job_id and jr.role_name = ''Administrator'' and jr.job_role_status = ''Active'') As Administrator,
(select TOP 1 u.first_name +'' ''+u.last_name from ' + QUOTENAME(@Tenant) + '.job_roles jr join ' + QUOTENAME(@Tenant) + '.user_user_details u on u.user_id = jr.user_id
where jr.job_id = j.job_id and jr.role_name = ''Role'' and jr.job_role_status = ''Active'') As Role,
(select TOP 1 u.first_name +'' ''+u.last_name from ' + QUOTENAME(@Tenant) + '.job_roles jr join ' + QUOTENAME(@Tenant) + '.user_user_details u on u.user_id = jr.user_id
where jr.job_id = j.job_id and jr.role_name = ''Lead Technician'' and jr.job_role_status = ''Active'') As Lead_Technician,'

/** Contact Details ****/
BEGIN
SET @SQL=@SQL+'(select cd.contact_first_name+'' ''+cd.contact_last_name from '+QUOTENAME(@Tenant)+'.'+'contact_details cd where cd.contact_id=(select Top 1jc.contact_id from '+QUOTENAME(@Tenant)+'.'+'job_contacts jc
where jc.job_id=j.job_id and jc.contact_work_type=''Adjuster'' and jc.status=''Active'' and contact_category=''Common'')) As Assigned_Adjuster,
(select cd.contact_first_name+'' ''+cd.contact_last_name from '+QUOTENAME(@Tenant)+'.'+'contact_details cd where cd.contact_id=(select Top 1 jc.contact_id from '+QUOTENAME(@Tenant)+'.'+'job_contacts jc
where jc.job_id=j.job_id and jc.contact_work_type=''Insurance Agent'' and jc.status=''Active'' and contact_category=''Common'')) As Assigned_Agent,
(select cd.contact_first_name+'' ''+cd.contact_last_name from '+QUOTENAME(@Tenant)+'.'+'contact_details cd where cd.contact_id=(select Top 1 jc.contact_id from '+QUOTENAME(@Tenant)+'.'+'job_contacts jc
where jc.job_id=j.job_id and jc.contact_work_type=''Property Manager'' and jc.status=''Active'' and contact_category=''Common'')) As Property_Manager,
(select cd.contact_first_name+'' ''+cd.contact_last_name from '+QUOTENAME(@Tenant)+'.'+'contact_details cd where cd.contact_id=(select Top 1 jc.contact_id from '+QUOTENAME(@Tenant)+'.'+'job_contacts jc
where jc.job_id=j.job_id and jc.contact_work_type=''Public Adjuster'' and jc.status=''Active'' and contact_category=''Common'')) As Public_Adjuster,
(select cd.contact_first_name+'' ''+cd.contact_last_name from '+QUOTENAME(@Tenant)+'.'+'contact_details cd where cd.contact_id=(select Top 1 jc.contact_id from '+QUOTENAME(@Tenant)+'.'+'job_contacts jc
where jc.job_id=j.job_id and jc.contact_work_type=''Independent Adjuster'' and jc.status=''Active'' and contact_category=''Common'')) As Independent_Adjuster,'
END
/**** Kpi Target******/
BEGIN
SET @SQL=@SQL+
'(select Top 1 jk.kpi_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Cycle Time'' and jk.kpi_value>=0) As Cycle_Time,
(select Top 1 jk.kpi_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''WIP Time'' and jk.kpi_value>=0) As WIP_Time,
(select Top 1 jk.kpi_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Total Final Invoice Time'' and jk.kpi_value>=0) As Total_Final_Invoice_Time,
(select Top 1 jk.kpi_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Days to Start'' and jk.kpi_value>=0) As Days_to_Start,
(select Top 1 jk.kpi_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Estimate Bid Time'' and jk.kpi_value>=0) As Estimate_Bid_Time,
(select Top 1 jk.kpi_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Final Estimate Upload Time'' and jk.kpi_value>=0) As Final_Estimate_Upload_Time,
(select Top 1 jk.kpi_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Onsite Arrival Time'' and jk.kpi_value>=0) As Onsite_Arrival_Time,
(select Top 1 jk.kpi_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Target Completion Accuracy'' and jk.kpi_value>=0) As Target_Completion_Accuracy,
(select Top 1 jk.kpi_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Contact Customer Time'' and jk.kpi_value>=0) As Contact_Customer_Time,
(select Top 1 jk.kpi_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Days to Sign'' and jk.kpi_value>=0) As Days_to_Sign,
(select Top 1 jk.kpi_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Final Invoice Delay Time'' and jk.kpi_value>=0) As Final_Invoice_Delay_Time,
(select Top 1 jk.kpi_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Gross Profit %'' and jk.kpi_value>=0) As Gross_Profit,
(select Top 1 jk.kpi_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Labor Efficiency Ratio'' and jk.kpi_value>=0) As Labor_Efficiency_Ratio,
'
END

/**** Kpi Target ******/
BEGIN
SET @SQL=@SQL+
'(select Top 1 jk.kpi_target_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Cycle Time'') As Cycle_Time_Target_Value,
(select Top 1 jk.kpi_target_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''WIP Time'') As WIP_Time_Target_Value,
(select Top 1 jk.kpi_target_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Total Final Invoice Time'') As Total_Final_Invoice_Time_Target_Value,
(select Top 1 jk.kpi_target_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Days to Start'') As Days_to_Start_Target_Value,
(select Top 1 jk.kpi_target_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Estimate Bid Time'') As Estimate_Bid_Time_Target_Value,
(select Top 1 jk.kpi_target_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Final Estimate Upload Time'') As Final_Estimate_Upload_Time_Target_Value,
(select Top 1 jk.kpi_target_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Onsite Arrival Time'') As Onsite_Arrival_Time_Target_Value,
(select Top 1 jk.kpi_target_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Target Completion Accuracy'') As Target_Completion_Accuracy_Target_Value,
(select Top 1 jk.kpi_target_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Contact Customer Time'') As Contact_Customer_Time_Target_Value,
(select Top 1 jk.kpi_target_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Days to Sign'') As Days_to_Sign_Target_Value,
(select Top 1 jk.kpi_target_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Final Invoice Delay Time'') As Final_Invoice_Delay_Time_Target_Value,
(select Top 1 jk.kpi_target_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Gross Profit %'') As Gross_Profit_Target_Value,
(select Top 1 jk.kpi_target_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Labor Efficiency Ratio'') As Labor_Efficiency_Ratio_Target_Value,
'
END

BEGIN
SET @SQL=@SQL+'m.dateofLoss AS Date_of_Loss,m.dateReceived AS Date_Received,m.datecontacted AS Date_Contacted,
m.dateinspected AS Arrived_onsite,m.dateofWorkAuthorization AS Work_Authorization,m.dateEstimatesent AS Estimate_Uploaded,
m.dateEstimateApproved AS Estimate_Approved,m.dateinventoried AS dateinventoried,m.intoProductiondate AS Assigned_to_Production_or_Into_Production,
m.target_start_date AS Target_Start_Date,m.startdate AS Start_Date,m.dateofmajoritycompletion AS Date_of_Majoritycompletion,
m.targetcompletiondate AS Target_Completion_Date,m.dateOfcOs AS COC_Actual_Completion_Date,m.dateinvoiced AS Date_Invoiced,m.final_invoice_date AS Final_Invoice_Date,
m.datePaid AS Date_Paid,m.closeddate AS Closed_Date,
j.created_datetime AS Created_Datetime,j.dash_file_created_date AS File_Date,
j.tpa_name as TPA,

(select sum(e.estimated_amount) from '+QUOTENAME(@Tenant)+'.'+'job_estimate e where e.job_id=j.job_id and e.status=''Active'') as Total_Estimate_Amount,
j.total_invoice as Total_Invoice,
j.total_cost as Total_Vendor_Cost,j.total_credits as Total_Credits,
(select sum(l.total_cost) from '+QUOTENAME(@Tenant)+'.'+'user_payroll_details l where l.job_id=j.job_id and l.labor_type = ''Labor'' and  (l.status=''Active'' or l.status is null)) as Job_Cost_Labor,
(select sum(l.total_cost) from '+QUOTENAME(@Tenant)+'.'+'user_payroll_details l where l.job_id=j.job_id and l.labor_type = ''Travel Time'' and  (l.status=''Active'' or l.status is null)) as Job_Cost_Travel,
(select case when sum(l.total_cost) is null then 0 else sum(l.total_cost) end from '+QUOTENAME(@Tenant)+'.'+'user_payroll_details l where l.job_id=j.job_id and l.labor_type in (''Labor'',''Travel Time'') and  (l.status=''Active'' or l.status is null)) as Job_Cost_Total_Labor,
j.total_payment as Total_Collected,j.dash_file_number as Ref_No,(CASE WHEN j.customer_type=''Customer'' then concat(j.first_name,'' '',j.last_name) ELSE j.customer_company_name end) as customerName,j.last_activity as Days_since_last_activity,
j.email as Email,j.property_type as Property_Type,
(select mp.program_type from '+QUOTENAME(@Tenant)+'.'+'m_program mp where mp.program_type_id=j.program_type and mp.status=''Active'') as Program_Type,
(select mc.config_value from '+QUOTENAME(@Tenant)+'.'+'m_config_data mc where mc.config_id=j.cause_of_loss and config_name=''Cause of Loss'' and mc.status=''Active'') as Cause_of_Loss,
(select ic.insurance_company_name from '+QUOTENAME(@Tenant)+'.'+'job_insurance_details ic where ic.job_id=j.job_id ) as Insurance_Company,
(select ic.claim_number from '+QUOTENAME(@Tenant)+'.'+'job_insurance_details ic where ic.job_id=j.job_id ) as Claim_Number,
j.referred_source as Referred_Source,j.comment as Closure_Explanation,j.reason as Closure_Reason,j.rough_estimate as Rough_Estimate_Total,
j.job_name as File_Name,DATEDIFF(day, j.created_datetime, (SELECT GETDATE())) as File_Age,DATEDIFF(day, j.status_change_datetime,
(SELECT GETDATE())) as Age_In_Current_Status,
(select m.status_category from '+QUOTENAME(@Tenant)+'.'+'m_status_configuration m where  m.additional_status = j.current_job_status and m.status=''Active'') as Sold_Status,



'

END
BEGIN
SET @SQL=@SQL+'
DATEADD(day, DATEDIFF(day, ' +cast (@weekDay as NVARCHAR(10))+ ', m.dateofLoss) /7*7, ' +cast (@weekDay as NVARCHAR(10))+ ') as Date_of_Loss_Week,
DATEADD(day, DATEDIFF(day, ' +cast (@weekDay as NVARCHAR(10))+ ', m.dateReceived) /7*7, ' +cast (@weekDay as NVARCHAR(10))+ ') as Date_Received_Week,
DATEADD(day, DATEDIFF(day, ' +cast (@weekDay as NVARCHAR(10))+ ', m.datecontacted) /7*7, ' +cast (@weekDay as NVARCHAR(10))+ ') as Data_Contacted_Week,
DATEADD(day, DATEDIFF(day, ' +cast (@weekDay as NVARCHAR(10))+ ', m.dateinspected) /7*7, ' +cast (@weekDay as NVARCHAR(10))+ ') as Data_Inspected_Week,
DATEADD(day, DATEDIFF(day, ' +cast (@weekDay as NVARCHAR(10))+ ', m.dateofWorkAuthorization) /7*7, ' +cast (@weekDay as NVARCHAR(10))+ ') as Data_WorkAuthorization_Week,
DATEADD(day, DATEDIFF(day, ' +cast (@weekDay as NVARCHAR(10))+ ', m.dateEstimatesent) /7*7, ' +cast (@weekDay as NVARCHAR(10))+ ') as Estimate_Uploaded_Sent_Week,
DATEADD(day, DATEDIFF(day, ' +cast (@weekDay as NVARCHAR(10))+ ', m.dateEstimateApproved) /7*7, ' +cast (@weekDay as NVARCHAR(10))+ ') as Estimate_Approved_Week,
DATEADD(day, DATEDIFF(day, ' +cast (@weekDay as NVARCHAR(10))+ ', m.dateinventoried) /7*7, ' +cast (@weekDay as NVARCHAR(10))+ ') as Date_Inventoried_Week,
DATEADD(day, DATEDIFF(day, ' +cast (@weekDay as NVARCHAR(10))+ ', m.intoProductiondate) /7*7, ' +cast (@weekDay as NVARCHAR(10))+ ') as Assigned_to_Production_or_Into_Production_Week,
DATEADD(day, DATEDIFF(day, ' +cast (@weekDay as NVARCHAR(10))+ ', m.target_start_date) /7*7, ' +cast (@weekDay as NVARCHAR(10))+ ') as Target_Start_Date_Week,
DATEADD(day, DATEDIFF(day, ' +cast (@weekDay as NVARCHAR(10))+ ', m.startdate) /7*7, ' +cast (@weekDay as NVARCHAR(10))+ ') as Start_Date_Week,
DATEADD(day, DATEDIFF(day, ' +cast (@weekDay as NVARCHAR(10))+ ', m.targetcompletiondate) /7*7, ' +cast (@weekDay as NVARCHAR(10))+ ') as Target_Completion_Date_Week,
DATEADD(day, DATEDIFF(day, ' +cast (@weekDay as NVARCHAR(10))+ ', m.dateOfcOs) /7*7, ' +cast (@weekDay as NVARCHAR(10))+ ') as COC_Actual_Completion_Date_Week,
DATEADD(day, DATEDIFF(day, ' +cast (@weekDay as NVARCHAR(10))+ ', m.dateinvoiced) /7*7, ' +cast (@weekDay as NVARCHAR(10))+ ') as Date_Invoiced_Week,

DATEADD(day, DATEDIFF(day, ' +cast (@weekDay as NVARCHAR(10))+ ', m.final_invoice_date) /7*7, ' +cast (@weekDay as NVARCHAR(10))+ ') as Final_Invoice_Date_Week,
DATEADD(day, DATEDIFF(day,' +cast (@weekDay as NVARCHAR(10))+ ', m.datePaid) /7*7, ' +cast (@weekDay as NVARCHAR(10))+ ') as Date_Paid_Week,
DATEADD(day, DATEDIFF(day,' +cast (@weekDay as NVARCHAR(10))+ ', m.closeddate) /7*7, ' +cast (@weekDay as NVARCHAR(10))+ ') as Closed_Date_Week,
DATEADD(day, DATEDIFF(day,' +cast (@weekDay as NVARCHAR(10))+ ', j.dash_file_created_date) /7*7, ' +cast (@weekDay as NVARCHAR(10))+ ') as File_Created_Date_Week'


END
BEGIN
SET @SQL=@SQL+',j.marketing_campaign as Marketing_Campaign,
j.marketing_owner as Marketing_Owner,j.marketing_channel as Marketing_Channel,
j.marketing_source as Marketing_Source,j.marketing_lead_details as Marketing_Lead_Details,j.budget_gp_amount as Budget_Gp_Amount,j.budget_gp_percentage as Budget_GP_percentage,
(coalesce( j.total_cost,0) + (select case when sum(l.total_cost) is null then 0 else sum(l.total_cost) end from '+QUOTENAME(@Tenant)+'.'+'user_payroll_details l where l.job_id=j.job_id and l.labor_type in (''Labor'',''Travel Time'') and  (l.status=''Active'' or l.status is null))) as Total_Cost,
j.scratchpad as Scratchpad,j.scratchpad_date as Scratchpad_Date,CASE
WHEN j.referred_type =''Organization'' THEN
(select e.external_agency_name from '+QUOTENAME(@Tenant)+'.'+'external_agency_details e where cast(e.external_agency_id AS CHAR)=j.referred_by)
WHEN j.referred_type =''People'' THEN
(select c.contact_first_name+'' ''+c.contact_last_name from '+QUOTENAME(@Tenant)+'.'+'contact_details c where cast(c.contact_id AS CHAR)=j.referred_by)
ELSE
j.referred_by
end
as Referred_By,CASE WHEN j.referred_type =''Organization'' THEN (select e.external_agency_name from '+QUOTENAME(@Tenant)+'.'+'external_agency_details e where cast(e.external_agency_id AS CHAR)=j.referred_by)
WHEN j.referred_type =''People'' THEN (select e.external_agency_name from
'+QUOTENAME(@Tenant)+'.'+'external_agency_details e where e.external_agency_id=(select external_agency_id from '+QUOTENAME(@Tenant)+'.'+'contact_details c where contact_id=j.referred_by and c.contact_status=''Active''))
ELSE NULL END as Referred_By_Organization_Name,
case when (select count(*) from '+QUOTENAME(@Tenant)+'.'+'job_insurance_details i where i.job_id=j.job_id)>0 then ''No'' else ''Yes'' end as Self_Pay'
END

BEGIN
SET @SQL=@SQL+' from '+QUOTENAME(@Tenant)+'.'+'job_details j
left join '+QUOTENAME(@Tenant)+'.'+'common_milestones m on j.job_id = m.source_id
 where j.created_datetime>='''+CONVERT(nvarchar, @startDate)+''' and j.created_datetime<='''+CONVERT(nvarchar, @endDate)+'''
 and j.current_job_status !=''Deleted'' order by j.job_id desc';
END

EXEC (@SQL)
print  (@SQL)
GO

GO
-- =============================================
-- Stored Procedure: [dbo].[all_jobs_report_export]
-- Repeatable Migration - Re-runs when content changes
-- =============================================
CREATE OR ALTER PROCEDURE  [dbo].[all_jobs_report_export]
(@Tenant Varchar(255),@startDate Datetime,@endDate Datetime,@Week INT)
As

DECLARE @SQL VARCHAR(MAX)
DECLARE @weekDay Int = @Week -1;
SET @SQL=N';

SET DATEFIRST ' +cast (@Week as NVARCHAR(10))+ ' Select  DATEADD(day, DATEDIFF(day, ' +cast (@weekDay as NVARCHAR(10))+ ' , j.created_datetime) /7*7, ' +cast (@weekDay as NVARCHAR(10))+ ') as Week_Day,
 (select l.location_code from '+QUOTENAME(@Tenant)+'.'+'rest_comp_location l where l.rest_comp_location_id=j.rest_comp_location_id) as Location,
 (select m.mast_num_code from '+QUOTENAME(@Tenant)+'.'+'mast_num_details m where m.mast_num_id=j.mast_num_id) as Master_Job_Number,
 (select m.company from '+QUOTENAME(@Tenant)+'.'+'mast_num_details m where m.mast_num_id=j.mast_num_id) as PropertyManagementCompany,
j.job_id as jobID#,j.job_code AS File_Number,j.job_type AS Division,
j.loss_address AS Loss_Address,j.loss_address_city AS City,
j.loss_address_state AS State,j.loss_address_zip AS Zip,j.current_job_status as Status,
j.mobile AS Cell_Number,j.work_phone AS Work_Number,j.phone1 AS Home_Number,

(select TOP 1 u.first_name +'' ''+u.last_name from ' + QUOTENAME(@Tenant) + '.job_roles jr join ' + QUOTENAME(@Tenant) + '.user_user_details u on u.user_id = jr.user_id
where jr.job_id = j.job_id and jr.role_name = ''Supervisor'' and jr.job_role_status = ''Active'') As Supervisor,
(select TOP 1 u.first_name +'' ''+u.last_name from ' + QUOTENAME(@Tenant) + '.job_roles jr join ' + QUOTENAME(@Tenant) + '.user_user_details u on u.user_id = jr.user_id
where jr.job_id = j.job_id and jr.role_name = ''Estimator'' and jr.job_role_status = ''Active'') As Estimator,
(select TOP 1 u.first_name +'' ''+u.last_name from ' + QUOTENAME(@Tenant) + '.job_roles jr join ' + QUOTENAME(@Tenant) + '.user_user_details u on u.user_id = jr.user_id
where jr.job_id = j.job_id and jr.role_name = ''Sales Representative'' and jr.job_role_status = ''Active'') As Sales_Representative,
(select TOP 1 u.first_name +'' ''+u.last_name from ' + QUOTENAME(@Tenant) + '.job_roles jr join ' + QUOTENAME(@Tenant) + '.user_user_details u on u.user_id = jr.user_id
where jr.job_id = j.job_id and jr.role_name = ''Coordinator'' and jr.job_role_status = ''Active'') As Coordinator,
(select TOP 1 u.first_name +'' ''+u.last_name from ' + QUOTENAME(@Tenant) + '.job_roles jr join ' + QUOTENAME(@Tenant) + '.user_user_details u on u.user_id = jr.user_id
where jr.job_id = j.job_id and jr.role_name = ''Finance'' and jr.job_role_status = ''Active'') As Finance,
(select TOP 1 u.first_name +'' ''+u.last_name from ' + QUOTENAME(@Tenant) + '.job_roles jr join ' + QUOTENAME(@Tenant) + '.user_user_details u on u.user_id = jr.user_id
where jr.job_id = j.job_id and jr.role_name = ''Administrator'' and jr.job_role_status = ''Active'') As Administrator,
(select TOP 1 u.first_name +'' ''+u.last_name from ' + QUOTENAME(@Tenant) + '.job_roles jr join ' + QUOTENAME(@Tenant) + '.user_user_details u on u.user_id = jr.user_id
where jr.job_id = j.job_id and jr.role_name = ''Role'' and jr.job_role_status = ''Active'') As Role,
(select TOP 1 u.first_name +'' ''+u.last_name from ' + QUOTENAME(@Tenant) + '.job_roles jr join ' + QUOTENAME(@Tenant) + '.user_user_details u on u.user_id = jr.user_id
where jr.job_id = j.job_id and jr.role_name = ''Lead Technician'' and jr.job_role_status = ''Active'') As Lead_Technician,'

/** Contact Details ****/
BEGIN
SET @SQL=@SQL+'(select cd.contact_first_name+'' ''+cd.contact_last_name from '+QUOTENAME(@Tenant)+'.'+'contact_details cd where cd.contact_id=(select Top 1jc.contact_id from '+QUOTENAME(@Tenant)+'.'+'job_contacts jc
where jc.job_id=j.job_id and jc.contact_work_type=''Adjuster'' and jc.status=''Active'' and contact_category=''Common'')) As Assigned_Adjuster,
(select cd.contact_first_name+'' ''+cd.contact_last_name from '+QUOTENAME(@Tenant)+'.'+'contact_details cd where cd.contact_id=(select Top 1 jc.contact_id from '+QUOTENAME(@Tenant)+'.'+'job_contacts jc
where jc.job_id=j.job_id and jc.contact_work_type=''Insurance Agent'' and jc.status=''Active'' and contact_category=''Common'')) As Assigned_Agent,
(select cd.contact_first_name+'' ''+cd.contact_last_name from '+QUOTENAME(@Tenant)+'.'+'contact_details cd where cd.contact_id=(select Top 1 jc.contact_id from '+QUOTENAME(@Tenant)+'.'+'job_contacts jc
where jc.job_id=j.job_id and jc.contact_work_type=''Property Manager'' and jc.status=''Active'' and contact_category=''Common'')) As Property_Manager,
(select cd.contact_first_name+'' ''+cd.contact_last_name from '+QUOTENAME(@Tenant)+'.'+'contact_details cd where cd.contact_id=(select Top 1 jc.contact_id from '+QUOTENAME(@Tenant)+'.'+'job_contacts jc
where jc.job_id=j.job_id and jc.contact_work_type=''Public Adjuster'' and jc.status=''Active'' and contact_category=''Common'')) As Public_Adjuster,
(select cd.contact_first_name+'' ''+cd.contact_last_name from '+QUOTENAME(@Tenant)+'.'+'contact_details cd where cd.contact_id=(select Top 1 jc.contact_id from '+QUOTENAME(@Tenant)+'.'+'job_contacts jc
where jc.job_id=j.job_id and jc.contact_work_type=''Independent Adjuster'' and jc.status=''Active'' and contact_category=''Common'')) As Independent_Adjuster,'
END
/**** Kpi Target******/
BEGIN
SET @SQL=@SQL+
'(select Top 1 jk.kpi_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Cycle Time'' and jk.kpi_value>=0) As Cycle_Time,
(select Top 1 jk.kpi_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''WIP Time'' and jk.kpi_value>=0) As WIP_Time,
(select Top 1 jk.kpi_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Total Final Invoice Time'' and jk.kpi_value>=0) As Total_Final_Invoice_Time,
(select Top 1 jk.kpi_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Days to Start'' and jk.kpi_value>=0) As Days_to_Start,
(select Top 1 jk.kpi_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Estimate Bid Time'' and jk.kpi_value>=0) As Estimate_Bid_Time,
(select Top 1 jk.kpi_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Final Estimate Upload Time'' and jk.kpi_value>=0) As Final_Estimate_Upload_Time,
(select Top 1 jk.kpi_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Onsite Arrival Time'' and jk.kpi_value>=0) As Onsite_Arrival_Time,
(select Top 1 jk.kpi_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Target Completion Accuracy'' and jk.kpi_value>=0) As Target_Completion_Accuracy,
(select Top 1 jk.kpi_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Contact Customer Time'' and jk.kpi_value>=0) As Contact_Customer_Time,
(select Top 1 jk.kpi_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Days to Sign'' and jk.kpi_value>=0) As Days_to_Sign,
(select Top 1 jk.kpi_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Final Invoice Delay Time'' and jk.kpi_value>=0) As Final_Invoice_Delay_Time,
(select Top 1 jk.kpi_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Gross Profit %'' and jk.kpi_value>=0) As Gross_Profit,
(select Top 1 jk.kpi_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Labor Efficiency Ratio'' and jk.kpi_value>=0) As Labor_Efficiency_Ratio,
'
END

/**** Kpi Target ******/
BEGIN
SET @SQL=@SQL+
'(select Top 1 jk.kpi_target_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Cycle Time'') As Cycle_Time_Target_Value,
(select Top 1 jk.kpi_target_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''WIP Time'') As WIP_Time_Target_Value,
(select Top 1 jk.kpi_target_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Total Final Invoice Time'') As Total_Final_Invoice_Time_Target_Value,
(select Top 1 jk.kpi_target_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Days to Start'') As Days_to_Start_Target_Value,
(select Top 1 jk.kpi_target_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Estimate Bid Time'') As Estimate_Bid_Time_Target_Value,
(select Top 1 jk.kpi_target_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Final Estimate Upload Time'') As Final_Estimate_Upload_Time_Target_Value,
(select Top 1 jk.kpi_target_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Onsite Arrival Time'') As Onsite_Arrival_Time_Target_Value,
(select Top 1 jk.kpi_target_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Target Completion Accuracy'') As Target_Completion_Accuracy_Target_Value,
(select Top 1 jk.kpi_target_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Contact Customer Time'') As Contact_Customer_Time_Target_Value,
(select Top 1 jk.kpi_target_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Days to Sign'') As Days_to_Sign_Target_Value,
(select Top 1 jk.kpi_target_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Final Invoice Delay Time'') As Final_Invoice_Delay_Time_Target_Value,
(select Top 1 jk.kpi_target_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Gross Profit %'') As Gross_Profit_Target_Value,
(select Top 1 jk.kpi_target_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Labor Efficiency Ratio'') As Labor_Efficiency_Ratio_Target_Value,
'
END

BEGIN
SET @SQL=@SQL+'m.dateofLoss AS Date_of_Loss,m.dateReceived AS Date_Received,m.datecontacted AS Date_Contacted,
m.dateinspected AS Arrived_onsite,m.dateofWorkAuthorization AS Work_Authorization,m.dateEstimatesent AS Estimate_Uploaded,
m.dateEstimateApproved AS Estimate_Approved,m.dateinventoried AS dateinventoried,m.intoProductiondate AS Assigned_to_Production_or_Into_Production,
m.target_start_date AS Target_Start_Date,m.startdate AS Start_Date,m.dateofmajoritycompletion AS Date_of_Majoritycompletion,
m.targetcompletiondate AS Target_Completion_Date,m.dateOfcOs AS COC_Actual_Completion_Date,m.dateinvoiced AS Date_Invoiced,m.final_invoice_date AS Final_Invoice_Date,
m.datePaid AS Date_Paid,m.closeddate AS Closed_Date,
j.created_datetime AS Created_Datetime,j.dash_file_created_date AS File_Date,
j.tpa_name as TPA,

(select sum(e.estimated_amount) from '+QUOTENAME(@Tenant)+'.'+'job_estimate e where e.job_id=j.job_id and e.status=''Active'') as Total_Estimate_Amount,
j.total_invoice as Total_Invoice,
j.total_cost as Total_Vendor_Cost,j.total_credits as Total_Credits,
(select sum(l.total_cost) from '+QUOTENAME(@Tenant)+'.'+'user_payroll_details l where l.job_id=j.job_id and l.labor_type = ''Labor'' and  (l.status=''Active'' or l.status is null)) as Job_Cost_Labor,
(select sum(l.total_cost) from '+QUOTENAME(@Tenant)+'.'+'user_payroll_details l where l.job_id=j.job_id and l.labor_type = ''Travel Time'' and  (l.status=''Active'' or l.status is null)) as Job_Cost_Travel,
(select case when sum(l.total_cost) is null then 0 else sum(l.total_cost) end from '+QUOTENAME(@Tenant)+'.'+'user_payroll_details l where l.job_id=j.job_id and l.labor_type in (''Labor'',''Travel Time'') and  (l.status=''Active'' or l.status is null)) as Job_Cost_Total_Labor,
j.total_payment as Total_Collected,j.dash_file_number as Ref_No,(CASE WHEN j.customer_type=''Customer'' then concat(j.first_name,'' '',j.last_name) ELSE j.customer_company_name end) as customerName,j.last_activity as Days_since_last_activity,
j.email as Email,j.property_type as Property_Type,
(select mp.program_type from '+QUOTENAME(@Tenant)+'.'+'m_program mp where mp.program_type_id=j.program_type and mp.status=''Active'') as Program_Type,
(select mc.config_value from '+QUOTENAME(@Tenant)+'.'+'m_config_data mc where mc.config_id=j.cause_of_loss and config_name=''Cause of Loss'' and mc.status=''Active'') as Cause_of_Loss,
(select ic.insurance_company_name from '+QUOTENAME(@Tenant)+'.'+'job_insurance_details ic where ic.job_id=j.job_id ) as Insurance_Company,
(select ic.claim_number from '+QUOTENAME(@Tenant)+'.'+'job_insurance_details ic where ic.job_id=j.job_id ) as Claim_Number,
j.referred_source as Referred_Source,j.comment as Closure_Explanation,j.reason as Closure_Reason,j.rough_estimate as Rough_Estimate_Total,
j.job_name as File_Name,DATEDIFF(day, j.created_datetime, (SELECT GETDATE())) as File_Age,DATEDIFF(day, j.status_change_datetime,
(SELECT GETDATE())) as Age_In_Current_Status,
(select m.status_category from '+QUOTENAME(@Tenant)+'.'+'m_status_configuration m where  m.additional_status = j.current_job_status and m.status=''Active'') as Sold_Status,



'

END
BEGIN
SET @SQL=@SQL+'
DATEADD(day, DATEDIFF(day, ' +cast (@weekDay as NVARCHAR(10))+ ', m.dateofLoss) /7*7, ' +cast (@weekDay as NVARCHAR(10))+ ') as Date_of_Loss_Week,
DATEADD(day, DATEDIFF(day, ' +cast (@weekDay as NVARCHAR(10))+ ', m.dateReceived) /7*7, ' +cast (@weekDay as NVARCHAR(10))+ ') as Date_Received_Week,
DATEADD(day, DATEDIFF(day, ' +cast (@weekDay as NVARCHAR(10))+ ', m.datecontacted) /7*7, ' +cast (@weekDay as NVARCHAR(10))+ ') as Data_Contacted_Week,
DATEADD(day, DATEDIFF(day, ' +cast (@weekDay as NVARCHAR(10))+ ', m.dateinspected) /7*7, ' +cast (@weekDay as NVARCHAR(10))+ ') as Data_Inspected_Week,
DATEADD(day, DATEDIFF(day, ' +cast (@weekDay as NVARCHAR(10))+ ', m.dateofWorkAuthorization) /7*7, ' +cast (@weekDay as NVARCHAR(10))+ ') as Data_WorkAuthorization_Week,
DATEADD(day, DATEDIFF(day, ' +cast (@weekDay as NVARCHAR(10))+ ', m.dateEstimatesent) /7*7, ' +cast (@weekDay as NVARCHAR(10))+ ') as Estimate_Uploaded_Sent_Week,
DATEADD(day, DATEDIFF(day, ' +cast (@weekDay as NVARCHAR(10))+ ', m.dateEstimateApproved) /7*7, ' +cast (@weekDay as NVARCHAR(10))+ ') as Estimate_Approved_Week,
DATEADD(day, DATEDIFF(day, ' +cast (@weekDay as NVARCHAR(10))+ ', m.dateinventoried) /7*7, ' +cast (@weekDay as NVARCHAR(10))+ ') as Date_Inventoried_Week,
DATEADD(day, DATEDIFF(day, ' +cast (@weekDay as NVARCHAR(10))+ ', m.intoProductiondate) /7*7, ' +cast (@weekDay as NVARCHAR(10))+ ') as Assigned_to_Production_or_Into_Production_Week,
DATEADD(day, DATEDIFF(day, ' +cast (@weekDay as NVARCHAR(10))+ ', m.target_start_date) /7*7, ' +cast (@weekDay as NVARCHAR(10))+ ') as Target_Start_Date_Week,
DATEADD(day, DATEDIFF(day, ' +cast (@weekDay as NVARCHAR(10))+ ', m.startdate) /7*7, ' +cast (@weekDay as NVARCHAR(10))+ ') as Start_Date_Week,
DATEADD(day, DATEDIFF(day, ' +cast (@weekDay as NVARCHAR(10))+ ', m.targetcompletiondate) /7*7, ' +cast (@weekDay as NVARCHAR(10))+ ') as Target_Completion_Date_Week,
DATEADD(day, DATEDIFF(day, ' +cast (@weekDay as NVARCHAR(10))+ ', m.dateOfcOs) /7*7, ' +cast (@weekDay as NVARCHAR(10))+ ') as COC_Actual_Completion_Date_Week,
DATEADD(day, DATEDIFF(day, ' +cast (@weekDay as NVARCHAR(10))+ ', m.dateinvoiced) /7*7, ' +cast (@weekDay as NVARCHAR(10))+ ') as Date_Invoiced_Week,

DATEADD(day, DATEDIFF(day, ' +cast (@weekDay as NVARCHAR(10))+ ', m.final_invoice_date) /7*7, ' +cast (@weekDay as NVARCHAR(10))+ ') as Final_Invoice_Date_Week,
DATEADD(day, DATEDIFF(day,' +cast (@weekDay as NVARCHAR(10))+ ', m.datePaid) /7*7, ' +cast (@weekDay as NVARCHAR(10))+ ') as Date_Paid_Week,
DATEADD(day, DATEDIFF(day,' +cast (@weekDay as NVARCHAR(10))+ ', m.closeddate) /7*7, ' +cast (@weekDay as NVARCHAR(10))+ ') as Closed_Date_Week,
DATEADD(day, DATEDIFF(day,' +cast (@weekDay as NVARCHAR(10))+ ', j.dash_file_created_date) /7*7, ' +cast (@weekDay as NVARCHAR(10))+ ') as File_Created_Date_Week'


END
BEGIN
SET @SQL=@SQL+',j.marketing_campaign as Marketing_Campaign,
j.marketing_owner as Marketing_Owner,j.marketing_channel as Marketing_Channel,
j.marketing_source as Marketing_Source,j.marketing_lead_details as Marketing_Lead_Details,j.budget_gp_amount as Budget_Gp_Amount,j.budget_gp_percentage as Budget_GP_percentage,
(coalesce( j.total_cost,0) + (select case when sum(l.total_cost) is null then 0 else sum(l.total_cost) end from '+QUOTENAME(@Tenant)+'.'+'user_payroll_details l where l.job_id=j.job_id and l.labor_type in (''Labor'',''Travel Time'') and  (l.status=''Active'' or l.status is null))) as Total_Cost,
j.scratchpad as Scratchpad,j.scratchpad_date as Scratchpad_Date,CASE
WHEN j.referred_type =''Organization'' THEN
(select e.external_agency_name from '+QUOTENAME(@Tenant)+'.'+'external_agency_details e where cast(e.external_agency_id AS CHAR)=j.referred_by)
WHEN j.referred_type =''People'' THEN
(select c.contact_first_name+'' ''+c.contact_last_name from '+QUOTENAME(@Tenant)+'.'+'contact_details c where cast(c.contact_id AS CHAR)=j.referred_by)
ELSE
j.referred_by
end
as Referred_By,CASE WHEN j.referred_type =''Organization'' THEN (select e.external_agency_name from '+QUOTENAME(@Tenant)+'.'+'external_agency_details e where cast(e.external_agency_id AS CHAR)=j.referred_by)
WHEN j.referred_type =''People'' THEN (select e.external_agency_name from
'+QUOTENAME(@Tenant)+'.'+'external_agency_details e where e.external_agency_id=(select external_agency_id from '+QUOTENAME(@Tenant)+'.'+'contact_details c where contact_id=j.referred_by and c.contact_status=''Active''))
ELSE NULL END as Referred_By_Organization_Name,
case when (select count(*) from '+QUOTENAME(@Tenant)+'.'+'job_insurance_details i where i.job_id=j.job_id)>0 then ''No'' else ''Yes'' end as Self_Pay'
END

BEGIN
SET @SQL=@SQL+' from '+QUOTENAME(@Tenant)+'.'+'job_details j
left join '+QUOTENAME(@Tenant)+'.'+'common_milestones m on j.job_id = m.source_id
 where j.created_datetime>='''+CONVERT(nvarchar, @startDate)+''' and j.created_datetime<='''+CONVERT(nvarchar, @endDate)+'''
 and j.current_job_status !=''Deleted'' order by j.job_id desc';
END

EXEC (@SQL)
print  (@SQL)
GO

GO
-- =============================================
-- Stored Procedure: [dbo].[all_jobs_report_java21]
-- Repeatable Migration - Re-runs when content changes
-- =============================================
CREATE OR ALTER PROCEDURE  [dbo].[all_jobs_report_java21]
(@Tenant Varchar(255),@locationId INT)
As

DECLARE @SQL VARCHAR(MAX)
SET @SQL=N';
SET DATEFIRST 7 Select  DATEADD(day, DATEDIFF(day, 0, j.created_datetime) /7*7, 0) as weekDay, j.job_id AS jobId,j.job_code AS subJobCode,j.job_hash_code AS jobHashCode,j.job_type AS jobType,
j.first_name As firstName, j.last_name As lastName,j.loss_address AS lossAddress,j.loss_address_city AS city,
j.loss_address_state AS state,j.loss_address_zip AS zip,j.rest_comp_location_id as locationId,j.current_job_status as status,
(select m.company from '+QUOTENAME(@Tenant)+'.'+'mast_num_details m where m.mast_num_id=j.mast_num_id) as company,
(select m.mast_num_code from '+QUOTENAME(@Tenant)+'.'+'mast_num_details m where m.mast_num_id=j.mast_num_id) as mastNumCode,
j.mobile AS mobile,j.work_phone AS workPhone,j.phone1 AS phone1,
(select u.first_name+'' ''+u.last_name from '+QUOTENAME(@Tenant)+'.'+'user_user_details u where u.user_id=(select jr.user_id from '+QUOTENAME(@Tenant)+'.'+'job_roles jr
where jr.job_id=j.job_id and jr.role_name=''Supervisor'' and jr.job_role_status=''Active'')) As supervisor,
(select u.first_name+'' ''+u.last_name from '+QUOTENAME(@Tenant)+'.'+'user_user_details u where u.user_id=(select jr.user_id from '+QUOTENAME(@Tenant)+'.'+'job_roles jr
where jr.job_id=j.job_id and jr.role_name=''Estimator'' and jr.job_role_status=''Active'')) As estimator,
(select u.first_name+'' ''+u.last_name from '+QUOTENAME(@Tenant)+'.'+'user_user_details u where u.user_id=(select jr.user_id from '+QUOTENAME(@Tenant)+'.'+'job_roles jr
where jr.job_id=j.job_id and jr.role_name=''Sales Representative'' and jr.job_role_status=''Active'')) As salesRepresentative,
(select u.first_name+'' ''+u.last_name from '+QUOTENAME(@Tenant)+'.'+'user_user_details u where u.user_id=(select jr.user_id from '+QUOTENAME(@Tenant)+'.'+'job_roles jr
where jr.job_id=j.job_id and jr.role_name=''Coordinator'' and jr.job_role_status=''Active'')) As coordinator,
(select u.first_name+'' ''+u.last_name from '+QUOTENAME(@Tenant)+'.'+'user_user_details u where u.user_id=(select jr.user_id from '+QUOTENAME(@Tenant)+'.'+'job_roles jr
where jr.job_id=j.job_id and jr.role_name=''Finance'' and jr.job_role_status=''Active'')) As finance,
(select u.first_name+'' ''+u.last_name from '+QUOTENAME(@Tenant)+'.'+'user_user_details u where u.user_id=(select jr.user_id from '+QUOTENAME(@Tenant)+'.'+'job_roles jr
where jr.job_id=j.job_id and jr.role_name=''Administrator'' and jr.job_role_status=''Active'')) As administrator,
(select u.first_name+'' ''+u.last_name from '+QUOTENAME(@Tenant)+'.'+'user_user_details u where u.user_id=(select jr.user_id from '+QUOTENAME(@Tenant)+'.'+'job_roles jr
where jr.job_id=j.job_id and jr.role_name=''Role'' and jr.job_role_status=''Active'')) As Role,'

/** Contact Details ****/
BEGIN
SET @SQL=@SQL+'(select cd.contact_first_name+'' ''+cd.contact_last_name from '+QUOTENAME(@Tenant)+'.'+'contact_details cd where cd.contact_id=(select Top 1jc.contact_id from '+QUOTENAME(@Tenant)+'.'+'job_contacts jc
where jc.job_id=j.job_id and jc.contact_work_type=''Adjuster'' and jc.status=''Active'' and contact_category=''Common'')) As adjuster,
(select cd.contact_first_name+'' ''+cd.contact_last_name from '+QUOTENAME(@Tenant)+'.'+'contact_details cd where cd.contact_id=(select Top 1 jc.contact_id from '+QUOTENAME(@Tenant)+'.'+'job_contacts jc
where jc.job_id=j.job_id and jc.contact_work_type=''Insurance Agent'' and jc.status=''Active'' and contact_category=''Common'')) As insuranceAgent,
(select cd.contact_first_name+'' ''+cd.contact_last_name from '+QUOTENAME(@Tenant)+'.'+'contact_details cd where cd.contact_id=(select Top 1 jc.contact_id from '+QUOTENAME(@Tenant)+'.'+'job_contacts jc
where jc.job_id=j.job_id and jc.contact_work_type=''Property Manager'' and jc.status=''Active'' and contact_category=''Common'')) As propertyManager,
(select cd.contact_first_name+'' ''+cd.contact_last_name from '+QUOTENAME(@Tenant)+'.'+'contact_details cd where cd.contact_id=(select Top 1 jc.contact_id from '+QUOTENAME(@Tenant)+'.'+'job_contacts jc
where jc.job_id=j.job_id and jc.contact_work_type=''Public Adjuster'' and jc.status=''Active'' and contact_category=''Common'')) As publicAdjuster,
(select cd.contact_first_name+'' ''+cd.contact_last_name from '+QUOTENAME(@Tenant)+'.'+'contact_details cd where cd.contact_id=(select Top 1 jc.contact_id from '+QUOTENAME(@Tenant)+'.'+'job_contacts jc
where jc.job_id=j.job_id and jc.contact_work_type=''Independent Adjuster'' and jc.status=''Active'' and contact_category=''Common'')) As independentAdjuster,'
END
/**** Kpi Target******/
BEGIN
SET @SQL=@SQL+
'(select Top 1 jk.kpi_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Cycle Time'' and jk.kpi_value>=0) As cycleTime,
(select Top 1 jk.kpi_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''WIP Time'' and jk.kpi_value>=0) As wipTime,
(select Top 1 jk.kpi_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Total Final Invoice Time'' and jk.kpi_value>=0) As TotalFinalInvoiceTime,
(select Top 1 jk.kpi_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Days to Start'' and jk.kpi_value>=0) As daysToStart,
(select Top 1 jk.kpi_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Estimate Bid Time'' and jk.kpi_value>=0) As estimateBidTime,
(select Top 1 jk.kpi_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Final Estimate Upload Time'' and jk.kpi_value>=0) As finalEstimateUploadTime,
(select Top 1 jk.kpi_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Onsite Arrival Time'' and jk.kpi_value>=0) As onsiteArrivalTime,
(select Top 1 jk.kpi_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Target Completion Accuracy'' and jk.kpi_value>=0) As targetCompletion,
(select Top 1 jk.kpi_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Contact Customer Time'' and jk.kpi_value>=0) As contactCustomerTime,
(select Top 1 jk.kpi_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Days to Sign'' and jk.kpi_value>=0) As daysToSign,
(select Top 1 jk.kpi_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Final Invoice Delay Time'' and jk.kpi_value>=0) As finalInvoiceDelayTime,
(select Top 1 jk.kpi_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Gross Profit %'' and jk.kpi_value>=0) As grossProfit,
(select Top 1 jk.kpi_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Labor Efficiency Ratio'' and jk.kpi_value>=0) As LaborEfficiencyRation,
'
END

/**** Kpi Target ******/
BEGIN
SET @SQL=@SQL+
'(select Top 1 jk.kpi_target_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Cycle Time'') As cycleTimeTargetVal,
(select Top 1 jk.kpi_target_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''WIP Time'') As wipTimeTargetVal,
(select Top 1 jk.kpi_target_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Total Final Invoice Time'') As TotalFinalInvoiceTimeTargetVal,
(select Top 1 jk.kpi_target_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Days to Start'') As daysToStartTargetVal,
(select Top 1 jk.kpi_target_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Estimate Bid Time'') As estimateBidTimeTargetVal,
(select Top 1 jk.kpi_target_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Final Estimate Upload Time'') As finalEstimateUploadTimeTargetVal,
(select Top 1 jk.kpi_target_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Onsite Arrival Time'') As onsiteArrivalTimeTargetVal,
(select Top 1 jk.kpi_target_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Target Completion Accuracy'') As targetCompletionTargetVal,
(select Top 1 jk.kpi_target_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Contact Customer Time'') As contactCustomerTimeTargetVal,
(select Top 1 jk.kpi_target_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Days to Sign'') As daysToSignTargetVal,
(select Top 1 jk.kpi_target_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Final Invoice Delay Time'') As finalInvoiceDelayTimeTargetVal,
(select Top 1 jk.kpi_target_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Gross Profit %'') As grossProfitTargetVal,
(select Top 1 jk.kpi_target_value from '+QUOTENAME(@Tenant)+'.'+'job_kpi_details jk  where jk.job_id=j.job_id and jk.kpi_name=''Labor Efficiency Ratio'') As LaborEfficiencyRationTargetVal,
'
END


BEGIN
SET @SQL=@SQL+'m.dateofLoss AS dateofLoss,m.dateReceived AS dateReceived,m.datecontacted AS datecontacted,
m.dateinspected AS dateinspected,m.dateofWorkAuthorization AS dateofWorkAuthorization,m.dateEstimatesent AS dateEstimatesent,
m.dateEstimateApproved AS dateEstimateApproved,m.dateinventoried AS dateinventoried,m.intoProductiondate AS intoProductiondate,
m.target_start_date AS targetStartDate,m.startdate AS startdate,m.dateofmajoritycompletion AS dateofmajoritycompletion,
m.targetcompletiondate AS targetcompletiondate,m.dateOfcOs AS dateOfcOs,m.dateinvoiced AS dateinvoiced,m.final_invoice_date AS finalInvoiceDate,
m.datePaid AS datePaid,m.closeddate AS closeddate,
j.created_datetime AS createdDatetime,j.dash_file_created_date AS fileDate,
j.referred_source as referredSoure,j.tpa_name as tpa,
case when (select count(*) from '+QUOTENAME(@Tenant)+'.'+'job_estimate e where e.job_id=j.job_id)>0 then ''Yes'' else ''No'' end as estimate,
(select sum(e.estimated_amount) from '+QUOTENAME(@Tenant)+'.'+'job_estimate e where e.job_id=j.job_id) as TotalEstimateAmount,
(select sum(f.doc_amt) from '+QUOTENAME(@Tenant)+'.'+'file_invoice f where f.file_number=j.job_code and f.doc_type=''Invoice'') as TotalInvoice,
((select sum(c.doc_amt) from '+QUOTENAME(@Tenant)+'.'+'file_cost c where c.file_number=j.job_code and c.tran_type NOT IN(''Vendor Credits'',''Credit Card Credits'',''VendorCredits'',''CreditCardCredits'',''Vendor Credit'') and (c.status=''Active'' or c.status is null)) -
(select case when sum(c.doc_amt) is null then 0 else sum(c.doc_amt) end from '+QUOTENAME(@Tenant)+'.'+'file_cost c where c.file_number=j.job_code and c.tran_type IN(''Vendor Credits'',''Credit Card Credits'',''VendorCredits'',''CreditCardCredits'',''Vendor Credit'') and (c.status=''Active'' or c.status is null))) as totalVendorCost,
(select sum(l.total_cost) from '+QUOTENAME(@Tenant)+'.'+'user_payroll_details l where l.job_id=j.job_id and l.labor_type = ''Labor'' and  (l.status=''Active'' or l.status is null)) as jobCostLabor,
(select sum(l.total_cost) from '+QUOTENAME(@Tenant)+'.'+'user_payroll_details l where l.job_id=j.job_id and l.labor_type = ''Travel Time'' and  (l.status=''Active'' or l.status is null)) as jobCostTravel,
(select case when sum(l.total_cost) is null then 0 else sum(l.total_cost) end from '+QUOTENAME(@Tenant)+'.'+'user_payroll_details l where l.job_id=j.job_id and l.labor_type in (''Labor'',''Travel Time'') and  (l.status=''Active'' or l.status is null)) as TotalLabor,
(select sum(f.doc_amt) from '+QUOTENAME(@Tenant)+'.'+'file_invoice f where f.file_number=j.job_code and f.doc_type=''Payment'') as TotalCollected,
j.customer_type AS customerType,j.customer_company_name AS customerCompanyName,j.dash_file_number as referenceNumber,'''' as customerName,j.last_activity as lastActivity,
j.email as email,j.property_type as propertyType,
(select mc.config_value from '+QUOTENAME(@Tenant)+'.'+'m_config_data mc where mc.config_id=j.program_type and config_name=''Program Type'' and mc.status=''Active'') as programType,
(select mc.config_value from '+QUOTENAME(@Tenant)+'.'+'m_config_data mc where mc.config_id=j.cause_of_loss and config_name=''Cause of Loss'' and mc.status=''Active'') as causeOfLoss,
(select ic.insurance_company_name from '+QUOTENAME(@Tenant)+'.'+'job_insurance_details ic where ic.job_id=j.job_id ) as insuranceCompany,
(select ic.claim_number from '+QUOTENAME(@Tenant)+'.'+'job_insurance_details ic where ic.job_id=j.job_id ) as claimNumber,
j.nps_score as npsScore,j.referred_source as referredSource,
CASE
WHEN j.referred_type =''Organization'' THEN
(select e.external_agency_name from '+QUOTENAME(@Tenant)+'.'+'external_agency_details e where e.external_agency_id=j.referred_by)
WHEN j.referred_type =''People'' THEN
(select c.contact_first_name+'' ''+c.contact_last_name from '+QUOTENAME(@Tenant)+'.'+'contact_details c where c.contact_id=j.referred_by)
ELSE
j.referred_by
end
as referredBy,j.comment as comments,j.reason as reason,j.rough_estimate as roughEstimate,DATEDIFF(day, j.created_datetime, (SELECT GETDATE())) as fileAge,DATEDIFF(day, j.status_change_datetime, (SELECT GETDATE())) as ageInCurrentStatus,
(select m.status_category from '+QUOTENAME(@Tenant)+'.'+'m_status_configuration m where  m.additional_status = j.current_job_status and m.status=''Active'') as statusCategory'

END


BEGIN
SET @SQL=@SQL+' from '+QUOTENAME(@Tenant)+'.'+'job_details j left join '+QUOTENAME(@Tenant)+'.'+'common_milestones m on j.job_id = m.source_id
 where CONVERT(VARCHAR(8), j.created_datetime, 112)>CONVERT(VARCHAR(8), ''2019-01-01 00:00:00'', 112)';
 IF(@locationId>0)
 BEGIN
 SET @SQL = @SQL+' and j.rest_comp_location_id='+cast (@locationId as NVARCHAR(10));
 END
 SET @SQL = @SQL+' order by j.job_id desc';
END

EXEC (@SQL)
print  (@SQL)
GO

GO
-- =============================================
-- Stored Procedure: [dbo].[all_jobs_report_optimization]
-- Repeatable Migration - Re-runs when content changes
-- =============================================
CREATE OR ALTER PROCEDURE  [dbo].[all_jobs_report_optimization]
(@Tenant Varchar(255),@locationId INT)
As
DECLARE @SQL VARCHAR(MAX)
SET NOCOUNT ON;
SET @SQL=N';
select j.job_id AS jobId,j.job_code AS subJobCode,j.job_hash_code AS jobHashCode,j.job_type AS jobType,
j.first_name As firstName, j.last_name As lastName,j.loss_address AS lossAddress,j.loss_address_city AS city,
j.loss_address_state AS state,j.loss_address_zip AS zip,j.rest_comp_location_id as locationId,j.current_job_status as status,
(select m.company from '+QUOTENAME(@Tenant)+'.'+'mast_num_details m where m.mast_num_id=j.mast_num_id) as company,
(select m.mast_num_code from '+QUOTENAME(@Tenant)+'.'+'mast_num_details m where m.mast_num_id=j.mast_num_id) as mastNumCode,
j.mobile AS mobile,j.work_phone AS workPhone,j.phone1 AS phone1,
(select u.first_name+'' ''+u.last_name from '+QUOTENAME(@Tenant)+'.'+'user_user_details u Inner Join '+QUOTENAME(@Tenant)+'.'+'job_roles jr 
on u.user_id=jr.user_id and jr.job_id=j.job_id and jr.role_name=''Supervisor'' and jr.job_role_status=''Active'') As supervisor,
(select u.first_name+'' ''+u.last_name from '+QUOTENAME(@Tenant)+'.'+'user_user_details u Inner Join '+QUOTENAME(@Tenant)+'.'+'job_roles jr 
on u.user_id=jr.user_id and jr.job_id=j.job_id and jr.role_name=''Estimator'' and jr.job_role_status=''Active'') As estimator,
(select u.first_name+'' ''+u.last_name from '+QUOTENAME(@Tenant)+'.'+'user_user_details u Inner Join '+QUOTENAME(@Tenant)+'.'+'job_roles jr 
on u.user_id=jr.user_id and jr.job_id=j.job_id and jr.role_name=''Sales Representative'' and jr.job_role_status=''Active'') As salesRepresentative,
(select u.first_name+'' ''+u.last_name from '+QUOTENAME(@Tenant)+'.'+'user_user_details u Inner Join '+QUOTENAME(@Tenant)+'.'+'job_roles jr 
on u.user_id=jr.user_id and jr.job_id=j.job_id and jr.role_name=''Coordinator'' and jr.job_role_status=''Active'') As coordinator,
(select u.first_name+'' ''+u.last_name from '+QUOTENAME(@Tenant)+'.'+'user_user_details u Inner Join '+QUOTENAME(@Tenant)+'.'+'job_roles jr 
on u.user_id=jr.user_id and jr.job_id=j.job_id and jr.role_name=''Finance'' and jr.job_role_status=''Active'') As finance,
(select u.first_name+'' ''+u.last_name from '+QUOTENAME(@Tenant)+'.'+'user_user_details u Inner Join '+QUOTENAME(@Tenant)+'.'+'job_roles jr 
on u.user_id=jr.user_id and jr.job_id=j.job_id and jr.role_name=''Administrator'' and jr.job_role_status=''Active'') As administrator,
(select u.first_name+'' ''+u.last_name from '+QUOTENAME(@Tenant)+'.'+'user_user_details u Inner Join '+QUOTENAME(@Tenant)+'.'+'job_roles jr 
on u.user_id=jr.user_id and jr.job_id=j.job_id and jr.role_name=''Role'' and jr.job_role_status=''Active'') As Role,'

/** Contact Details ****/
BEGIN
SET @SQL=@SQL+'(select cd.contact_first_name+'' ''+cd.contact_last_name from '+QUOTENAME(@Tenant)+'.'+'contact_details cd where cd.contact_id=(select Top 1jc.contact_id from '+QUOTENAME(@Tenant)+'.'+'job_contacts jc 
where jc.job_id=j.job_id and jc.contact_work_type=''Adjuster'' and jc.status=''Active'' and contact_category=''Common'')) As adjuster,
(select cd.contact_first_name+'' ''+cd.contact_last_name from '+QUOTENAME(@Tenant)+'.'+'contact_details cd where cd.contact_id=(select Top 1 jc.contact_id from '+QUOTENAME(@Tenant)+'.'+'job_contacts jc 
where jc.job_id=j.job_id and jc.contact_work_type=''Insurance Agent'' and jc.status=''Active'' and contact_category=''Common'')) As insuranceAgent,
(select cd.contact_first_name+'' ''+cd.contact_last_name from '+QUOTENAME(@Tenant)+'.'+'contact_details cd where cd.contact_id=(select Top 1 jc.contact_id from '+QUOTENAME(@Tenant)+'.'+'job_contacts jc 
where jc.job_id=j.job_id and jc.contact_work_type=''Property Manager'' and jc.status=''Active'' and contact_category=''Common'')) As propertyManager,
(select cd.contact_first_name+'' ''+cd.contact_last_name from '+QUOTENAME(@Tenant)+'.'+'contact_details cd where cd.contact_id=(select Top 1 jc.contact_id from '+QUOTENAME(@Tenant)+'.'+'job_contacts jc 
where jc.job_id=j.job_id and jc.contact_work_type=''Public Adjuster'' and jc.status=''Active'' and contact_category=''Common'')) As publicAdjuster,
(select cd.contact_first_name+'' ''+cd.contact_last_name from '+QUOTENAME(@Tenant)+'.'+'contact_details cd where cd.contact_id=(select Top 1 jc.contact_id from '+QUOTENAME(@Tenant)+'.'+'job_contacts jc 
where jc.job_id=j.job_id and jc.contact_work_type=''Independent Adjuster'' and jc.status=''Active'' and contact_category=''Common'')) As independentAdjuster,'
END

/**BEGIN
SET @SQL=@SQL+'(select cd.contact_first_name+'' ''+cd.contact_last_name from '+QUOTENAME(@Tenant)+'.'+'contact_details cd where cd.contact_id=(select jc.contact_id from '+QUOTENAME(@Tenant)+'.'+'job_contacts jc 
where jc.job_id=j.job_id and jc.contact_work_type=''Adjuster'' and jc.status=''Active'')) As contactAdjuster,
(select cd.contact_first_name+'' ''+cd.contact_last_name from '+QUOTENAME(@Tenant)+'.'+'contact_details cd where cd.contact_id=(select jc.contact_id from '+QUOTENAME(@Tenant)+'.'+'job_contacts jc 
where jc.job_id=j.job_id and jc.contact_work_type=''Insurance Agent'' and jc.status=''Active'')) As contactInsuranceAgent,
(select cd.contact_first_name+'' ''+cd.contact_last_name from '+QUOTENAME(@Tenant)+'.'+'contact_details cd where cd.contact_id=(select jc.contact_id from '+QUOTENAME(@Tenant)+'.'+'job_contacts jc 
where jc.job_id=j.job_id and jc.contact_work_type=''Property Manager'' and jc.status=''Active'')) As contactPropertyManager,
(select cd.contact_first_name+'' ''+cd.contact_last_name from '+QUOTENAME(@Tenant)+'.'+'contact_details cd where cd.contact_id=(select jc.contact_id from '+QUOTENAME(@Tenant)+'.'+'job_contacts jc 
where jc.job_id=j.job_id and jc.contact_work_type=''Referred By'' and jc.status=''Active'')) As contactReferredBy,
(select cd.contact_first_name+'' ''+cd.contact_last_name from '+QUOTENAME(@Tenant)+'.'+'contact_details cd where cd.contact_id=(select jc.contact_id from '+QUOTENAME(@Tenant)+'.'+'job_contacts jc 
where jc.job_id=j.job_id and jc.contact_work_type=''Sales Representative'' and jc.status=''Active'')) As contactSaleRepresentative,
(select cd.contact_first_name+'' ''+cd.contact_last_name from '+QUOTENAME(@Tenant)+'.'+'contact_details cd where cd.contact_id=(select jc.contact_id from '+QUOTENAME(@Tenant)+'.'+'job_contacts jc 
where jc.job_id=j.job_id and jc.contact_work_type=''Third Party Administrator'' and jc.status=''Active'')) As contactThirdPartyAdministrator,'
END******/

