(select sum(l.total_cost) from '+QUOTENAME(@Tenant)+'.'+'user_payroll_details l where l.job_id=j.job_id and l.labor_type in (''Labor'',''Travel Time'') and (l.status=''Active'' or l.status is null)) as TotalLabor,
(select sum(f.doc_amt) from '+QUOTENAME(@Tenant)+'.'+'file_invoice f where f.file_number=j.job_code and f.doc_type IN(''Payment'',''Payments'')) as TotalCollected,
j.customer_type AS customerType,j.customer_company_name AS customerCompanyName,j.dash_file_number as referenceNumber,'''' as customerName,j.last_activity as lastActivity,
j.email as email,j.property_type as propertyType,
(select mc.config_value from '+QUOTENAME(@Tenant)+'.'+'m_config_data mc where mc.config_id=j.program_type and config_name=''Program Type'' and mc.status=''Active'') as programType,
(select mc.config_value from '+QUOTENAME(@Tenant)+'.'+'m_config_data mc where mc.config_id=j.cause_of_loss and config_name=''Cause of Loss'' and mc.status=''Active'') as causeOfLoss,
(select ic.insurance_company_name from '+QUOTENAME(@Tenant)+'.'+'job_insurance_details ic where ic.job_id=j.job_id ) as insuranceCompany,
(select ic.claim_number from '+QUOTENAME(@Tenant)+'.'+'job_insurance_details ic where ic.job_id=j.job_id ) as claimNumber,
j.nps_score as npsScore,
j.referred_source as referredSource,
CASE
WHEN j.referred_type =''Organization'' THEN
(select e.external_agency_name from '+QUOTENAME(@Tenant)+'.'+'external_agency_details e where e.external_agency_id=j.referred_by) 
WHEN j.referred_type =''People'' THEN
(select c.contact_first_name+'' ''+c.contact_last_name from '+QUOTENAME(@Tenant)+'.'+'contact_details c where c.contact_id=j.referred_by)
ELSE
j.referred_by
end
as referredBy,j.comment as comments,j.reason as reason,j.job_name as jobName,
(select m.status_category from '+QUOTENAME(@Tenant)+'.'+'m_status_configuration m where  m.additional_status = j.current_job_status and m.status=''Active'') as statusCategory'
END

BEGIN
SET @SQL=@SQL+' from '+QUOTENAME(@Tenant)+'.'+'job_details j left join '+QUOTENAME(@Tenant)+'.'+'common_milestones m on j.job_id = m.source_id
 where 
  CONVERT(VARCHAR(8), j.created_datetime, 112)>CONVERT(VARCHAR(8), ''2017-01-01 00:00:00'', 112) order by j.job_id desc';
END

IF(@locationId>0)
 BEGIN
 SET @SQL = @SQL+' and j.rest_comp_location_id='+cast (@locationId as NVARCHAR(10));
 END

EXEC (@SQL)
print  (@SQL)
GO

GO
-- =============================================
-- Stored Procedure: [dbo].[closed_jobs_mobile]
-- Repeatable Migration - Re-runs when content changes
-- =============================================
CREATE OR ALTER PROCEDURE  [dbo].[closed_jobs_mobile]
(@Tenant Varchar(255),@locationId INT,@search Varchar(255))
As

DECLARE @SQL VARCHAR(MAX)
SET @SQL=N';

select 

j.job_id AS jobId,j.job_code AS subJobCode,j.job_hash_code AS jobHashCode,j.job_type AS jobType,
case when (j.customer_type is not null and (j.customer_type = ''Customer Organization'' or j.customer_type = ''Customer Company''))
then j.customer_company_name when (j.first_name is null and j.last_name is null) then 
(select m.company from [tenant1].mast_num_details m where m.mast_num_id=j.mast_num_id)
else concat(j.first_name,'' '',j.last_name) end as customerName,
j.first_name As firstName, j.last_name As lastName,j.loss_address AS lossAddress,j.loss_address_city AS city,
j.loss_address_state AS state,j.loss_address_zip AS zip,j.current_job_status as status,
case when j.mobile is not null then j.mobile when j.work_phone is not null then j.work_phone else j.phone1 end as phoneNo,
(select m.company from '+QUOTENAME(@Tenant)+'.'+'mast_num_details m where m.mast_num_id=j.mast_num_id) as company,

(select u.first_name+'' ''+u.last_name from '+QUOTENAME(@Tenant)+'.'+'user_user_details u where u.user_id=(select jr.user_id from '+QUOTENAME(@Tenant)+'.'+'job_roles jr 
where jr.job_id=j.job_id and jr.role_name=''Supervisor'')) As supervisor,
(select u.first_name+'' ''+u.last_name from '+QUOTENAME(@Tenant)+'.'+'user_user_details u where u.user_id=(select jr.user_id from '+QUOTENAME(@Tenant)+'.'+'job_roles jr 
where jr.job_id=j.job_id and jr.role_name=''Estimator'')) As estimator,

 case when j.dash_file_created_date is null then j.created_datetime else j.created_datetime end as fileDate,
 
j.created_datetime AS createdDatetime,
case when (select count(*) from '+QUOTENAME(@Tenant)+'.'+'job_estimate e where e.job_id=j.job_id)>0 then ''Yes'' else ''No'' end as estimate,
case when (select count(*) from '+QUOTENAME(@Tenant)+'.'+'job_estimate e where e.job_id=j.job_id)>0 then (select sum(e.estimated_amount) from '+QUOTENAME(@Tenant)+'.'+'job_estimate e where e.job_id=j.job_id) else 0 end as estimatedAmount,
j.customer_type as customerType,j.customer_company_name as customerCompanyName,j.dash_file_number as referenceNumber

 from '+QUOTENAME(@Tenant)+'.'+'job_details j where j.current_job_status IN (''Closed'',''Rejected'') '

IF(@locationId != 0) 
BEGIN
SET @SQL=@SQL+'and j.rest_comp_location_id='+ cast (@locationId as NVARCHAR(10))+' ';
END


BEGIN
SET @SQL=@SQL+' and (REPLACE(REPLACE(j.job_code, ''FN'', ''''),''_'','' '') like ''%'+@search+'%'' or concat(j.first_Name,'' '',j.last_Name) like ''%'+@search+'%'' )  order by j.created_datetime desc';
END

EXEC (@SQL)
print  (@SQL)
GO

