-- ===================================================
-- XCEL-6474: Stored Procedure for Corporate Override of Tenant File Type Status
-- ===================================================
-- Author: XCEL-6474 Implementation Team
-- Date: 2026-04-08
-- Description: Allows corporate backend to update a specific file type's status in any
--              tenant schema. Used when allow_corporate_file_type_override is enabled.
-- Migration Type: REPEATABLE - Flyway re-runs on checksum change
-- ===================================================

IF OBJECT_ID('[dbo].[configure_tenant_file_type_status]', 'P') IS NOT NULL
    DROP PROCEDURE [dbo].[configure_tenant_file_type_status];
GO

CREATE PROCEDURE [dbo].[configure_tenant_file_type_status]
    @Tenant         SYSNAME,          -- SYSNAME = NVARCHAR(128); QUOTENAME silently returns NULL for longer identifiers
    @Host           SYSNAME,          -- Caller-supplied host schema; avoids non-deterministic TOP 1 lookup
    @FileTypeId     INT,
    @FileTypeStatus NVARCHAR(50),   -- 'Active' or 'In-Active' — set directly on [tenant].[file_types].status
    @UpdatedBy      INT = NULL
AS
BEGIN
    SET NOCOUNT ON;

    IF @UpdatedBy IS NULL OR @UpdatedBy = 0
        THROW 50000, '@UpdatedBy must be a valid user id', 1;
    DECLARE @SQL          NVARCHAR(MAX);
    DECLARE @FileTypeName NVARCHAR(255);

    -- Only update assigned_file_type when turning OFF (dispatch must stop immediately).
    -- When turning ON, leave assigned_file_type as-is — corporate re-activates dispatch
    -- via the Activate button in the Division Types grid.

    -- Cross-tenant communication pattern: Xcelerate uses a database-per-schema multi-tenancy model.
    -- JPA cannot reach across schema boundaries, so all cross-tenant DML must go through this SP
    -- using dynamic SQL with QUOTENAME(@schema) to safely build the target table reference.
    -- The transaction below ensures both the tenant file_types update and the host assigned_file_type
    -- kill are atomic — partial state (file type disabled but dispatch still active) is rolled back.

    -- Look up the file type name from the tenant's file_types table (outside transaction — read-only)
    SET @SQL = N'SELECT @FTName = [file_type] FROM ' + QUOTENAME(@Tenant) + N'.[file_types] WHERE [file_type_id] = @FileTypeIdParam';
    EXEC sp_executesql @SQL,
        N'@FTName NVARCHAR(255) OUTPUT, @FileTypeIdParam INT',
        @FTName = @FileTypeName OUTPUT,
        @FileTypeIdParam = @FileTypeId;

    SET XACT_ABORT ON;
    BEGIN TRY
        BEGIN TRAN;

        -- Update the contractor tenant's file_types status
        SET @SQL = N'UPDATE ' + QUOTENAME(@Tenant) + N'.[file_types] SET [status] = @FileTypeStatusParam WHERE [file_type_id] = @FileTypeIdParam';
        EXEC sp_executesql @SQL,
            N'@FileTypeStatusParam NVARCHAR(50), @FileTypeIdParam INT',
            @FileTypeStatusParam = @FileTypeStatus,
            @FileTypeIdParam     = @FileTypeId;

        -- Only kill dispatch when turning OFF — set assigned_file_type to Deleted
        IF @FileTypeStatus != 'Active' AND @Host IS NOT NULL AND @FileTypeName IS NOT NULL
        BEGIN
            SET @SQL = N'UPDATE ' + QUOTENAME(@Host) + N'.[assigned_file_type]'
                + N' SET [assignment_status] = ''Deleted'', [status] = ''Deleted'','
                + N'     [updated_by] = @UpdatedByParam, [updated_datetime] = GETDATE()'
                + N' WHERE [contractor] = @TenantParam AND [file_type] = @FileTypeNameParam';
            EXEC sp_executesql @SQL,
                N'@TenantParam NVARCHAR(255), @FileTypeNameParam NVARCHAR(255), @UpdatedByParam INT',
                @TenantParam       = @Tenant,
                @FileTypeNameParam = @FileTypeName,
                @UpdatedByParam    = @UpdatedBy;
        END

        COMMIT;
    END TRY
    BEGIN CATCH
        IF @@TRANCOUNT > 0 ROLLBACK;
        THROW;
    END CATCH
END
GO

PRINT 'R__SP_configure_tenant_file_type_status: configure_tenant_file_type_status procedure created/updated';
GO

GO
