-- =============================================
-- Stored Procedure: [dbo].[job_list_pagination]
-- Repeatable Migration - Re-runs when content changes
-- =============================================
CREATE OR ALTER PROCEDURE [dbo].[job_list_pagination]
(
    @Tenant VARCHAR(255),
    @locationId INT,
    @listType VARCHAR(50),
    @startIndex INT,
    @endIndex INT,
    @userId INT,
    @lastSyncDate VARCHAR(23)
)
AS
BEGIN
    DECLARE @SQL NVARCHAR(MAX)
    SET @SQL = N'
    SELECT *
    FROM (
        SELECT
            j.job_id AS jobId,
            j.job_code AS subJobCode,
            j.job_hash_code AS jobHashCode,
            j.job_type AS jobType,
            j.first_name AS firstName,
            j.last_name AS lastName,
            j.loss_address AS lossAddress,
            j.loss_address_city AS city,
            j.loss_address_state AS state,
            j.loss_address_zip AS zip,
            j.rest_comp_location_id AS locationId,
            j.current_job_status AS status,
            (SELECT m.company FROM ' + QUOTENAME(@Tenant) + '.mast_num_details m WHERE m.mast_num_id = j.mast_num_id) AS company,
            j.mobile AS mobile,
            j.work_phone AS workPhone,
            j.phone1 AS phone1,
            (SELECT u.first_name + '' '' + u.last_name FROM ' + QUOTENAME(@Tenant) + '.user_user_details u WHERE u.user_id = (SELECT jr.user_id FROM ' + QUOTENAME(@Tenant) + '.job_roles jr 
            WHERE jr.job_id = j.job_id AND jr.role_name = ''Supervisor'')) AS supervisor,
            (SELECT u.first_name + '' '' + u.last_name FROM ' + QUOTENAME(@Tenant) + '.user_user_details u WHERE u.user_id = (SELECT jr.user_id FROM ' + QUOTENAME(@Tenant) + '.job_roles jr 
            WHERE jr.job_id = j.job_id AND jr.role_name = ''Estimator'')) AS estimator,
            j.created_datetime AS createdDatetime,
            j.dash_file_created_date AS fileDate,
            CASE WHEN (SELECT COUNT(*) FROM ' + QUOTENAME(@Tenant) + '.job_estimate e WHERE e.job_id = j.job_id) > 0 THEN ''Yes'' ELSE ''No'' END AS estimate,
            CASE WHEN (SELECT COUNT(*) FROM ' + QUOTENAME(@Tenant) + '.job_estimate e WHERE e.job_id = j.job_id) > 0 THEN (SELECT SUM(e.estimated_amount) FROM ' + QUOTENAME(@Tenant) + '.job_estimate e WHERE e.job_id = j.job_id) ELSE 0 END AS estimatedAmount,
            j.customer_type AS customerType,
            j.customer_company_name AS customerCompanyName,
            j.dash_file_number AS referenceNumber,
            j.mast_num_id AS mastNumId,
            j.email AS email,
            j.job_name AS jobName,
            j.unit_number AS unitNumber,
            j.loss_address_lat AS lossAddressLat,
            j.loss_address_lan AS lossAddressLan,
			(select ic.claim_number from '+QUOTENAME(@Tenant)+'.'+'job_insurance_details ic where ic.job_id=j.job_id ) as claimNumber,
			(select ic.policy_number from '+QUOTENAME(@Tenant)+'.'+'job_insurance_details ic where ic.job_id=j.job_id ) as policyNumber,
			(select ic.deductible from '+QUOTENAME(@Tenant)+'.'+'job_insurance_details ic where ic.job_id=j.job_id ) as deductible,
			(select ic.deductible_amount from '+QUOTENAME(@Tenant)+'.'+'job_insurance_details ic where ic.job_id=j.job_id ) as deductibleAmount,
			(select ic.deductible_comments from '+QUOTENAME(@Tenant)+'.'+'job_insurance_details ic where ic.job_id=j.job_id ) as deductibleComments,
			(select u.first_name+'' ''+u.last_name from '+QUOTENAME(@Tenant)+'.'+'user_user_details u where u.user_id=(select jr.user_id from '+QUOTENAME(@Tenant)+'.'+'job_roles jr 
			where jr.job_id=j.job_id and jr.role_name=''Coordinator'' and jr.job_role_status=''Active'')) As coordinator,
			(select ic.insurance_company_name from '+QUOTENAME(@Tenant)+'.'+'job_insurance_details ic where ic.job_id=j.job_id ) as insuranceCompany,
			(select u.first_name+'' ''+u.last_name from '+QUOTENAME(@Tenant)+'.'+'user_user_details u where u.user_id=(select jr.user_id from '+QUOTENAME(@Tenant)+'.'+'job_roles jr 
			where jr.job_id=j.job_id and jr.role_name=''Lead Technician'' and jr.job_role_status=''Active'')) As leadTechnician,
			j.total_estimates AS totalEstimates,

            (SELECT location_city FROM ' + QUOTENAME(@Tenant) + '.rest_comp_location WHERE rest_comp_location_id = j.rest_comp_location_id) AS locationName,
            ROW_NUMBER() OVER (ORDER BY j.created_datetime DESC) AS RowNum
        FROM ' + QUOTENAME(@Tenant) + '.job_details j  left join '+QUOTENAME(@Tenant)+'.'+'common_milestones m on j.job_id = m.source_id  
        WHERE 
		j.created_datetime> ''2019-01-01 00:00:00'' 
		and j.current_job_status!=''Deleted'' 
		AND j.job_id IN (SELECT jr.job_Id FROM ' + QUOTENAME(@Tenant) + '.[job_roles] jr WHERE jr.user_id = ' + CAST(@userId AS NVARCHAR(10)) + ')
        AND j.current_job_status NOT IN (''Closed'',''Rejected'')
		';
IF(@locationId != 0) 
BEGIN
SET @SQL=@SQL+'and j.rest_comp_location_id='+ cast (@locationId as NVARCHAR(10))+' ';
END
IF(@listType = 'partial')
BEGIN
SET @SQL= @SQL+' and (j.created_datetime >='''+ @lastSyncDate+''' or j.updated_datetime >= '''+ @lastSyncDate+''')';
END


    SET @SQL = @SQL + '
      ) AS T
    WHERE RowNum >= ' + CAST(@startIndex AS NVARCHAR(10)) + ' AND RowNum <= ' + CAST((@startIndex + @endIndex - 1) AS NVARCHAR(10)) + 'order by createdDatetime desc;'

    EXEC (@SQL); 
    PRINT(@SQL);
END
GO

GO
-- =============================================
-- Stored Procedure: [dbo].[job_list_procedure_java21]
-- Repeatable Migration - Re-runs when content changes
-- =============================================
CREATE OR ALTER PROCEDURE  [dbo].[job_list_procedure_java21]
(@Tenant Varchar(255),@locationId INT,@listType Varchar(50),@userId INT)
As

DECLARE @SQL VARCHAR(MAX)
SET @SQL=N';

select j.job_id AS jobId,j.job_code AS subJobCode,j.job_hash_code AS jobHashCode,j.job_type AS jobType,
j.first_name As firstName, j.last_name As lastName,j.loss_address AS lossAddress,j.loss_address_city AS city,
j.loss_address_state AS state,j.loss_address_zip AS zip,j.rest_comp_location_id as locationId,j.current_job_status as status,
(select m.company from '+QUOTENAME(@Tenant)+'.'+'mast_num_details m where m.mast_num_id=j.mast_num_id) as company,
j.mobile AS mobile,j.work_phone AS workPhone,j.phone1 AS phone1,
(select u.first_name+'' ''+u.last_name from '+QUOTENAME(@Tenant)+'.'+'user_user_details u where u.user_id=(select jr.user_id from '+QUOTENAME(@Tenant)+'.'+'job_roles jr
where jr.job_id=j.job_id and jr.role_name=''Supervisor'')) As supervisor,
(select u.first_name+'' ''+u.last_name from '+QUOTENAME(@Tenant)+'.'+'user_user_details u where u.user_id=(select jr.user_id from '+QUOTENAME(@Tenant)+'.'+'job_roles jr
where jr.job_id=j.job_id and jr.role_name=''Estimator'')) As estimator,j.created_datetime AS createdDatetime,j.dash_file_created_date AS fileDate,
case when (select count(*) from '+QUOTENAME(@Tenant)+'.'+'job_estimate e where e.job_id=j.job_id)>0 then ''Yes'' else ''No'' end as estimate,
case when (select count(*) from '+QUOTENAME(@Tenant)+'.'+'job_estimate e where e.job_id=j.job_id)>0 then (select sum(e.estimated_amount) from '+QUOTENAME(@Tenant)+'.'+'job_estimate e where e.job_id=j.job_id) else 0 end as estimatedAmount,
j.customer_type AS customerType,j.customer_company_name AS customerCompanyName,j.dash_file_number as referenceNumber,j.mast_num_id AS mastNumId,j.email AS email,j.job_name AS jobName,j.unit_number as unitNumber,j.loss_address_lat As lossAddressLat,j.loss_address_lan AS lossAddressLan,
(select location_city from '+QUOTENAME(@Tenant)+'.'+'rest_comp_location where rest_comp_location_id=j.rest_comp_location_id) AS locationName
 from '+QUOTENAME(@Tenant)+'.'+'job_details j where j.created_datetime> ''2017-01-01 00:00:00'' '
IF(@locationId != 0)
BEGIN
SET @SQL=@SQL+'and j.rest_comp_location_id='+ cast (@locationId as NVARCHAR(10))+' ';
END

IF(@listType = 'My')

BEGIN
SET @SQL=@SQL+' and j.job_id in(select jr.job_Id from '+QUOTENAME(@Tenant)+'.'+'[job_roles] jr where jr.user_id='+ cast (@userId as NVARCHAR(10))+') and j.current_job_status NOT IN(''Closed'',''Rejected'') order by j.created_datetime desc';
END

ELSE IF(@listType = 'Active')
BEGIN

SET @SQL=@SQL+' and j.current_job_status NOT IN (''Closed'',''Rejected'') order by j.created_datetime desc ';

