where jr.job_id=j.job_id and jr.role_name=''Coordinator'')) As coordinator,

(select u.first_name+'' ''+u.last_name from '+QUOTENAME(@Tenant)+'.'+'user_user_details u where u.user_id=(select Top 1 jr.user_id from '+QUOTENAME(@Tenant)+'.'+'job_roles jr 

where jr.job_id=j.job_id and jr.role_name=''Finance'')) As finance,

(select u.first_name+'' ''+u.last_name from '+QUOTENAME(@Tenant)+'.'+'user_user_details u where u.user_id=(select Top 1 jr.user_id from '+QUOTENAME(@Tenant)+'.'+'job_roles jr 

where jr.job_id=j.job_id and jr.role_name=''Administrator'')) As administrator,

(select u.first_name+'' ''+u.last_name from '+QUOTENAME(@Tenant)+'.'+'user_user_details u where u.user_id=(select Top 1 jr.user_id from '+QUOTENAME(@Tenant)+'.'+'job_roles jr 

where jr.job_id=j.job_id and jr.role_name=''Role'')) As Role,

(select u.first_name+'' ''+u.last_name from '+QUOTENAME(@Tenant)+'.'+'user_user_details u where u.user_id=(select Top 1 jr.user_id from '+QUOTENAME(@Tenant)+'.'+'job_roles jr 

where jr.job_id=j.job_id and jr.role_name=''Lead Technician'')) As leadTechnician,

m.dateofLoss AS dateofLoss,m.dateReceived AS dateReceived,m.datecontacted AS datecontacted,

m.dateinspected AS dateinspected,m.dateofWorkAuthorization AS dateofWorkAuthorization,m.dateEstimatesent AS dateEstimatesent,

m.dateEstimateApproved AS dateEstimateApproved,m.dateinventoried AS dateinventoried,m.intoProductiondate AS intoProductiondate,

m.target_start_date AS targetStartDate,m.startdate AS startdate,m.dateofmajoritycompletion AS dateofmajoritycompletion,

m.targetcompletiondate AS targetcompletiondate,m.dateOfcOs AS dateOfcOs,m.dateinvoiced AS dateinvoiced,m.final_invoice_date AS finalInvoiceDate,

m.datePaid AS datePaid,m.closeddate AS closeddate,

j.referred_source as referredSoure,j.tpa_name as tpa,';

SET @SQL=@SQL+'

(select ic.insurance_company_name from '+QUOTENAME(@Tenant)+'.'+'job_insurance_details ic where ic.job_id=j.job_id ) as insuranceCompany,

(select Top 1 m.matterport_id from '+QUOTENAME(@Tenant)+'.'+'matterport_details m where m.job_id=j.job_id order by m.matterport_id desc ) as matterport,

j.created_datetime AS createdDatetime,j.dash_file_created_date AS fileDate,

case when (select count(*) from '+QUOTENAME(@Tenant)+'.'+'job_estimate e where e.job_id=j.job_id and e.status=''Active'')>0 then ''Yes'' else ''No'' end as estimate,

case when (select count(*) from '+QUOTENAME(@Tenant)+'.'+'job_estimate e where e.job_id=j.job_id and e.status=''Active'')>0 then (select sum(e.estimated_amount) from '+QUOTENAME(@Tenant)+'.'+'job_estimate e where e.job_id=j.job_id and e.status=''Active'') else 0 end as estimatedAmount,

j.customer_type AS customerType,j.customer_company_name AS customerCompanyName,j.dash_file_number as referenceNumber,'''' as customerName,j.last_activity as lastActivity,j.encircle_claim_id as encircleClaimId,j.email as email,

(select i.claim_number from '+QUOTENAME(@Tenant)+'.'+'job_insurance_details i where i.job_id=j.job_id ) as claimNumber';

SET @SQL=@SQL+',j.scratchpad as scratchpad,j.scratchpad_date as scratchpadDate,j.nps_score as npsScore,j.job_name as jobName,j.unit_number as unitNumber,

case when (select count(*) from '+QUOTENAME(@Tenant)+'.'+'job_insurance_details i where i.job_id=j.job_id)>0 then ''No'' else ''Yes'' end as selfPay,

CASE

WHEN j.referred_type =''Organization'' THEN

(select e.external_agency_name from '+QUOTENAME(@Tenant)+'.'+'external_agency_details e where e.external_agency_id=j.referred_by) 

WHEN j.referred_type =''People'' THEN

(select c.contact_first_name+'' ''+c.contact_last_name from '+QUOTENAME(@Tenant)+'.'+'contact_details c where c.contact_id=j.referred_by)

ELSE

j.referred_by

end

as referredBy,

((Case when j.total_cost is null then 0 else j.total_cost end)-(Case when j.total_credits is null then 0 else j.total_credits end)) as totalVendorCost,

(select case when sum(l.total_cost) is null then 0 else sum(l.total_cost) end  from '+QUOTENAME(@Tenant)+'.'+'user_payroll_details l where l.job_id=j.job_id and l.labor_type IN(''Labor'',''Travel Time'') and  (l.status=''Active'' or l.status is null)) as laborCost,

j.total_invoice as TotalInvoice,j.total_payment as TotalCollected,j.rough_estimate as roughEstimate,

(select Top 1 d.docusketch_id from '+QUOTENAME(@Tenant)+'.'+'docusketch_details d where d.job_id=j.job_id order by d.docusketch_id desc ) as docusketchId,

DATEDIFF(day, j.created_datetime, (SELECT GETDATE())) as fileAge,DATEDIFF(day, j.status_change_datetime, (SELECT GETDATE())) as ageInCurrentStatus,

(select location_city from '+QUOTENAME(@Tenant)+'.'+'rest_comp_location where rest_comp_location_id=j.rest_comp_location_id) AS locationName,

j.budget_gp_percentage as budgetGpPercentage,j.budget_gp_amount as budgetGpAmount ,

(select m.company_cam_project_id from '+QUOTENAME(@Tenant)+'.'+'mast_num_details m where m.mast_num_id=j.mast_num_id) as companyCamProjectId, 

(select m.company_cam_project_link from '+QUOTENAME(@Tenant)+'.'+'mast_num_details m where m.mast_num_id=j.mast_num_id) as companyCamProjectLink,

j.workorders_count as workordersCount,

(select sc.status_order from '+QUOTENAME(@Tenant)+'.m_status_configuration sc WHERE sc.additional_status = j.current_job_status AND sc.status = ''Active'') AS statusOrder,

j.xact_status AS xactStatus

from '+QUOTENAME(@Tenant)+'.'+'job_details j left join '+QUOTENAME(@Tenant)+'.'+'common_milestones m on j.job_id = m.source_id  

where j.created_datetime> ''2019-01-01 00:00:00'' and j.current_job_status!=''Deleted'''

If(@locationIdList != '0')

BEGIN

SET @SQL=@SQL+' and j.rest_comp_location_id IN (' + @locationIdList + ')'

END

IF(@listType = 'My')
 
BEGIN 

SET @SQL=@SQL+' and j.job_id in(select jr.job_Id from '+QUOTENAME(@Tenant)+'.'+'[job_roles] jr where jr.user_id='+ cast (@userId as NVARCHAR(10))+') and j.current_job_status NOT IN(''Closed'',''Rejected'') order by j.created_datetime desc';

END
 
ELSE IF(@listType = 'Active')

BEGIN
 
SET @SQL=@SQL+' and j.current_job_status NOT IN (''Closed'',''Rejected'') order by j.created_datetime desc ';
 
END
 
ELSE

BEGIN

SET @SQL=@SQL+' order by j.created_datetime desc';

END
 
print  (@SQL)

EXEC (@SQL)


 
END
GO

