CREATE OR ALTER PROCEDURE  [dbo].[job_phone_lookup]
(@Tenant Varchar(255),@Phone Varchar(50))
As
BEGIN

SET NOCOUNT ON;

DECLARE @SQL VARCHAR(MAX)
SET @SQL=N';
select * from '+QUOTENAME(@Tenant)+'.'+'job_details j where j.current_job_status NOT IN(''Closed'',''Rejected'') and Right(dbo.RemoveSpecialChars(j.mobile),10)=Right(dbo.RemoveSpecialChars('''+@Phone+'''),10) or Right(dbo.RemoveSpecialChars(j.work_phone),10)=Right(dbo.RemoveSpecialChars('''+@Phone+'''),10)
or  Right(dbo.RemoveSpecialChars(j.phone1),10)=Right(dbo.RemoveSpecialChars('''+@Phone+'''),10)'
EXEC (@SQL)
END
