-- =============================================
-- Stored Procedure: [dbo].[master_list_summary]
-- Repeatable Migration - Re-runs when content changes
-- =============================================
CREATE OR ALTER PROCEDURE  [dbo].[master_list_summary]
(@Tenant Varchar(255),@locationId INT,@Type Varchar(50),@userId INT)
As

DECLARE @SQL VARCHAR(MAX)
SET @SQL=N';
select ROW_NUMBER() OVER (ORDER BY CAST(m.created_datetime AS DATE) desc) AS id,m.mast_num_id as mastNumId,m.master_name as mastName,m.mast_num_hash as mastNumHash,m.mast_num_code as mastNumCode,
j.job_id as jobId,j.job_hash_code as jobHash,j.job_code as jobCode,j.job_name as jobName,
m.first_name as firstName,m.last_name as lastName,m.email,m.mobile,m.work_phone as workPhone,m.phone1, m.customer_type as customerType,m.customer_company as customerCompany,
m.customer_company_name as customerCompanyName,m.loss_date as masterJobReceivedDate,m.loss_address as address,
m.loss_address_city as city,m.loss_address_state as state,m.loss_address_zip as zip,m.company as company,
m.created_datetime as masterCreatedDate,j.loss_address as jobLossAddress,j.job_type as jobType,
j.created_datetime as jobCreatedDate,j.current_job_status as jobStatus,m.status as mastStatus,m.loss_date as lossDate,
(select u.first_name +'' ''+u.last_name  from '+QUOTENAME(@Tenant)+'.'+'user_user_details u where u.user_id=m.salesRepresentative) as mastSalesRep,
CASE
WHEN m.referred_type =''Organization'' THEN
(select e.external_agency_name from '+QUOTENAME(@Tenant)+'.'+'external_agency_details e where e.external_agency_id=m.referred_by) 
when m.referred_type =''People'' THEN
(select Top 1 c.contact_first_name+'' ''+c.contact_last_name from '+QUOTENAME(@Tenant)+'.'+'contact_details c where c.contact_id=m.referred_by)
ELSE
m.referred_by
end
as mastReferredBy,
(select u.first_name+'' ''+u.last_name from '+QUOTENAME(@Tenant)+'.'+'user_user_details u where u.user_id=(select Top 1 jr.user_id from '+QUOTENAME(@Tenant)+'.'+'job_roles jr 
where jr.job_id=j.job_id and jr.role_name=''Supervisor'')) As supervisor,
(select u.first_name+'' ''+u.last_name from '+QUOTENAME(@Tenant)+'.'+'user_user_details u where u.user_id=(select Top 1 jr.user_id from '+QUOTENAME(@Tenant)+'.'+'job_roles jr 
where jr.job_id=j.job_id and jr.role_name=''Estimator'')) As estimator,

(select u.first_name+'' ''+u.last_name from '+QUOTENAME(@Tenant)+'.'+'user_user_details u where u.user_id=(select Top 1 jr.user_id from '+QUOTENAME(@Tenant)+'.'+'job_roles jr 
where jr.job_id=j.job_id and jr.role_name=''Coordinator'')) As coordinator,
(SELECT TOP 1 m.final_invoice_date from '+QUOTENAME(@Tenant)+'.'+'common_milestones m where j.job_id = m.source_id order by m.entered_datetime desc) As finalInvoiceDate,
case when (select count(*) from '+QUOTENAME(@Tenant)+'.'+'job_estimate e where e.job_id=j.job_id)>0 then ''Yes'' else ''No'' end as estimate,
case when (select count(*) from '+QUOTENAME(@Tenant)+'.'+'job_estimate e where e.job_id=j.job_id)>0 then (select sum(e.estimated_amount) from '+QUOTENAME(@Tenant)+'.'+'job_estimate e where e.job_id=j.job_id) else 0 end as estimatedAmount
,j.loss_address_city as jobCity,j.loss_address_state as jobState,j.loss_address_zip as jobZip,j.customer_type AS jobCustomerType,j.customer_company_name AS jobCustomerCompanyName,j.company as jobCompany, 
 j.first_name As jobFirstName, j.last_name As jobLastName,j.unit_number as unitNumber,m.administrator as mastAdministrator,
 (select location_city from '+QUOTENAME(@Tenant)+'.'+'rest_comp_location where rest_comp_location_id=m.rest_comp_location_id ) AS locationName
from '+QUOTENAME(@Tenant)+'.'+'mast_num_details m
left join '+QUOTENAME(@Tenant)+'.'+'job_details j on j.mast_num_id=m.mast_num_id
 and CONVERT(VARCHAR(8), j.created_datetime, 112)>CONVERT(VARCHAR(8), ''2019-01-01 00:00:00'', 112)
where m.status!=''Deleted'' and CONVERT(VARCHAR(8), m.created_datetime, 112)>CONVERT(VARCHAR(8), ''2019-01-01 00:00:00'', 112)'

 
IF(@locationId != 0) 
BEGIN
SET @SQL=@SQL+'and m.rest_comp_location_id='+ cast (@locationId as NVARCHAR(10))+' ';
END


IF(@Type = 'myopen')

BEGIN 
SET @SQL=@SQL+'and m.status IN (''New'',''Open'') and m.mast_num_id in(select jd.mast_num_id from '+QUOTENAME(@Tenant)+'.'+'[job_details] jd where jd.job_Id IN(select jr.job_Id from '+QUOTENAME(@Tenant)+'.'+'[job_roles] jr where jr.user_id='+ cast (@userId as NVARCHAR(10))+')) order by m.created_datetime desc';
			/**** and j.job_id in(select jr.job_Id from '+QUOTENAME(@Tenant)+'.'+'[job_roles] jr where jr.user_id='+ cast (@userId as NVARCHAR(10))+') and j.current_job_status NOT IN(''Closed'',''Rejected'') ****/
			  
END 

ELSE IF(@Type = 'allopen')
BEGIN

SET @SQL=@SQL+' and m.status IN (''New'',''Open'') order by m.created_datetime desc ';
    /**** and j.current_job_status NOT IN (''Closed'',''Rejected'') ****/

END


ELSE
BEGIN
SET @SQL=@SQL+' order by m.created_datetime desc';
END

EXEC (@SQL)
print  (@SQL)
GO

