-- =============================================
-- Stored Procedure: [dbo].[proc_cte_job_details]
-- Repeatable Migration - Re-runs when content changes
-- =============================================
CREATE OR ALTER PROCEDURE proc_cte_job_details(@tenant varchar(160))

AS

BEGIN

DECLARE @SQL VARCHAR(MAX)

SET @SQL=N';

WITH CTE_JobDetails AS 

(

    SELECT jd.[job_code],

	MAX(jd.[current_job_status]) AS [status],

	MAX(cn.[mast_num_job_notes_id]) AS [NoteID]

    FROM 

        '+QUOTENAME(@Tenant)+'.[job_details] jd

    LEFT JOIN 

        '+QUOTENAME(@Tenant)+'.[common_notes] cn

    ON 

        jd.[job_id] = cn.[job_id]

    WHERE 

        cn.[notes_category] = ''Financial Notes''

    GROUP BY 

        jd.[job_code]

)

SELECT 

    cte.[job_code],

    cn.[mast_num_job_notes_id],

    cn.[notes],

    cn.[written_datetime],

	cte.status

FROM 

    CTE_JobDetails cte

JOIN 

    '+QUOTENAME(@Tenant)+'.[common_notes] cn

ON 

    cte.[NoteID] = cn.[mast_num_job_notes_id]

WHERE cte.[status] != ''Closed'' AND cte.[status] != ''Rejected'''

END;

EXEC (@SQL)

print  (@SQL)
GO

GO
-- =============================================
-- Stored Procedure: [dbo].[usp_AllTenantsUtilizationReport]
-- Repeatable Migration - Re-runs when content changes
-- =============================================
CREATE OR ALTER PROCEDURE [dbo].[usp_AllTenantsUtilizationReport]
AS
BEGIN
    SET NOCOUNT ON;

    -- Create temp table to hold all results
    CREATE TABLE #AllTenantUtilization (
        purchased_user INT,
        users_count INT,
        last_job_created_date DATETIME,
        last_note_created_date DATETIME,
        last_schedule_created_date DATETIME,
        job_count INT,
        notes_count INT,
        time_tracking_count INT,
        forms_count INT,
        task_count INT,
        calender_count INT,
        sales_activity_count INT,
        contact_notes_count INT,
        organization_notes_count INT,
        encircle NVARCHAR(10),
        cleanClaims NVARCHAR(10),
        quickbooksdesktop NVARCHAR(10),
        quickbooksonline NVARCHAR(10),
        zapier NVARCHAR(10),
        pictureCount INT,
        recentPictureCount INT,
        companyCam NVARCHAR(10),
        tenantNumber NVARCHAR(255)
    );

    -- Variables for cursor
    DECLARE @tenant_schema NVARCHAR(255);
    DECLARE @total_count INT = 0;
    DECLARE @processed_count INT = 0;
    DECLARE @error_count INT = 0;

    -- Get total count
    SELECT @total_count = COUNT(*)
    FROM common.rest_comp_details
    WHERE schema_name IS NOT NULL;

    PRINT 'Starting to process ' + CAST(@total_count AS NVARCHAR(10)) + ' tenants...';
    PRINT '';

    -- Cursor to loop through each tenant (including inactive)
    DECLARE tenant_cursor CURSOR FOR
    SELECT schema_name
    FROM common.rest_comp_details
    WHERE schema_name IS NOT NULL
    ORDER BY schema_name;

    OPEN tenant_cursor;
    FETCH NEXT FROM tenant_cursor INTO @tenant_schema;

    WHILE @@FETCH_STATUS = 0
    BEGIN
        BEGIN TRY
            -- Call the procedure for this tenant
            INSERT INTO #AllTenantUtilization
            EXEC [dbo].[utlization_reports_java21] @Tenant = @tenant_schema;
            
            SET @processed_count = @processed_count + 1;
            
            -- Print progress every 50 tenants
            IF @processed_count % 50 = 0
            BEGIN
                PRINT 'Processed ' + CAST(@processed_count AS NVARCHAR(10)) + ' of ' + CAST(@total_count AS NVARCHAR(10)) + ' tenants...';
            END
        END TRY
        BEGIN CATCH
            SET @error_count = @error_count + 1;
            PRINT 'ERROR processing ' + @tenant_schema + ': ' + ERROR_MESSAGE();
        END CATCH
        
        FETCH NEXT FROM tenant_cursor INTO @tenant_schema;
    END;

    CLOSE tenant_cursor;
    DEALLOCATE tenant_cursor;

    PRINT '';
    PRINT 'Processing complete!';
    PRINT 'Successfully processed: ' + CAST(@processed_count AS NVARCHAR(10)) + ' tenants';
    PRINT 'Errors: ' + CAST(@error_count AS NVARCHAR(10));
    PRINT '';

    -- Return the results with improved formatting
    SELECT 
        r.tenantNumber AS [Tenant Number],
        c.rest_comp_title AS [Tenant Company Name],
        r.purchased_user AS [Licenses Purchased],
        r.users_count AS [Active Users],
        r.last_job_created_date AS [Last Job Added DateTime],
        r.last_note_created_date AS [Last Note Added DateTime],
        r.last_schedule_created_date AS [Last Appointment Added DateTime],
        r.job_count AS [Job Count],
        r.notes_count AS [Notes Count],
        r.time_tracking_count AS [Time Tracking Records Count],
        r.forms_count AS [Signed Forms Count],
        r.task_count AS [Completed Tasks],
        r.calender_count AS [Scheduler Usage Count],
        r.sales_activity_count AS [Sales Activities Count],
        r.contact_notes_count AS [Contact Notes Count],
        r.organization_notes_count AS [Organization Notes Count],
        -- Convert flags to Yes/No
        CASE 
            WHEN r.encircle = '1' OR UPPER(r.encircle) = 'TRUE' THEN 'Yes'
            WHEN r.encircle = '0' OR UPPER(r.encircle) = 'FALSE' THEN 'No'
            ELSE ISNULL(r.encircle, 'No')
        END AS [Encircle Integration],
        CASE 
            WHEN r.cleanClaims = '1' OR UPPER(r.cleanClaims) = 'TRUE' THEN 'Yes'
            WHEN r.cleanClaims = '0' OR UPPER(r.cleanClaims) = 'FALSE' THEN 'No'
            ELSE ISNULL(r.cleanClaims, 'No')
        END AS [CleanClaim Integration],
        CASE 
            WHEN r.quickbooksdesktop = '1' OR UPPER(r.quickbooksdesktop) = 'TRUE' THEN 'Yes'
            WHEN r.quickbooksdesktop = '0' OR UPPER(r.quickbooksdesktop) = 'FALSE' THEN 'No'
            ELSE ISNULL(r.quickbooksdesktop, 'No')
        END AS [QuickBooksDesktop Integration],
        CASE 
            WHEN r.quickbooksonline = '1' OR UPPER(r.quickbooksonline) = 'TRUE' THEN 'Yes'
            WHEN r.quickbooksonline = '0' OR UPPER(r.quickbooksonline) = 'FALSE' THEN 'No'
            ELSE ISNULL(r.quickbooksonline, 'No')
        END AS [QuickBooksOnline Integration],
        CASE 
            WHEN r.zapier = '1' OR UPPER(r.zapier) = 'TRUE' THEN 'Yes'
            WHEN r.zapier = '0' OR UPPER(r.zapier) = 'FALSE' THEN 'No'
            ELSE ISNULL(r.zapier, 'No')
        END AS [Zapier Integration],
        r.pictureCount AS [Picture Count],
        r.recentPictureCount AS [Recent Picture Count],
        CASE 
            WHEN r.companyCam = '1' OR UPPER(r.companyCam) = 'TRUE' THEN 'Yes'
            WHEN r.companyCam = '0' OR UPPER(r.companyCam) = 'FALSE' THEN 'No'
            ELSE ISNULL(r.companyCam, 'No')
        END AS [CompanyCam Integration],
        -- Add Active status at the end
        CASE 
            WHEN c.rest_comp_status = 'Active' THEN 'Active'
            ELSE ISNULL(c.rest_comp_status, 'Inactive')
        END AS [Tenant Status]
    FROM #AllTenantUtilization r
    LEFT JOIN common.rest_comp_details c ON c.schema_name = r.tenantNumber
    ORDER BY r.tenantNumber;

    PRINT 'Total rows returned: ' + CAST(@@ROWCOUNT AS NVARCHAR(10));

    -- Cleanup
    DROP TABLE #AllTenantUtilization;
END;

GO

