 cte2 as(SELECT max(cte.[kpi target]) ''kpi target'' FROM cte join cte1 on cte1.config_value like ''%''+ cte.job_type +''%''
 where (cte1.config_value = IIF('''+@Division+''' = ''-ALL-'',cte1.config_value,'''+@Division+''') or (cte1.config_value IS NULL)) and kpi_name like ''%'+@KPIValue+'%''),
 cte3 as(SELECT datename(mm,j.Created_datetime) ''Month'',Month(j.Created_datetime) ''MonthNum'',sum(k.kpi_value) as ''KPI'',count(k.Job_id) as ''Count''
 FROM '+QUOTENAME(@Tenant)+'.'+'[job_kpi_details] k join'+QUOTENAME(@Tenant)+'.'+'job_details as j on k.job_id=j.job_id join'+QUOTENAME(@Tenant)+'.'+'v_roles as v 
 on v.job_id=j.job_id join'+QUOTENAME(@Tenant)+'.'+'[job_insurance_details] as i on i.job_id=j.job_id
 WHERE datepart(yy,j.Created_datetime) =year(DATEADD(year,-1,getdate())) and (k.kpi_value)>=0
 and kpi_name=('''+@KPIValue+''') 
 and (j.job_type = IIF('''+@Division+''' = ''-ALL-'',j.job_type,'''+@Division+''') or (j.job_type IS NULL)) 
 and (v.Estimator='''+@Estimator+''' or '''+@Estimator+'''=''-ALL-'')
 and (v.Supervisor='''+@Supervisor+''' or '''+@Supervisor+'''=''-ALL-'')
 and (i.insurance_company_name ='''+@Insurancecompany+''' or '''+@Insurancecompany+'''=''-ALL-'') 
 and (j.tpa_name='''+@TPA+''' or '''+@TPA+'''=''-ALL-'') group by datename(mm,j.Created_datetime),Month(j.Created_datetime))
  
 SELECT  cte3.Month,cte3.MonthNum,sum(cte3.KPI/cte3.Count)'+ QUOTENAME(@KPIValue)+',sum(cte2.[kpi target]) ''TargetValue'' from cte2  join cte3 on 1=1 group by cte3.Month,cte3.MonthNum
 order by cte3.MonthNum'
  
