 on v.job_id=j.job_id join'+QUOTENAME(@Tenant)+'.'+'[job_insurance_details] as i on i.job_id=j.job_id
 WHERE j.Created_datetime >=
 DateAdd(Year, -1, DateAdd(Month, DateDiff(Month, 0, GetDate()), 0) - 1) + 1   
      and j.Created_datetime   < DateAdd(Month, DateDiff(Month, 0, GetDate()), 0) and (k.kpi_value)>=0
 and kpi_name=('''+@KPIValue+''') 
