-- Stored Procedure: [dbo].[usp_Load_AllJobs]
-- Repeatable Migration - Re-runs when content changes
-- =============================================
CREATE OR ALTER PROCEDURE [dbo].[usp_Load_AllJobs]

       -- Add the parameters for the stored procedure here
        (@Tenant NVARCHAR(15),@Status NVARCHAR(511),@Division NVARCHAR(255),@Estimator NVARCHAR(511),
		 @SalesRep NVARCHAR(511),@Supervisor NVARCHAR(511))
		 		 	 
AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	SET NOCOUNT ON;

	--SET @Division=(SELECT DISTINCT job_type FROM [xcelerate].[tenant1].[job_details]
	--               WHERE job_type=@Division)

	--SET @Estimator=(SELECT  Estimator FROM [xcelerate].[dbo].[v_roles] 
	--                WHERE Estimator=@Estimator)

	--SET @SalesRep=(SELECT  [Sales Representative] FROM [xcelerate].[dbo].[v_roles]
	--               WHERE [Sales Representative]=@SalesRep)

	--SET @Supervisor=(SELECT DISTINCT Supervisor FROM [xcelerate].[dbo].[v_roles] 
	--                 WHERE Supervisor=@Supervisor)


    -- interfering with SELECT statements.

DECLARE @SQL NVARCHAR(MAX)
DECLARE @Cols AS NVARCHAR(MAX)

SELECT @Cols= ISNULL(@Cols + ',','') 
       + QUOTENAME(kpi_name)
FROM (SELECT DISTINCT kpi_name FROM tenant1.job_kpi_details) AS Courses


SET @SQL=N';with cte as

(SELECT jd.job_code ''File Number'',jd.current_job_status ''Status'',jd.job_type ''Division'',jd.job_id,

jd.first_name'+'+'' ''+'+'jd.last_name  ''Customer Name'',

r.Supervisor,r.Estimator,r.Coordinator,r.[Sales Representative] ''Sales Rep'',

r.Administrator,r.Finance,r.Role,sum(e.estimated_amount) ''Total Estimate Amount'',

CONVERT(DATE,m.targetcompletiondate) ''Target Completion Date'',CONVERT(DATE,m.dateofWorkAuthorization) ''Work Authorization Date'',

CONVERT(DATE,m.dateEstimatesent) ''Date Estimate Uploaded'',CONVERT(DATE,m.startdate) ''Start Date'',

CONVERT(DATE,m.dateOfcOs) ''COC Date'',CONVERT(DATE,m.final_invoice_date) ''Final Invoice Date'',

CONVERT(DATE,m.dateinvoiced) ''Invoice Date'',CONVERT(DATE,m.dateinspected) ''Date Inspected'',

CONVERT(DATE,m.datecontacted) ''Date Contacted'',CONVERT(DATE,m.dateReceived) ''Date Created'',CONVERT(DATE,m.closeddate) ''Date Closed'',

null ''Warranty Date'',jd.referred_source ''Referred Source'',null  ''Referred By'',

i.Insurance_company_name ''Insurance Company'',jd.tpa_name TPA, 

(select config_value from' +QUOTENAME(@Tenant)+'.'+'m_config_data where

 config_name =''Program Type'' and config_id = program_type) ''Program Type'',

(select config_value from' +QUOTENAME(@Tenant)+'.'+'m_config_data where 

config_name = ''Cause of Loss'' and config_id = cause_of_loss) ''Cause of Loss'',
  
0 ''Total Job Cost'',0 ''Total Labor Cost'',0 ''Total Subcontractor Cost'',

0 ''Total Invoiced'',0 ''Total Equipment Revenue'',0 ''Total Emergency Services Revenue'',

0 ''Total Labor (Hours)'',0 ''Total Collected'',jd.[dash_file_number] ''Reference File Details'',jd.[loss_address] ''Address'',jd.[loss_address_city] ''City'',

jd.[loss_address_state] ''State'',jd.[loss_address_zip] ''Zip Code'',jd.[property_type] ''Commercial/Residential''

from '+QUOTENAME(@Tenant)+'.'+'[job_details] jd

left join'+QUOTENAME(@Tenant)+'.'+'[v_roles] r

on jd.job_id = r.job_id

left join'+QUOTENAME(@Tenant)+'.'+'[common_milestones] m

on jd.job_id = m.source_id

left join'+QUOTENAME(@Tenant)+'.'+'[job_insurance_details] i

on jd.job_id = i.job_id 

left join'+QUOTENAME(@Tenant)+'.'+'[job_estimate] e

on jd.job_id = e.job_id

 where jd.current_job_status = IIF('''+@Status+'''=''-ALL-'',jd.current_job_status,'''+@Status+''') and Year(JD.created_datetime)>=2017
		  and (jd.job_type = IIF('''+@Division+''' = ''-ALL-'',jd.job_type,'''+@Division+''') or (jd.job_type IS NULL))
		  and (r.Estimator='''+@Estimator+''' or '''+@Estimator+'''=''-ALL-'')
		  and (r.[Sales Representative]='''+@SalesRep+''' or '''+@SalesRep+'''=''-ALL-'') 
		  and  (r.Supervisor='''+@Supervisor+''' or '''+@Supervisor+'''=''-ALL-'')
		  group by jd.job_code,jd.current_job_status,jd.job_type,jd.first_name'+'+'' ''+'+'jd.last_name,
		  r.Supervisor,r.Estimator,r.Coordinator,r.[Sales Representative],r.Administrator,r.Finance,r.Role,CONVERT(DATE,m.targetcompletiondate),CONVERT(DATE,m.dateofWorkAuthorization),
		  CONVERT(DATE,m.dateEstimatesent),CONVERT(DATE,m.startdate),CONVERT(DATE,m.dateOfcOs),CONVERT(DATE,m.final_invoice_date),CONVERT(DATE,m.dateinvoiced),CONVERT(DATE,m.dateinspected),
		  CONVERT(DATE,m.datecontacted),CONVERT(DATE,m.dateReceived) ,CONVERT(DATE,m.closeddate),jd.referred_source,i.Insurance_company_name,jd.tpa_name,
		  program_type,cause_of_loss,jd.[dash_file_number],jd.job_id,jd.[loss_address],jd.[loss_address_city],jd.[loss_address_state],jd.[loss_address_zip],jd.[property_type])
,cte2 as(select j.job_id,
CASE
WHEN j.referred_type =''Organization'' THEN
(select e.external_agency_name from '+QUOTENAME(@Tenant)+'.'+'external_agency_details e where e.external_agency_id=j.referred_by)
WHEN j.referred_type =''People'' THEN
(select c.contact_first_name+'' ''+c.contact_last_name from '+QUOTENAME(@Tenant)+'.'+'contact_details c where c.contact_id=j.referred_by)
ELSE
j.referred_by
end
as ''Referred By''
from '+QUOTENAME(@Tenant)+'.'+'job_details j)

  ,cte3 as(
   select * from 
 (SELECT job_id,kpi_name,kpi_value FROM'+QUOTENAME(@Tenant)+'.'+'[job_kpi_details] where job_id is not null)src
  PIVOT (
  max(kpi_value)
  FOR kpi_name in (' + @Cols + ')
  ) piv
  )
 
 ,cte4 as(
   select * from 
 (SELECT job_id,kpi_name,kpi_target_value FROM'+QUOTENAME(@Tenant)+'.'+'[job_kpi_details] where job_id is not null)src1
  PIVOT (
  max(kpi_target_value)
  FOR kpi_name in (' + @Cols + ')
  ) piv1
  )

  ,cte5 as(
    select * from 
 (SELECT job_id,kpi_name,created_datetime FROM'+QUOTENAME(@Tenant)+'.'+'[job_kpi_details] where job_id is not null)src2
  PIVOT (
  max(created_datetime)
  FOR kpi_name in (' + @Cols + ')
  ) piv2
  )

  ,cte6 as(

  SELECT cte3.job_id,cte3.[Cycle Time],cte4.[Cycle Time] ''Cycle Target'',CONVERT(DATE,cte5.[Cycle Time]) ''Cycle Time Date Calculated'',cte3.[WIP Time],cte4.[WIP Time] ''WIP Time Target'',
    
  CONVERT(DATE,cte5.[WIP Time]) ''WIP Date Calculated'',cte3.[Total Final Invoice Time],cte4.[Total Final Invoice Time] ''Total Final Invoice Target'',
  
  CONVERT(DATE,cte5.[Total Final Invoice Time]) ''Total Final Invoice Date Calculated'',cte3.[Days to Start],cte4.[Days to Start] ''Days to Start Target'',
  
  CONVERT(DATE,cte5.[Days to Start]) ''Days To Start Date Calculated'',cte3.[Estimate Bid Time],cte4.[Estimate Bid Time] ''Estimate Bid Time Target'',
  
  CONVERT(DATE,cte5.[Estimate Bid Time]) ''Estimate Bid Time Date Calculated'',cte3.[Final Estimate Upload Time],cte4.[Final Estimate Upload Time] ''Final estimate Upload Time Target'',

  CONVERT(DATE,cte5.[Final Estimate Upload Time]) ''Final estimate Upload Time Date Calculated'',cte3.[Onsite Arrival Time],cte4.[Onsite Arrival Time] ''Onsite Arrival Time Target'',

  CONVERT(DATE,cte5.[Onsite Arrival Time]) ''Onsite Arrival Time Date Calculated'',cte3.[Target Completion Accuracy],cte4.[Target Completion Accuracy] ''Target Completion Accuracy Target'',

  CONVERT(DATE,cte5.[Target Completion Accuracy]) ''Target Completion Accuracy Date Calculated'',cte3.[Contact Customer Time],cte4.[Contact Customer Time] ''Contact Customer Time Target'',

  CONVERT(DATE,cte5.[Contact Customer Time]) ''Contact Customer Time Date Calculated'',cte3.[Days to Sign],cte4.[Days to Sign] ''Days to Sign Target'',

  CONVERT(DATE,cte5.[Days to Sign]) ''Days to Sign Date Calculated'',cte3.[Final Invoice Delay Time],cte4.[Final Invoice Delay Time] ''Final Invoice Delay Time Target'',

  CONVERT(DATE,cte5.[Final Invoice Delay Time]) ''Final Invoice Delay Time Date Calculated''

  from cte3 join cte4 on cte3.job_id=cte4.job_id join cte5 on cte3.job_id=cte5.job_id)

		
SELECT [File Number],[Status],Division,[Customer Name],Supervisor,Estimator,Coordinator,[Sales Rep],

Administrator,Finance,Role,[Total Estimate Amount],[Target Completion Date],[Work Authorization Date],[Date Estimate Uploaded],[Start Date],[COC Date],[Final Invoice Date],

[Invoice Date],[Date Inspected],[Date Contacted],[Date Created],[Date Closed],[Warranty Date],[Referred Source],cte2.[Referred By],[Insurance Company],TPA, 

[Program Type],[Cause of Loss],[Total Job Cost],[Total Labor Cost],[Total Subcontractor Cost],[Total Invoiced],[Total Equipment Revenue],[Total Emergency Services Revenue],

[Total Labor (Hours)],[Total Collected],[Reference File Details],[Address],[City],[State],[Zip Code],[Commercial/Residential],cte6.[Cycle Time],cte6.[Cycle Target],cte6.[Cycle Time Date Calculated],

cte6.[WIP Time],cte6.[WIP Time Target],cte6.[WIP Date Calculated],cte6.[Total Final Invoice Time],cte6.[Total Final Invoice Target],cte6.[Total Final Invoice Date Calculated],cte6.[Days to Start],cte6.[Days to Start Target],

cte6.[Days To Start Date Calculated],cte6.[Estimate Bid Time],cte6.[Estimate Bid Time Target],cte6.[Estimate Bid Time Date Calculated],cte6.[Final Estimate Upload Time],cte6.[Final estimate Upload Time Target],

cte6.[Final estimate Upload Time Date Calculated],cte6.[Onsite Arrival Time],cte6.[Onsite Arrival Time Target],cte6.[Onsite Arrival Time Date Calculated],cte6.[Target Completion Accuracy],cte6.[Target Completion Accuracy Target],

cte6.[Target Completion Accuracy Date Calculated],cte6.[Contact Customer Time],cte6.[Contact Customer Time Target],cte6.[Contact Customer Time Date Calculated],cte6.[Days to Sign],cte6.[Days to Sign Target],

cte6.[Days to Sign Date Calculated],cte6.[Final Invoice Delay Time],cte6.[Final Invoice Delay Time Target],cte6.[Final Invoice Delay Time Date Calculated]

from  cte 

left join cte2 on cte.job_id=cte2.job_id 

left join cte6 on cte.job_id=cte6.job_id'

EXEC (@SQL)
END







