-- =============================================
-- Stored Procedure: [dbo].[usp_Load_AverageJobSize_All]
-- Repeatable Migration - Re-runs when content changes
-- =============================================
CREATE OR ALTER PROCEDURE [dbo].[usp_Load_AverageJobSize_All] 
     (@Tenant NVARCHAR(15),@Dates INT)

	 --change @Tenant 7 to 15 

AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	-- interfering with SELECT statements.
	SET NOCOUNT ON;
	--DECLARE @currentyear as currentdat;

    -- Insert statements for procedure here

DECLARE @SQL NVARCHAR(MAX)

DROP TABLE IF EXISTS #TEMP3
CREATE TABLE #TEMP3(job_id INT,job_type NVARCHAR(200));

SET @SQL='SELECT job_id,job_type FROM'++QUOTENAME(@Tenant)+'.'+'[job_details]'

INSERT INTO #TEMP3 EXEC (@SQL)

DROP TABLE IF EXISTS #TableVariable3
CREATE TABLE #TableVariable3 (Id INT IDENTITY(1,1), job_type NVARCHAR(500))
INSERT INTO #TableVariable3 SELECT DISTINCT job_type FROM #TEMP3 WHERE job_type not in (' ') ORDER BY job_type

DROP TABLE IF EXISTS #JobSize3
CREATE TABLE #JobSize3 ([All Records] NVARCHAR(500),[Average Job Size(Estimate)] FLOAT)

DECLARE @tableLength3 INT,@k3 NVARCHAR(7)

SELECT @tableLength3 = COUNT(Id) FROM #TableVariable3

SET @k3 = 1

DROP TABLE IF EXISTS #TEMP
CREATE TABLE #TEMP(job_id INT,Estimator NVARCHAR(200),[Sales Representative] NVARCHAR(200),Supervisor NVARCHAR(200));

SET @SQL='SELECT job_id,estimator,[Sales Representative],Supervisor FROM'++QUOTENAME(@Tenant)+'.'+'[v_roles]'

INSERT INTO #TEMP EXEC (@SQL)

DROP TABLE IF EXISTS #TableVariable
CREATE TABLE #TableVariable (Id INT IDENTITY(1,1), estimator NVARCHAR(500))
INSERT INTO #TableVariable SELECT DISTINCT estimator FROM #TEMP  WHERE estimator not in (' ')

DROP TABLE IF EXISTS #JobSize
CREATE TABLE #JobSize (Estimator NVARCHAR(20),[Average Job Size(Estimate)] FLOAT)

DECLARE @tableLength INT,@k NVARCHAR(7)

SELECT @tableLength = COUNT(Id) FROM #TableVariable

SET @k = 1

DROP TABLE IF EXISTS #TableVariable1
CREATE TABLE #TableVariable1 (Id INT IDENTITY(1,1), [Sales Representative] NVARCHAR(500))
INSERT INTO #TableVariable1 SELECT DISTINCT [Sales Representative] FROM #TEMP  WHERE [Sales Representative] not in (' ')

DROP TABLE IF EXISTS #JobSize1
CREATE TABLE #JobSize1 ([Sales Rep] NVARCHAR(20),[Average Job Size(Estimate)] FLOAT)
 
DECLARE @tableLength1 INT,@k1 NVARCHAR(7)

SELECT @tableLength1 = COUNT(Id) FROM #TableVariable1

SET @k1 = 1

DROP TABLE IF EXISTS #TableVariable2
CREATE TABLE #TableVariable2 (Id INT IDENTITY(1,1), Supervisor NVARCHAR(500))
INSERT INTO #TableVariable2 SELECT DISTINCT Supervisor FROM #TEMP  WHERE Supervisor not in (' ')

DROP TABLE IF EXISTS #JobSize2
CREATE TABLE #JobSize2 (Supervisor NVARCHAR(20),[Average Job Size(Estimate)] FLOAT)
 
DECLARE @tableLength2 INT,@k2 NVARCHAR(7)

SELECT @tableLength2 = COUNT(Id) FROM #TableVariable2

SET @k2 = 1

DROP TABLE IF EXISTS #TEMP4
CREATE TABLE #TEMP4(job_id INT,insurance_company_name NVARCHAR(200));

SET @SQL='SELECT job_id,insurance_company_name FROM'++QUOTENAME(@Tenant)+'.'+'[job_insurance_details]'

INSERT INTO #TEMP4 EXEC (@SQL)

DROP TABLE IF EXISTS #TableVariable4
CREATE TABLE #TableVariable4 (Id INT IDENTITY(1,1), insurance_company_name NVARCHAR(500))
INSERT INTO #TableVariable4 SELECT DISTINCT insurance_company_name FROM #TEMP4 WHERE insurance_company_name not in (' ') ORDER BY insurance_company_name

DROP TABLE IF EXISTS #JobSize4
CREATE TABLE #JobSize4 ([Insurance company] NVARCHAR(500),[Average Job Size(Estimate)] FLOAT)

DECLARE @tableLength4 INT,@k4 NVARCHAR(7)

SELECT @tableLength4 = COUNT(Id) FROM #TableVariable4

SET @k4 = 1

DROP TABLE IF EXISTS #TEMP5
CREATE TABLE #TEMP5(Referred_source NVARCHAR(200));

SET @SQL='SELECT config_value as Referred_source FROM'+QUOTENAME(@Tenant)+'.'+'m_config_data  WHERE config_name=''Referred'+' '+'source'''

INSERT INTO #TEMP5 EXEC (@SQL)

DROP TABLE IF EXISTS #TableVariable5
CREATE TABLE #TableVariable5 (Id INT IDENTITY(1,1), Referred_source NVARCHAR(500))
INSERT INTO #TableVariable5 SELECT DISTINCT Referred_source FROM #TEMP5 WHERE Referred_source not in (' ') 

DROP TABLE IF EXISTS #JobSize5
CREATE TABLE #JobSize5 ([Referred Source] NVARCHAR(500),[Average Job Size(Estimate)] FLOAT)

DECLARE @tableLength5 INT,@k5 NVARCHAR(7)

SELECT @tableLength5 = COUNT(Id) FROM #TableVariable5

SET @k5 = 1

IF(@Dates='1')---This date paramater is used to populate the data for sum of total estimates by no.of records for current year

BEGIN

		 WHILE @k3 <= @tableLength3 

BEGIN	 

DROP TABLE IF EXISTS #count1 
CREATE TABLE #count1(Sum_Job_Size FLOAT,purpose VARCHAR(20),rest_comp_location_id VARCHAR(20))
SET @SQL = N'INSERT INTO #count1 SELECT  Sum(e.estimated_amount) Sum_Job_Size,' + '''report'''+ ',1
FROM '+QUOTENAME(@Tenant)+'.'+'[job_estimate] e
join #TEMP3 as v ON e'+ '.'+'job_id=v' +'.'+'job_id join'+QUOTENAME(@Tenant)+'.'+'[job_details] as j on j.job_id=e.job_id 
where v'+ '.' + 'job_type = (SELECT job_type FROM  #TableVariable3 WHERE Id = '+ @k3 +')
and j'+'.'+'current_job_status in(' + '''Planning''' + ',' + '''Production''' + ',' + '''Invoice''' + ',' + '''Receivables''' + ',' + '''Closed''' + ')
and e.status=('+'''Active'''+')
and  datepart(yy,j.created_datetime) =year(getdate())'     
EXEC (@SQL)	

DROP TABLE IF EXISTS #count2
CREATE TABLE #count2(Count_Job_Size FLOAT,purpose VARCHAR(20))
SET @SQL = N'INSERT INTO #count2 SELECT  COUNT(e'+'.'+'job_id) Count_Job_Size,' + '''report'''+
'FROM'+QUOTENAME(@Tenant)+'.'+'[job_estimate] e
