CREATE OR ALTER PROCEDURE [dbo].[usp_Load_AverageJobSizeCustom_InsuranceCompany] 
     (@Tenant NVARCHAR(15),@Startdate DATETIME,@Enddate DATETIME)

	 --change @Tenant 7 to 15 

AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	-- interfering with SELECT statements.
	SET NOCOUNT ON;
	--DECLARE @currentyear as currentdat;

    -- Insert statements for procedure here

DECLARE @SQL NVARCHAR(MAX)

DROP TABLE IF EXISTS #TEMP
CREATE TABLE #TEMP(job_id INT,insurance_company_name NVARCHAR(200));

SET @SQL='SELECT job_id,insurance_company_name FROM'++QUOTENAME(@Tenant)+'.'+'[job_insurance_details]'

INSERT INTO #TEMP EXEC (@SQL)

DROP TABLE IF EXISTS #TableVariable
CREATE TABLE #TableVariable (Id INT IDENTITY(1,1), insurance_company_name NVARCHAR(500))
INSERT INTO #TableVariable SELECT DISTINCT insurance_company_name FROM #TEMP WHERE insurance_company_name not in (' ') ORDER BY insurance_company_name

DROP TABLE IF EXISTS #JobSize
CREATE TABLE #JobSize ([Insurance company] NVARCHAR(500),[Average Job Size(Estimate)] FLOAT)

DECLARE @tableLength INT,@k NVARCHAR(7)

SELECT @tableLength = COUNT(Id) FROM #TableVariable

 SET @k = 1

		 WHILE @k <= @tableLength 

BEGIN	 

DROP TABLE IF EXISTS #count1 
CREATE TABLE #count1(Sum_Job_Size FLOAT,purpose VARCHAR(20),rest_comp_location_id VARCHAR(20))
SET @SQL = N'INSERT INTO #count1 SELECT  Sum(e.estimated_amount) Sum_Job_Size,' + '''report'''+ ',1
FROM '+QUOTENAME(@Tenant)+'.'+'[job_estimate] e
join #TEMP as v ON e'+ '.'+'job_id=v' +'.'+'job_id join'+QUOTENAME(@Tenant)+'.'+'[job_details] as j on j.job_id=e.job_id 
where v'+ '.' + 'insurance_company_name = (SELECT insurance_company_name FROM  #TableVariable WHERE Id = '+ @k +')
and j'+'.'+'current_job_status in(' + '''Planning''' + ',' + '''Production''' + ',' + '''Invoice''' + ',' + '''Receivables''' + ',' + '''Closed''' + ')
and e.status=('+'''Active'''+')
and  j.created_datetime BETWEEN'''+CONVERT(NVARCHAR(100),@StartDate,109)+'''and'''+CONVERT(NVARCHAR(100),@EndDate,109)+''''       
EXEC (@SQL)	

DROP TABLE IF EXISTS #count2
CREATE TABLE #count2(Count_Job_Size FLOAT,purpose VARCHAR(20))
SET @SQL = N'INSERT INTO #count2 SELECT  COUNT(e'+'.'+'job_id) Count_Job_Size,' + '''report'''+
'FROM'+QUOTENAME(@Tenant)+'.'+'[job_estimate] e
join #TEMP as v ON e'+ '.'+'job_id=v' +'.'+'job_id join'+QUOTENAME(@Tenant)+'.'+'[job_details] as j on j.job_id=e.job_id
where v'+ '.' + 'insurance_company_name = (SELECT insurance_company_name FROM  #TableVariable WHERE Id = '+ @k +')
and j'+'.'+'current_job_status in(' + '''Planning''' + ',' + '''Production''' + ',' + '''Invoice''' + ',' + '''Receivables''' + ',' + '''Closed''' + ')
and e.status=('+'''Active'''+')
and  j.created_datetime BETWEEN'''+CONVERT(NVARCHAR(100),@StartDate,109)+'''and'''+CONVERT(NVARCHAR(100),@EndDate,109)+''''  
EXEC (@SQL)

 SET @SQL = N'INSERT INTO #JobSize SELECT DISTINCT v.insurance_company_name'+','+'(COALESCE(
((a.Sum_Job_Size)/NULLIF(b.Count_Job_Size,0)),0))
 FROM'+QUOTENAME(@Tenant)+'.'+'[job_estimate] e join #TEMP as v ON e.job_id=v.job_id join'+QUOTENAME(@Tenant)+'.'+'[job_details] as j on j.job_id=e.job_id
join #count1 as a on a.rest_comp_location_id=j.rest_comp_location_id join 
#count2 as b ON a.purpose=b.purpose WHERE v.insurance_company_name=(SELECT insurance_company_name FROM  #TableVariable WHERE Id = '+ @k +')'     
EXEC (@SQL)

	  SET @k = @k + 1
END	  
SELECT * FROM #JobSize

END 




