     (@Type INT,@Tenant NVARCHAR(15),@Startdate DATETIME,@Enddate DATETIME,@Status INT)

	 --change @Tenant 7 to 15 

AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	-- interfering with SELECT statements.
	SET NOCOUNT ON;

DECLARE @SQL NVARCHAR(MAX)

DROP TABLE IF EXISTS #TEMP
CREATE TABLE #TEMP(Referred_source NVARCHAR(200));

SET @SQL='SELECT config_value as Referred_source FROM'+QUOTENAME(@Tenant)+'.'+'m_config_data  WHERE config_name=''Referred'+' '+'source'''

INSERT INTO #TEMP EXEC (@SQL)

DROP TABLE IF EXISTS #TableVariable
CREATE TABLE #TableVariable (Id INT IDENTITY(1,1), Referred_source NVARCHAR(500))
INSERT INTO #TableVariable SELECT DISTINCT Referred_source FROM #TEMP WHERE Referred_source not in (' ') 

DROP TABLE IF EXISTS #CLOSERATIO
CREATE TABLE #CLOSERATIO ([Referred Source] NVARCHAR(500),[Close Ratio] NVARCHAR(20),[Files Sold] NVARCHAR(20),[Total Files] NVARCHAR(20))


DECLARE @tableLength INT,@k NVARCHAR(7)


SELECT @tableLength = COUNT(Id) FROM #TableVariable

 SET @k = 1

IF(@Type=1)

BEGIN
		 WHILE @k <= @tableLength 

BEGIN	 
	  
DROP TABLE IF EXISTS #count1 
CREATE TABLE #count1(closeratio1 FLOAT,purpose VARCHAR(20),rest_comp_location_id VARCHAR(20))
SET @SQL = N'INSERT INTO #count1 SELECT  COUNT(a'+'.'+'job_id) Closeratiocount,' + '''report'''+ ',1
FROM '+QUOTENAME(@Tenant)+'.'+'[job_details] a
join #TEMP as v ON a.referred_source=v.referred_source
where v'+ '.' + 'referred_source = (SELECT referred_source FROM  #TableVariable WHERE Id = '+ @k +')
and a'+'.'+'current_job_status in(' + '''Planning''' + ',' + '''Production''' + ',' + '''Invoice''' + ',' + '''Receivables''' + ',' + '''Closed''' +','+'''Rejected'''+')
and  a'+'.'+'job_type in(' + '''Reconstruction''' + ',' + '''Content''' + ',' + '''Asbestos''' + ','+ '''Structure Cleaning'''+ ') 
and  a.created_datetime BETWEEN'''+CONVERT(NVARCHAR(100),@StartDate,109)+'''and'''+CONVERT(NVARCHAR(100),@EndDate,109)+''''    
EXEC (@SQL)	

DROP TABLE IF EXISTS #count2
CREATE TABLE #count2(closeratio1 FLOAT,purpose VARCHAR(20))
SET @SQL = N'INSERT INTO #count2 SELECT  COUNT(a'+'.'+'job_id) Closeratiocount,' + '''report'''+
'FROM'+QUOTENAME(@Tenant)+'.'+'[job_details] a
join #TEMP as v ON a.referred_source=v.referred_source
where v'+ '.' + 'referred_source = (SELECT referred_source FROM  #TableVariable WHERE Id = '+ @k +')
and a'+'.'+'current_job_status in(' + '''Planning''' + ',' + '''Production''' + ',' + '''Invoice''' + ',' + '''Receivables''' + ',' + '''Closed''' + ')
and  a'+'.'+'job_type in(' + '''Reconstruction''' + ',' + '''Content''' + ',' + '''Asbestos''' + ','+ '''Structure Cleaning''' + ')
and  a.created_datetime BETWEEN'''+CONVERT(NVARCHAR(100),@StartDate,109)+'''and'''+CONVERT(NVARCHAR(100),@EndDate,109)+'''' 
EXEC (@SQL)

SET @SQL = N'INSERT INTO #CLOSERATIO SELECT DISTINCT v.referred_source'+','+'(FLOOR(COALESCE(
((b.closeratio1) * 100/NULLIF(a.closeratio1,0)),0))),b.closeratio1,a.closeratio1
 FROM'+QUOTENAME(@Tenant)+'.'+'[job_details] j join #TEMP as v ON j.referred_source=v.referred_source
join #count1 as a on a.rest_comp_location_id=J.rest_comp_location_id join 
#count2 as b ON a.purpose=b.purpose WHERE v.referred_source=(SELECT referred_source FROM  #TableVariable WHERE Id = '+ @k +')'     
EXEC (@SQL)
	  SET @k = @k + 1
END	  
IF(@Status=1)
BEGIN 
SELECT * FROM #CLOSERATIO
END

IF(@Status=2)
BEGIN 
DELETE FROM #CLOSERATIO WHERE [Files Sold]=0 and [Total Files]=0 and [Close Ratio]=0
SELECT * FROM #CLOSERATIO
END
END 

IF(@Type=2)

BEGIN
		 WHILE @k <= @tableLength 

BEGIN	 
	  
DROP TABLE IF EXISTS #count3
CREATE TABLE #count3(closeratio1 FLOAT,purpose VARCHAR(20),rest_comp_location_id VARCHAR(20))
SET @SQL = N'INSERT INTO #count3 SELECT  COUNT(a'+'.'+'job_id) Closeratiocount,' + '''report'''+ ',1
FROM '+QUOTENAME(@Tenant)+'.'+'[job_details] a
join #TEMP as v ON a.referred_source=v.referred_source
where v'+ '.' + 'referred_source = (SELECT referred_source FROM  #TableVariable WHERE Id = '+ @k +')
and  a'+'.'+'job_type in(' + '''Water''' + ',' + '''Board Up''' + ',' + '''Bio''' + ','+ '''Remediation'''+ ')
and  a.created_datetime BETWEEN'''+CONVERT(NVARCHAR(100),@StartDate,109)+'''and'''+CONVERT(NVARCHAR(100),@EndDate,109)+''''      
EXEC (@SQL)	

DROP TABLE IF EXISTS #count4
CREATE TABLE #count4(closeratio1 FLOAT,purpose VARCHAR(20))
SET @SQL = N'INSERT INTO #count4 SELECT  COUNT(a'+'.'+'job_id) Closeratiocount,' + '''report'''+
'FROM'+QUOTENAME(@Tenant)+'.'+'[job_details] a
join #TEMP as v ON a.referred_source=v.referred_source
where v'+ '.' + 'referred_source = (SELECT referred_source FROM  #TableVariable WHERE Id = '+ @k +')
and a'+'.'+'current_job_status not in(' +'''Rejected''' + ')
and  a'+'.'+'job_type in(' + '''Water''' + ',' + '''Board Up''' + ',' + '''Bio''' + ','+ '''Remediation'''+ ')
and  a.created_datetime BETWEEN'''+CONVERT(NVARCHAR(100),@StartDate,109)+'''and'''+CONVERT(NVARCHAR(100),@EndDate,109)+''''  
EXEC (@SQL)

SET @SQL = N'INSERT INTO #CLOSERATIO SELECT DISTINCT v.referred_source'+','+'(FLOOR(COALESCE(
((b.closeratio1) * 100/NULLIF(a.closeratio1,0)),0))),b.closeratio1,a.closeratio1
 FROM'+QUOTENAME(@Tenant)+'.'+'[job_details] j join #TEMP as v ON j.referred_source=v.referred_source
join #count3 as a on a.rest_comp_location_id=J.rest_comp_location_id join 
#count4 as b ON a.purpose=b.purpose WHERE v.referred_source=(SELECT referred_source FROM  #TableVariable WHERE Id = '+ @k +')'     
EXEC (@SQL)
	  SET @k = @k + 1
END	  
IF(@Status=1)
BEGIN 
SELECT * FROM #CLOSERATIO
END

IF(@Status=2)
BEGIN 
DELETE FROM #CLOSERATIO WHERE [Files Sold]=0 and [Total Files]=0 and [Close Ratio]=0
SELECT * FROM #CLOSERATIO
END
END 

END

GO

