DROP TABLE IF EXISTS #count1 
CREATE TABLE #count1(closeratio1 FLOAT,purpose VARCHAR(255),rest_comp_location_id VARCHAR(255))
SET @SQL = N'INSERT INTO #count1 SELECT  COUNT(a'+'.'+'job_id) Closeratiocount,' + '''report'''+ ',1
FROM '+QUOTENAME(@Tenant)+'.'+'[job_details] a
join #TEMP3 as v ON a'+ '.'+'job_id=v' +'.'+'job_id
where v'+ '.' + 'job_type = (SELECT job_type FROM  #TableVariable3 WHERE Id = '+ @k3 +')
and  a'+'.'+'job_type in(' + '''Water''' + ',' + '''Board Up''' + ',' + '''Bio''' + ','+ '''Remediation'''+ ')
and  datepart(yy,a.created_datetime) =year(getdate())'     
EXEC (@SQL)	

DROP TABLE IF EXISTS #count2
CREATE TABLE #count2(closeratio1 FLOAT,purpose VARCHAR(255))
SET @SQL = N'INSERT INTO #count2 SELECT  COUNT(a'+'.'+'job_id) Closeratiocount,' + '''report'''+
'FROM'+QUOTENAME(@Tenant)+'.'+'[job_details] a
join #TEMP3 as v ON a'+ '.'+'job_id=v' +'.'+'job_id
where v'+ '.' + 'job_type = (SELECT job_type FROM  #TableVariable3 WHERE Id = '+ @k3 +')
and a'+'.'+'current_job_status not in(' +'''Rejected''' + ')
and  a'+'.'+'job_type in(' + '''Water''' + ',' + '''Board Up''' + ',' + '''Bio''' + ','+ '''Remediation'''+ ')
and  datepart(yy,a.created_datetime) =year(getdate())' 
EXEC (@SQL)

 SET @SQL = N'INSERT INTO #CLOSERATIO3 SELECT DISTINCT v.job_type'+','+'(FLOOR(COALESCE(
((b.closeratio1) * 100/NULLIF(a.closeratio1,0)),0))),b.closeratio1,a.closeratio1
 FROM'+QUOTENAME(@Tenant)+'.'+'[job_details] j join #TEMP3 as v ON j.job_id=v.job_id
join #count1 as a on a.rest_comp_location_id=J.rest_comp_location_id join 
#count2 as b ON a.purpose=b.purpose WHERE v.job_type=(SELECT job_type FROM  #TableVariable3 WHERE Id = '+ @k3 +')'     
EXEC (@SQL)
	  SET @k3 = @k3 + 1
END	 

