DROP TABLE IF EXISTS #TEMP
CREATE TABLE #TEMP(job_id INT,[Sales Representative] NVARCHAR(200));

SET @SQL='SELECT job_id,[Sales Representative] FROM'++QUOTENAME(@Tenant)+'.'+'[v_roles]'

INSERT INTO #TEMP EXEC (@SQL)

DROP TABLE IF EXISTS #TableVariable
CREATE TABLE #TableVariable (Id INT IDENTITY(1,1), [Sales Representative] NVARCHAR(500))
INSERT INTO #TableVariable SELECT DISTINCT [Sales Representative] FROM #TEMP  WHERE [Sales Representative] not in (' ')

DROP TABLE IF EXISTS #CLOSERATIO
CREATE TABLE #CLOSERATIO ([Sales Rep] NVARCHAR(255),[Close Ratio] NVARCHAR(255),[Files Sold] NVARCHAR(255),[Total Files] NVARCHAR(255))
 

DECLARE @tableLength INT,@k NVARCHAR(255)

SELECT @tableLength = COUNT(Id) FROM #TableVariable

SET @k = 1


