FROM '+QUOTENAME(@Tenant)+'.'+'[job_details] a join #TEMP v on a.job_id=v.job_id
where v'+ '.' + '[Sales Representative] = (SELECT [Sales Representative] FROM  #TableVariable WHERE Id = '+ @k +')
and a'+'.'+'current_job_status in(' + '''Planning''' + ',' + '''Production''' + ',' + '''Invoice''' + ',' + '''Receivables''' + ',' + '''Closed''' +','+'''Rejected'''+')
and  a'+'.'+'job_type in(' + '''Reconstruction''' + ',' + '''Content''' + ',' + '''Asbestos''' + ','+ '''Structure Cleaning'''+ ') 
