((b.closeratio1) * 100/NULLIF(a.closeratio1,0)),0))),b.closeratio1,a.closeratio1
FROM'+QUOTENAME(@Tenant)+'.'+'[job_details] j join #TEMP v on j.job_id=v.job_id
