CREATE OR ALTER PROCEDURE [dbo].[usp_Load_Leads_ReferredBy] 
     (@Tenant NVARCHAR(90),@Group INT,@parameter1 NVARCHAR(500),@Dates INT)  --@TENANT(7) TO 15

AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	-- interfering with SELECT statements.
	SET NOCOUNT ON;
	--DECLARE @currentyear as currentdat;

    -- Insert statements for procedure here

DECLARE @SQL NVARCHAR(MAX)

DROP TABLE IF EXISTS #ReferredBy
CREATE TABLE #ReferredBy ([Sales Rep] NVARCHAR(50),Files INT,[Estimate Amount] FLOAT)

IF(@Group=1)--This option is used to populate the data for Leads report of SalesRep All 
BEGIN

IF(@Dates='1')---This date paramater is used to populate the data for Leads report of All records for current year

BEGIN

DROP TABLE IF EXISTS #count1 
CREATE TABLE #count1([sales representative] NVARCHAR(50),Files INT,Estimate_amount FLOAT)
SET @SQL = N'INSERT INTO #count1 SELECT Top 10 concat(u.contact_first_name,'' '',u.contact_last_name),Count(e.Job_id),Sum(e.estimated_amount)
FROM '+QUOTENAME(@Tenant)+'.'+'[job_estimate] e join'+QUOTENAME(@Tenant)+'.'+'[job_details] as j on e.job_id=j.job_id 
join'++QUOTENAME(@Tenant)+'.'+'[job_contacts] as c on c.job_id=j.job_id join'+QUOTENAME(@Tenant)+'.'+'contact_details as u on u.contact_id=c.contact_id
where c.contact_work_type=''Referred By'' and datepart(yy,j.created_datetime) =year(getdate()) group by concat(u.contact_first_name,'' '',u.contact_last_name) order by Count(e.Job_id) desc' 
EXEC (@SQL)

SET @SQL = N'INSERT INTO #ReferredBy SELECT [sales representative],Files,(Estimate_amount)
FROM  #count1'
EXEC (@SQL)

SELECT * FROM #ReferredBy where [Sales Rep] not in (' ')
END

