DROP TABLE IF EXISTS #count12 
CREATE TABLE #count12([sales representative] NVARCHAR(50),Files INT,Estimate_amount FLOAT)
SET @SQL = N'INSERT INTO #count12 SELECT Top 10 concat(u.contact_first_name,'' '',u.contact_last_name),Count(e.Job_id),Sum(e.estimated_amount)
FROM '+QUOTENAME(@Tenant)+'.'+'[job_estimate] e join'+QUOTENAME(@Tenant)+'.'+'[job_details] as j on e.job_id=j.job_id 
join'++QUOTENAME(@Tenant)+'.'+'[job_contacts] as c on c.job_id=j.job_id join'+QUOTENAME(@Tenant)+'.'+'contact_details as u on u.contact_id=c.contact_id 
join'++QUOTENAME(@Tenant)+'.'+'[v_roles] as v on v.job_id=j.job_id
where c.contact_work_type=''Referred By'' and v.Estimator='''+@parameter1+''' and j.created_datetime >= DATEADD(DAY, -90, GETDATE())
group by concat(u.contact_first_name,'' '',u.contact_last_name) order by Count(e.Job_id) desc' 
EXEC (@SQL)

SET @SQL = N'INSERT INTO #ReferredBy SELECT [sales representative],Files,(Estimate_amount)
FROM  #count12'
EXEC (@SQL)

SELECT * FROM #ReferredBy where [Sales Rep] not in (' ')
END

