SET @SQL = N'INSERT INTO #count17 SELECT j.referred_source,Count(e.Job_id),Sum(e.estimated_amount)
FROM '+QUOTENAME(@Tenant)+'.'+'[job_estimate] e
join'+QUOTENAME(@Tenant)+'.'+'[job_details] as j on e.job_id=j.job_id join'+QUOTENAME(@Tenant)+'.'+'[v_roles] as v on v.job_id=j.job_id
where v.[sales representative]='''+@parameter1+'''
and  j.created_datetime >= DATEADD(DAY, -90, GETDATE()) group by j.referred_source' 
EXEC (@SQL)

SET @SQL = N'INSERT INTO #ReferredSource SELECT referred_source,Files,(Estimate_amount)
FROM  #count17'
EXEC (@SQL)

SELECT * FROM #ReferredSource 
END

