-- =============================================
-- Stored Procedure: [dbo].[usp_Load_Parameter1List]
-- Repeatable Migration - Re-runs when content changes
-- =============================================
CREATE OR ALTER PROCEDURE [dbo].[usp_Load_Parameter1List] 
	-- Add the parameters for the stored procedure here
			(@Tenant varchar(15),@Parameter NVARCHAR(200))
			--@TENANT(7) TO 15
AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	-- interfering with SELECT statements.
	SET NOCOUNT ON;

	DECLARE @SQL VARCHAR(MAX)
	    
		SET @SQL = N' with cte5 as ( select ''All Records'' as [config_name],''null'' as [config_value])
	, cte as (
    Select distinct ''By Estimator'' as [config_name],v.[Estimator] as [config_value]
    From '+ QUOTENAME(@Tenant)+'.'+'v_roles as v join'+ QUOTENAME(@Tenant)+'.'+'job_estimate as e on v.job_id=e.job_id join '+ QUOTENAME(@Tenant)+'.'+'job_details as j on j.job_id=e.job_id
	)
    ,cte1 as(
	 Select distinct ''By Sales Rep'' as [config_name],v.[Sales Representative] as [config_value]
    From '+ QUOTENAME(@Tenant)+'.'+'v_roles as v join '+ QUOTENAME(@Tenant)+'.'+'job_estimate as e on v.job_id=e.job_id join '+ QUOTENAME(@Tenant)+'.'+'job_details as j on j.job_id=e.job_id
	)
	,cte2 as(
	 Select distinct ''By Supervisor'' as [config_name],v.[Supervisor] as [config_value]
     From '+ QUOTENAME(@Tenant)+'.'+'v_roles as v join '+ QUOTENAME(@Tenant)+'.'+'job_estimate as e on v.job_id=e.job_id join '+ QUOTENAME(@Tenant)+'.'+'job_details as j on j.job_id=e.job_id
	)
	,cte3 as(
	 Select distinct ''By Insurance Company'' as [config_name],i.[Insurance_company_name] as [config_value] 
   From '+ QUOTENAME(@Tenant)+'.'+'job_insurance_details as i join '+ QUOTENAME(@Tenant)+'.'+'job_estimate as e on i.job_id=e.job_id join '+ QUOTENAME(@Tenant)+'.'+'job_details as j on j.job_id=e.job_id
	)
	,cte4 as(
	Select [config_name], [config_value] from cte5 
	Union all 
    Select [config_name], [config_value] from cte where [config_value] not in ('+''' '''+') 
    Union all
    Select [config_name], [config_value] from cte1 where [config_value] not in ('+''' '''+')
	Union all
    Select [config_name], [config_value] from cte2 where [config_value] not in ('+''' '''+') 
	Union all
    Select [config_name], [config_value] from cte3 where [config_value] not in ('+''' '''+') 
	Union all
	Select ''By Division'' as [config_name],[config_value] from '+ QUOTENAME(@Tenant)+'.'+'m_config_data where [config_name]=''Job Type'' 
	Union all
	Select ''By Referred Source'' as [config_name],[config_value] from '+ QUOTENAME(@Tenant)+'.'+'m_config_data m join '+ QUOTENAME(@Tenant)+'.'+'job_details j  on m.[config_value]=j.referred_source join 
	'+ QUOTENAME(@Tenant)+'.'+'job_estimate as e on j.job_id=e.job_id  where [config_name]=''Referred Source'') 


	select distinct [config_value] from cte4 where [config_name] in ('''+@Parameter+''') order by [config_value] asc'

     EXEC (@SQL)
	
	DROP TABLE IF EXISTS #CarrierList1
	CREATE TABLE #CarrierList1 (config_value varchar(200));
	--insert into CarrierList values (@SQL)
	insert into #CarrierList1 exec(@SQL)
	select * from #CarrierList1


   -- END


END

GO

