-- =============================================
-- Stored Procedure: [dbo].[usp_Load_TotalEstimatesWrittenSold_All]
-- Repeatable Migration - Re-runs when content changes
-- =============================================
CREATE OR ALTER PROCEDURE [dbo].[usp_Load_TotalEstimatesWrittenSold_All] 
     (@Tenant NVARCHAR(15),@Dates INT)  --@TENANT(7) TO 15

AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	-- interfering with SELECT statements.
	SET NOCOUNT ON;
	--DECLARE @currentyear as currentdat;

    -- Insert statements for procedure here

DECLARE @SQL NVARCHAR(MAX)

DROP TABLE IF EXISTS #WrittenSold
CREATE TABLE #WrittenSold ([All Records] NVARCHAR(500),[Total Estimates Written] FLOAT,[Total Estimates Sold] FLOAT)

DROP TABLE IF EXISTS #WrittenSold1
CREATE TABLE #WrittenSold1 (Estimator NVARCHAR(20),[Total Estimates Written] FLOAT,[Total Estimates Sold] FLOAT)

DROP TABLE IF EXISTS #WrittenSold2
CREATE TABLE #WrittenSold2 (Supervisor NVARCHAR(20),[Total Estimates Written] FLOAT,[Total Estimates Sold] FLOAT)

DROP TABLE IF EXISTS #WrittenSold3
CREATE TABLE #WrittenSold3 ([Sales Rep] NVARCHAR(20),[Total Estimates Written] FLOAT,[Total Estimates Sold] FLOAT)

DROP TABLE IF EXISTS #WrittenSold4
CREATE TABLE #WrittenSold4 ([Insurance Company] NVARCHAR(500),[Total Estimates Written] FLOAT,[Total Estimates Sold] FLOAT)

DROP TABLE IF EXISTS #WrittenSold5
CREATE TABLE #WrittenSold5 ([Referred Source] NVARCHAR(500),[Total Estimates Written] FLOAT,[Total Estimates Sold] FLOAT)

IF(@Dates='1')---This date paramater is used to populate the data for total estimates written & sold for current year

BEGIN

SET @SQL = N' with cte1 as(

SELECT j.job_type,sum(e.estimated_amount) ''Total Estimates Written'' FROM'+QUOTENAME(@Tenant)+'.'+'job_estimate as e join'+QUOTENAME(@Tenant)+'.'+'job_details as j
on e.job_id=j.job_id 
where datepart(yy,j.created_datetime) =year(getdate())and  j.job_type  not in ('' '') group by j.job_type),
cte2 as(
SELECT j.job_type,sum(e.estimated_amount) ''Total Estimates Sold'' FROM'+QUOTENAME(@Tenant)+'.'+'job_estimate as e join'+QUOTENAME(@Tenant)+'.'+'job_details as j 
on e.job_id=j.job_id join'+QUOTENAME(@Tenant)+'.'+'common_milestones m on m.source_id=j.job_id
where datepart(yy,j.created_datetime) =year(getdate()) and m.dateofWorkAuthorization is not null  and  j.job_type  not in ('' '') group by j.job_type)

Insert into #WrittenSold
select cte1.job_type,cte1.[Total Estimates Written],cte2.[Total Estimates Sold] from cte1 join cte2 on cte1.job_type=cte2.job_type'    
EXEC (@SQL)	

SET @SQL = N' with cte1 as(

SELECT v.Estimator,sum(e.estimated_amount) ''Total Estimates Written'' FROM'+QUOTENAME(@Tenant)+'.'+'job_estimate as e join'+QUOTENAME(@Tenant)+'.'+'job_details as j
on e.job_id=j.job_id join'+QUOTENAME(@Tenant)+'.'+'v_roles as v on v.job_id=j.job_id
where datepart(yy,j.created_datetime) =year(getdate())and  v.Estimator not in ('' '') group by v.Estimator),
cte2 as(
SELECT v.Estimator,sum(e.estimated_amount) ''Total Estimates Sold'' FROM'+QUOTENAME(@Tenant)+'.'+'job_estimate as e join'+QUOTENAME(@Tenant)+'.'+'job_details as j 
on e.job_id=j.job_id join'+QUOTENAME(@Tenant)+'.'+'v_roles as v on v.job_id=j.job_id join'+QUOTENAME(@Tenant)+'.'+'common_milestones m on m.source_id=j.job_id
where datepart(yy,j.created_datetime) =year(getdate()) and m.dateofWorkAuthorization is not null  and  v.Estimator not in ('' '') group by v.Estimator)

Insert into #WrittenSold1
select cte1.Estimator,cte1.[Total Estimates Written],cte2.[Total Estimates Sold] from cte1 join cte2 on cte1.Estimator=cte2.Estimator'    
EXEC (@SQL)	

SET @SQL = N' with cte1 as(

SELECT v.Supervisor,sum(e.estimated_amount) ''Total Estimates Written'' FROM'+QUOTENAME(@Tenant)+'.'+'job_estimate as e join'+QUOTENAME(@Tenant)+'.'+'job_details as j
on e.job_id=j.job_id join'+QUOTENAME(@Tenant)+'.'+'v_roles as v on v.job_id=j.job_id
where datepart(yy,j.created_datetime) =year(getdate()) and v.Supervisor not in ('' '') group by v.Supervisor),
cte2 as(
SELECT v.Supervisor,sum(e.estimated_amount) ''Total Estimates Sold'' FROM'+QUOTENAME(@Tenant)+'.'+'job_estimate as e join'+QUOTENAME(@Tenant)+'.'+'job_details as j 
on e.job_id=j.job_id join'+QUOTENAME(@Tenant)+'.'+'v_roles as v on v.job_id=j.job_id join'+QUOTENAME(@Tenant)+'.'+'common_milestones m on m.source_id=j.job_id
where datepart(yy,j.created_datetime) =year(getdate()) and m.dateofWorkAuthorization is not null  and  v.Supervisor not in ('' '') group by v.Supervisor)

Insert into #WrittenSold2
select cte1.Supervisor,cte1.[Total Estimates Written],cte2.[Total Estimates Sold] from cte1 join cte2 on cte1.Supervisor=cte2.Supervisor'    
EXEC (@SQL)

SET @SQL = N' with cte1 as(

SELECT v.[Sales Representative],sum(e.estimated_amount) ''Total Estimates Written'' FROM'+QUOTENAME(@Tenant)+'.'+'job_estimate as e join'+QUOTENAME(@Tenant)+'.'+'job_details as j
on e.job_id=j.job_id join'+QUOTENAME(@Tenant)+'.'+'v_roles as v on v.job_id=j.job_id
where datepart(yy,j.created_datetime) =year(getdate())and  v.[Sales Representative] not in ('' '') group by v.[Sales Representative]),
cte2 as(
SELECT v.[Sales Representative],sum(e.estimated_amount) ''Total Estimates Sold'' FROM'+QUOTENAME(@Tenant)+'.'+'job_estimate as e join'+QUOTENAME(@Tenant)+'.'+'job_details as j 
on e.job_id=j.job_id join'+QUOTENAME(@Tenant)+'.'+'v_roles as v on v.job_id=j.job_id join'+QUOTENAME(@Tenant)+'.'+'common_milestones m on m.source_id=j.job_id
where datepart(yy,j.created_datetime) =year(getdate()) and m.dateofWorkAuthorization is not null  and  v.[Sales Representative] not in ('' '') group by v.[Sales Representative])

Insert into #WrittenSold3
select cte1.[Sales Representative],cte1.[Total Estimates Written],cte2.[Total Estimates Sold] from cte1 join cte2 on cte1.[Sales Representative]=cte2.[Sales Representative]'    
EXEC (@SQL)

SET @SQL = N' with cte1 as(

SELECT i.insurance_company_name,sum(e.estimated_amount) ''Total Estimates Written'' FROM'+QUOTENAME(@Tenant)+'.'+'job_estimate as e join'+QUOTENAME(@Tenant)+'.'+'job_details as j
on e.job_id=j.job_id join'+QUOTENAME(@Tenant)+'.'+'job_insurance_details as i on i.job_id=j.job_id 
where datepart(yy,j.created_datetime) =year(getdate()) and  i.insurance_company_name not in ('' '') group by i.insurance_company_name),
cte2 as(
SELECT i.insurance_company_name,sum(e.estimated_amount) ''Total Estimates Sold'' FROM'+QUOTENAME(@Tenant)+'.'+'job_estimate as e join'+QUOTENAME(@Tenant)+'.'+'job_details as j 
on e.job_id=j.job_id join'+QUOTENAME(@Tenant)+'.'+'job_insurance_details as i on i.job_id=j.job_id join'+QUOTENAME(@Tenant)+'.'+'common_milestones m on m.source_id=j.job_id
where datepart(yy,j.created_datetime) =year(getdate()) and m.dateofWorkAuthorization is not null  and  i.insurance_company_name not in ('' '') group by i.insurance_company_name)

Insert into #WrittenSold4
select cte1.insurance_company_name,cte1.[Total Estimates Written],cte2.[Total Estimates Sold] from cte1 join cte2 on cte1.insurance_company_name=cte2.insurance_company_name'    
EXEC (@SQL)	

SET @SQL = N' with cte1 as(

SELECT f.config_value,sum(e.estimated_amount) ''Total Estimates Written'' FROM'+QUOTENAME(@Tenant)+'.'+'job_estimate as e join'+QUOTENAME(@Tenant)+'.'+'job_details as j
on e.job_id=j.job_id join'+QUOTENAME(@Tenant)+'.'+'m_config_data as f on f.config_value=j.referred_source
where datepart(yy,j.created_datetime) =year(getdate()) and f.config_name=''Referred Source'' and  f.config_value not in ('' '') group by f.config_value),
cte2 as(
SELECT f.config_value,sum(e.estimated_amount) ''Total Estimates Sold'' FROM'+QUOTENAME(@Tenant)+'.'+'job_estimate as e join'+QUOTENAME(@Tenant)+'.'+'job_details as j 
on e.job_id=j.job_id join'+QUOTENAME(@Tenant)+'.'+'m_config_data as f on f.config_value=j.referred_source join'+QUOTENAME(@Tenant)+'.'+'common_milestones m on m.source_id=j.job_id
where datepart(yy,j.created_datetime) =year(getdate()) and f.config_name=''Referred Source'' and m.dateofWorkAuthorization is not null  and f.config_value not in ('' '') group by f.config_value)

Insert into #WrittenSold5
select cte1.config_value,cte1.[Total Estimates Written],cte2.[Total Estimates Sold] from cte1 join cte2 on cte1.config_value=cte2.config_value'    
EXEC (@SQL)
SELECT * FROM #WrittenSold 
UNION ALL
SELECT * FROM #WrittenSold1 
UNION ALL
SELECT * FROM #WrittenSold2 
UNION ALL
SELECT * FROM #WrittenSold3
UNION ALL
SELECT * FROM #WrittenSold4
UNION ALL
SELECT * FROM #WrittenSold5  	
END 

ELSE IF(@Dates='2')	---This date paramater is used to populate the data for total estimates written & sold for last year

BEGIN

SET @SQL = N' with cte1 as(

SELECT j.job_type,sum(e.estimated_amount) ''Total Estimates Written'' FROM'+QUOTENAME(@Tenant)+'.'+'job_estimate as e join'+QUOTENAME(@Tenant)+'.'+'job_details as j
on e.job_id=j.job_id 
where datepart(yy,j.created_datetime) =year(DATEADD(year,-1,getdate())) and  j.job_type  not in ('' '') group by j.job_type),
cte2 as(
