on e.job_id=j.job_id join'+QUOTENAME(@Tenant)+'.'+'common_milestones m on m.source_id=j.job_id
where datepart(yy,j.created_datetime) =year(DATEADD(year,-1,getdate())) and m.dateofWorkAuthorization is not null  and  j.job_type  not in ('' '') group by j.job_type)

