EXEC (@SQL)	

SET @SQL = N' with cte1 as(

SELECT v.Supervisor,sum(e.estimated_amount) ''Total Estimates Written'' FROM'+QUOTENAME(@Tenant)+'.'+'job_estimate as e join'+QUOTENAME(@Tenant)+'.'+'job_details as j
