Insert into #WrittenSold
select cte1.config_value,cte1.[Total Estimates Written],cte2.[Total Estimates Sold] from cte1 join cte2 on cte1.config_value=cte2.config_value'    
EXEC (@SQL)	
SELECT * FROM #WrittenSold 



END 






