DECLARE @i int
SET @i=1
SET @list=(SELECT COUNT([SCHEMA_NAME]) FROM [common].[rest_comp_details] WHERE REST_COMP_ID IN
(SELECT contractor FROM [common].[association] where host=@Franchisor))

DECLARE @list1 nvarchar(MAX)
DECLARE @i1 int
SET @i1=1
SET @list1=(SELECT COUNT([SCHEMA_NAME]) FROM [common].[rest_comp_details] WHERE REST_COMP_ID IN
(SELECT contractor FROM [common].[association] where host=@Franchisor))

DECLARE @list2 nvarchar(MAX)
DECLARE @i2 int
SET @i2=1
