(SELECT contractor FROM [common].[association] where host=@Franchisor))

SET @franchisorSchema = (SELECT [SCHEMA_NAME] FROM [common].[rest_comp_details] WHERE REST_COMP_ID = @Franchisor )

DROP TABLE IF EXISTS #temp
CREATE TABLE #temp(row_id INT,REST_COMP_ID INT,[SCHEMA_NAME] NVARCHAR(100))
INSERT INTO #temp
SELECT ROW_NUMBER() OVER (ORDER BY REST_COMP_ID ),REST_COMP_ID,[SCHEMA_NAME] FROM [common].[rest_comp_details] WHERE REST_COMP_ID IN
(SELECT contractor FROM [common].[association] where host=@Franchisor)

SET @SQL2=N'CREATE OR ALTER VIEW ['+@franchisorSchema+'].[opportunity_master_jobs_view]
WITH SCHEMABINDING

As

SELECT ROW_NUMBER() OVER (order by t.masterCreatedDate desc) AS id,t.opportunityCode,t.opportunityName,t.opportunityId,t.opportunityHashCode,t.contractor,t.opportunityStatus,t.opportunityReceivedDate,t.restCompAuthToken,
t.mastNumId,
t.mastName,
t.mastNumHash,
t.mastNumCode,
t.jobId,
t.jobHash,
t.jobCode,
t.jobName,
t.firstName,
t.lastName,
t.email,
t.mobile,
t.workPhone,
t.phone1,
t.customerType,
t.customerCompany,
t.customerCompanyName,
t.masterJobReceivedDate,
t.address,
t.city,
t.state,
t.zip,
t.company,
t.masterCreatedDate,
t.jobLossAddress,
t.jobType,
t.jobCreatedDate,
t.jobStatus,
t.mastStatus,
t.lossDate,
t.mastSalesRep,
t.mastReferredBy,
t.supervisor,
t.estimator,
t.coordinator,
t.finalInvoiceDate,
t.estimate,
t.estimatedAmount,
t.jobCity,
t.jobState,
t.jobZip,
t.jobCustomerType,
t.jobCustomerCompanyName,
t.jobCompany,
t.jobFirstName,
t.jobLastName,
t.unitNumber,
t.phone
 from (
'

SET @SQL=''
While(@i<=@list)

BEGIN

SET @tenant=(SELECT [SCHEMA_NAME] FROM #temp WHERE row_id=@i)

SET @SQL=@SQL+'select o.[opportunity_code] AS opportunityCode,o.[opportunity_name] AS opportunityName,o.[actual_opportunity_id] as opportunityId,
fo.opportunity_hash_code as opportunityHashCode,
(select rest_comp_name from common.rest_comp_details where schema_name='''+@tenant+''') as contractor,
o.opportunity_received_date as opportunityReceivedDate,(select rest_comp_auth_token from common.rest_comp_details where schema_name='''+@tenant+''') as restCompAuthToken,
fo.current_opportunity_status as opportunityStatus,
m.mast_num_id as mastNumId,m.master_name as mastName,m.mast_num_hash as mastNumHash,m.mast_num_code as mastNumCode,
j.job_id as jobId,j.job_hash_code as jobHash,j.job_code as jobCode,j.job_name as jobName,
m.first_name as firstName,m.last_name as lastName,m.email,m.mobile,m.work_phone as workPhone,m.phone1, m.customer_type as customerType,m.customer_company as customerCompany,
m.customer_company_name as customerCompanyName,m.loss_date as masterJobReceivedDate,m.loss_address as address,
m.loss_address_city as city,m.loss_address_state as state,m.loss_address_zip as zip,m.company as company,
m.created_datetime as masterCreatedDate,j.loss_address as jobLossAddress,j.job_type as jobType,
j.created_datetime as jobCreatedDate,j.current_job_status as jobStatus,m.status as mastStatus,m.loss_date as lossDate,

m.salesRepresentative as mastSalesRep,
CASE
WHEN m.referred_type =''Organization'' THEN
(select e.external_agency_name from '+@tenant+'.external_agency_details e where e.external_agency_id=m.referred_by)
when m.referred_type =''People'' THEN
(select Top 1 c.contact_first_name+'' ''+c.contact_last_name from '+@tenant+'.contact_details c where c.contact_id=m.referred_by)
ELSE
m.referred_by
end
as mastReferredBy,
(select u.first_name+'' ''+u.last_name from '+@tenant+'.user_user_details u where u.user_id=(select jr.user_id from '+@tenant+'.job_roles jr
where jr.job_id=j.job_id and jr.role_name=''Supervisor'')) As supervisor,
(select u.first_name+'' ''+u.last_name from '+@tenant+'.user_user_details u where u.user_id=(select jr.user_id from '+@tenant+'.job_roles jr
where jr.job_id=j.job_id and jr.role_name=''Estimator'')) As estimator,

(select u.first_name+'' ''+u.last_name from '+@tenant+'.user_user_details u where u.user_id=(select jr.user_id from '+@tenant+'.job_roles jr
where jr.job_id=j.job_id and jr.role_name=''Coordinator'')) As coordinator,
(SELECT TOP 1 m.final_invoice_date from '+@tenant+'.common_milestones m where j.job_id =(select max(m.source_id) from '+@tenant+'.common_milestones m)) As finalInvoiceDate,
case when (select count(*) from '+@tenant+'.job_estimate e where e.job_id=j.job_id)>0 then ''Yes'' else ''No'' end as estimate,
case when (select count(*) from '+@tenant+'.job_estimate e where e.job_id=j.job_id)>0 then (select sum(e.estimated_amount) from '+@tenant+'.job_estimate e where e.job_id=j.job_id) else 0 end as estimatedAmount
,j.loss_address_city as jobCity,j.loss_address_state as jobState,j.loss_address_zip as jobZip,j.customer_type AS jobCustomerType,j.customer_company_name AS jobCustomerCompanyName,j.company as jobCompany,
 j.first_name As jobFirstName, j.last_name As jobLastName,j.unit_number as unitNumber,r.rest_comp_phone_number1 as phone
from '+@tenant+'.mast_num_details m
left join '+@tenant+'.job_details j on j.mast_num_id=m.mast_num_id
INNER JOIN '+@tenant+'.[opportunity_details] AS o on m.opportunity_id = o.opportunity_id
INNER JOIN '+@franchisorSchema+'.[opportunity_details] AS fo on fo.opportunity_id = o.actual_opportunity_id
LEFT JOIN [common].[rest_comp_details] AS r on r.rest_comp_id=fo.association_id
and CONVERT(VARCHAR(8), j.created_datetime, 112)>CONVERT(VARCHAR(8), ''2017-01-01 00:00:00'', 112)
and CONVERT(VARCHAR(8), m.created_datetime, 112)>CONVERT(VARCHAR(8), ''2017-01-01 00:00:00'', 112) and m.status !=''Deleted'''

IF(@i1<@list1)

BEGIN

SET @SQL = @SQL+'

UNION

'
--print @SQL
SET @i1=@i1+1

END

SET @i=@i+1

END

SET @SQL3=@SQL2+@SQL+') AS T'

PRINT @SQL3 ;
EXEC (@SQL3)
--EXEC(@SQL3)
END
GO

