-- =============================================
-- Stored Procedure: [dbo].[Get_Opportunity_Tasks]
-- Repeatable Migration - Re-runs when content changes
-- =============================================
CREATE OR ALTER PROCEDURE [dbo].[Get_Opportunity_Tasks]
(@Tenant VARCHAR(90),@sourceCategory VARCHAR(90),@opportunityId NVARCHAR(100))
AS
DECLARE @SQL VARCHAR(MAX)
SET @SQL=N';
select c.task_id As taskId,c.task_title AS taskTitle,c.assigned_to AS assignTo,c.assigned_to_role AS assignToRole,c.expected_start_datetime AS expectedStartDatetime,
c.expected_end_datetime AS expectedEndDatetime,c.actual_start_datetime AS actualStartDatetime,c.actual_end_datetime AS actualEndDatetime,c.assign_type AS assignType,c.status as status,
Case when c.assign_type =''Division'' then
     (select division_name from '+QUOTENAME(@Tenant)+'.'+'m_divisions m where m.division_id=c.assigned_to and m.status = ''Active'')
     when  c.assign_type =''Role'' then
     (select role_name from '+QUOTENAME(@Tenant)+'.'+'m_roles r where r.role_id=c.assigned_to and r.status = ''Active'')
     else 
     NULL
END  AS ownerName,c.closed_reason AS closedReason,c.delay_reason AS delayReason,c.comments AS comments,c.time_to_complete AS timeToComplete,c.time_uom AS timeUom,
c.task_approval_status AS taskApprovalStatus,c.action_required AS actionRequired,c.action_type AS actionType,c.action_value AS actionValue,c.event_type AS eventType,
c.rejected_reason As rejectedReason,c.previous_status AS previousStatus,
c.trigger_event AS triggerEvent,c.mark_milestone AS markMilestone,c.action_required_doc_type AS actionRequiredDocType,c.task_sequence as taskSequence,
c.contingent_task_yes AS contingentTaskYes,c.contingent_task_no AS contingentTaskNo,c.task_desc AS description,
c.change_corporate_status_upon_completion as changeCorporateStatusUponCompletion,
c.change_status_upon_completion as changeStatusUponCompletion,
c.assignment_notification as assignmentNotification,c.icon_id,c.previous_or_simultaneously_task   
from '+QUOTENAME(@Tenant)+'.'+'common_tasks c
where c.source_id = '+ @opportunityId+'  and c.source='''+@sourceCategory+''' and c.assign_type!=''Corporate'' 
order by task_sequence '
EXEC (@SQL)
print  (@SQL)
GO

