-- Repeatable Migration - Re-runs when content changes
-- =============================================
CREATE OR ALTER PROCEDURE  [dbo].[opportunity_list_summary_by_status_java21]
(@tenant Varchar(100),@status Varchar(100))
As



DECLARE @SQL VARCHAR(MAX)
SET @SQL=N';
select ROW_NUMBER() OVER (ORDER BY CAST(o.created_datetime AS DATE) desc)  as id,
o.opportunity_id as opportunityId,o.opportunity_code as opportunityCode,o.opportunity_desc as opportunityDesc,
o.job_type as jobType,o.loss_address as lossAddress,o.loss_address_city as lossAddressCity,o.loss_address_state as lossAddressState,
o.loss_address_zip as lossAddressZip,o.billing_address as billingAddress,o.billing_address_city as billingAddressCity,o.billing_address_state as billingAddressState,
o.billing_address_zip as billingAddressZip,o.previous_opportunity_status as previousOpportunityStatus,o.current_opportunity_status as currentOpportunityStatus,
o.loss_date as lossDate,o.first_name as firstName,o.last_name as lastName,o.email as email,o.mobile as mobile,o.work_phone as workPhone,
o.phone as phone,o.customer_type as customerType,o.customer_company as customerCompany,o.customer_company_name as customerCompanyName,
o.company as company,o.company_id as companyId,o.opportunity_name as opportunityName,o.unit_number as unitNumber,o.communication_type as communicationType,
o.rooms_affected as roomsAffected,o.wage_rate as wageRate,o.billing_address_unit as billingAddressUnit,
(select rest_comp_name from common.rest_comp_details where rest_comp_id=o.association_id) as contractor,
o.created_datetime as createdDatetime,o.opportunity_received_date as opportunityReceivedDate,o.opportunity_hash_code as opportunityHashCode,
o.emergency_loss as emergencyLoss,(select top 1 job_hash_code from '+QUOTENAME(@Tenant)+'.'+'job_details j where j.opportunity_id=o.opportunity_id and j.job_type=o.job_type) as jobHashCode,
o.tpa_name as tpa,
o.tpa_category_name as tpaCategory,o.reference_file_number as referenceFileNumber,
(select rest_comp_phone_number1 from common.rest_comp_details where rest_comp_id=o.association_id) as restCompPhoneNumber1
from '+QUOTENAME(@tenant)+'.'+'opportunity_details o '
IF(@status='Unaccepted')
BEGIN
 SET @SQL = @SQL+' where o.current_opportunity_status IN(''New'',''Assigned'',''Rejected'')'
END


SET @SQL=@SQL+' order by o.created_datetime desc';




EXEC (@SQL)
print  (@SQL)
GO

