o.loss_date as lossDate,o.first_name as firstName,o.last_name as lastName,o.email as email,o.mobile as mobile,o.work_phone as workPhone,
o.phone as phone,o.customer_type as customerType,o.customer_company as customerCompany,o.customer_company_name as customerCompanyName,
o.company as company,o.company_id as companyId,o.opportunity_name as opportunityName,o.unit_number as unitNumber,o.communication_type as communicationType,
o.rooms_affected as roomsAffected,o.wage_rate as wageRate,o.billing_address_unit as billingAddressUnit,
(select rest_comp_name from common.rest_comp_details where rest_comp_id=o.association_id) as contractor,
o.created_datetime as createdDatetime,o.opportunity_received_date as opportunityReceivedDate,o.opportunity_hash_code as opportunityHashCode,
o.emergency_loss as emergencyLoss,(select top 1 job_hash_code from '+QUOTENAME(@Tenant)+'.'+'job_details j where j.opportunity_id=o.opportunity_id and j.job_type=o.job_type) as jobHashCode,';
IF(@Tenant='tenant119' or @Tenant='tenant108')
BEGIN
SET @SQL=@SQL+'o.tpa_name as tpa,
(select category_name from '+QUOTENAME(@Franchisor)+'.'+'external_agency_category ec where external_agency_category_id=o.tpa_category) as tpaCategory'
END
ELSE
BEGIN
SET @SQL=@SQL+'(select tpa_name from '+QUOTENAME(@Franchisor)+'.'+'opportunity_details fo where fo.opportunity_id=o.actual_opportunity_id) as tpa,
(select category_name from '+QUOTENAME(@Franchisor)+'.'+'external_agency_category ec where external_agency_category_id=
(select tpa_category from '+QUOTENAME(@Franchisor)+'.'+'opportunity_details fo where fo.opportunity_id=o.actual_opportunity_id)) as tpaCategory'
END

SET @SQL=@SQL+',o.reference_file_number as referenceFileNumber,(select top 1 current_job_status from '+QUOTENAME(@Tenant)+'.'+'job_details j where j.opportunity_id=o.opportunity_id and j.job_type=o.job_type) as currentJobStatus  from '+QUOTENAME(@Tenant)+'.'+'opportunity_details o where o.current_opportunity_status NOT IN(''Deleted'',''Rejected'')'

 


BEGIN
SET @SQL=@SQL+' order by o.created_datetime desc';
END

print  (@SQL)

EXEC (@SQL)
print  (@SQL)
GO

