CREATE OR ALTER PROCEDURE [dbo].[opportunity_status_update]
(
@Tenant VARCHAR(255),
@opportunity_id int,
@Comments VARCHAR(255),
@association_id int,
@Status VARCHAR(255),
@updateColumns NVARCHAR(255))



As
BEGIN



SET NOCOUNT ON;

DECLARE @SQL VARCHAR(MAX)



IF(@Status = 'Accepted')
BEGIN
SET @SQL=N'
update '+QUOTENAME(@Tenant)+'.'+'opportunity_details set current_opportunity_status ='''+@Status+''' '+@updateColumns+' where opportunity_id = '+CAST(@opportunity_id AS NVARCHAR(10))+';
update '+QUOTENAME(@Tenant)+'.'+'opportunity_assignment_details set status ='''+@Status+''',comments='''+@Comments+''' where opportunity_id = '+CAST(@opportunity_id AS NVARCHAR(10)) +' and contractor='+CAST(@association_id AS NVARCHAR(10));
SET @SQL = @SQL+'update '+QUOTENAME(@Tenant)+'.'+'job_details set current_job_status =''Deleted'' where opportunity_id = '+CAST(@opportunity_id AS NVARCHAR(10))+';
update '+QUOTENAME(@Tenant)+'.'+'mast_num_details set status =''Deleted'' where opportunity_id = '+CAST(@opportunity_id AS NVARCHAR(10))+';'
END
ELSE IF(@Status = 'Rejected')
BEGIN
SET @SQL=@SQL+'
update '+QUOTENAME(@Tenant)+'.'+'opportunity_details set current_opportunity_status ='''+@Status+''',rejection_reason='''+@Comments+''' '+@updateColumns+' where opportunity_id = '+CAST(@opportunity_id AS NVARCHAR(10))+';
update '+QUOTENAME(@Tenant)+'.'+'opportunity_assignment_details set status ='''+@Status+''',comments='''+@Comments+''' where opportunity_id = '+CAST(@opportunity_id AS NVARCHAR(10)) +' and contractor='+CAST(@association_id AS NVARCHAR(10));
END



EXEC (@SQL)




END
