-- =============================================
-- Stored Procedure: [dbo].[all_calendar_appointments_report_java21]
-- Repeatable Migration - Re-runs when content changes
-- =============================================
CREATE OR ALTER PROCEDURE [dbo].[all_calendar_appointments_report_java21]
    @Tenant VARCHAR(255),
    @startDate DATETIME,
    @endDate DATETIME
AS
BEGIN
    DECLARE @sql NVARCHAR(MAX);

    SET @sql = N'
    SELECT
        es.job_id AS jobId,
        es.status AS status,
        es.scratchpad AS scratchpad,
        es.schedule_date AS scheduleDate,
        es.arrival_time AS arrivalTime,
        es.expected_duration AS expectedDuration,
        es.created_datetime AS createdDatetime,
        es.updated_datetime AS updatedDatetime,
        es.type_of_visit AS typeOfVisit,
        es.schedule_start_date AS scheduleStartDate,
        es.schedule_end_date AS scheduleEndDate,
        es.event_occurrence AS eventOccurrence,
        es.title AS title,
        es.description AS description,
        es.location AS location,
        es.schedule_type AS scheduleType,
        es.all_day_event AS allDayEvent,
        es.source AS source,
        es.zapier_created_by AS zapierCreatedBy,
        es.calendar_type AS calendarType,
        es.email AS email,
        es.amount_budgeted AS amountBudgeted,
        es.amount_spent AS amountSpent,
        es.appointment_type AS appointmentType,
        es.activity_status AS activityStatus,
        jd.job_code AS FileNumber,

        ISNULL(ud.first_name, '''') + '' '' + ISNULL(ud.last_name, '''') AS Assignee,
        ISNULL(cud.first_name, '''') + '' '' + ISNULL(cud.last_name, '''') AS CreatedBy

    FROM ' + QUOTENAME(@Tenant) + '.ems_schedule AS es
    LEFT JOIN ' + QUOTENAME(@Tenant) + '.user_user_details AS cud
        ON es.created_by = cud.user_id
    JOIN ' + QUOTENAME(@Tenant) + '.ems_schedule_details AS esd
        ON esd.schedule_id = es.schedule_id
    LEFT JOIN ' + QUOTENAME(@Tenant) + '.user_user_details AS ud
        ON esd.technician_id = ud.user_id
    LEFT JOIN ' + QUOTENAME(@Tenant) + '.job_details AS jd
        ON es.job_id = jd.job_id

    WHERE jd.job_id IS NOT NULL
    AND es.status != ''Deleted''
    AND es.schedule_date BETWEEN ''' + CONVERT(NVARCHAR, @startDate) + ''' AND ''' + CONVERT(NVARCHAR, @endDate) + '''
    AND (esd.status != ''Deleted'' OR esd.status IS NULL)';

    EXEC(@sql);
END;
GO

GO
