WHERE es.created_by = ud.user_id and jd.job_id is not null 
and es.status != ''Deleted''  
and es.schedule_date BETWEEN  '''+CONVERT(nvarchar, @startDate)+''' AND '''+CONVERT(nvarchar, @endDate)+''''
