-- =============================================
-- Stored Procedure: [dbo].[all_notes_report]
-- Repeatable Migration - Re-runs when content changes
-- =============================================
CREATE OR ALTER PROCEDURE [dbo].[all_notes_report]
    @Tenant NVARCHAR(100),
    @startDate DATETIME,
    @endDate DATETIME
AS
BEGIN
    SET NOCOUNT ON;

    DECLARE @sql NVARCHAR(MAX);

    SET @sql = N'
        SELECT
            cn.mast_num_job_notes_id AS mastNumJobNotesId,
            cn.mast_num_id AS mastNumId,
            jd.job_code AS jobCode,
            jd.job_hash_code AS jobHashCode,
            cn.notes_category AS notesCategory,
            cn.notes AS notes,
            cn.notes_written_by AS notesWrittenBy,
            cn.written_datetime AS writtenDatetime,
            cn.updated_datetime AS updatedDatetime,
            cn.source AS source,
            cn.status AS status,
            cn.xa_sync_status AS xaSyncStatus
        FROM ' + @Tenant + '.common_notes cn
        LEFT JOIN ' + @Tenant + '.job_details jd
            ON cn.job_id = jd.job_id
        WHERE cn.written_datetime >= @StartDateParam
          AND cn.written_datetime <= @EndDateParam
          AND cn.status = ''Active''
        ORDER BY cn.written_datetime DESC;
    ';

    EXEC sp_executesql @sql,
        N'@StartDateParam DATETIME, @EndDateParam DATETIME',
        @StartDateParam = @startDate,
        @EndDateParam = @endDate;
END
GO

