-- =============================================
-- Stored Procedure: [dbo].[all_time_tracking_report]
-- Repeatable Migration - Re-runs when content changes
-- =============================================
CREATE OR ALTER PROCEDURE [dbo].[all_time_tracking_report]
    @Tenant Varchar(255), 
    @startDate Datetime, 
    @endDate Datetime
AS
BEGIN
    DECLARE @SQL NVARCHAR(MAX);
 
    SET @SQL = N'
    SELECT 
	 ROW_NUMBER() OVER (ORDER BY p.user_payroll_id) AS rowId,
	 p.user_payroll_id,
        p.shift_date AS shiftDate,
        p.clock_in_time AS clockInTime,
        p.clock_out_time AS clockOutTime,
        p.job_code AS jobCode,
        p.labor_type AS laborType,
        p.hour_type AS hourType,
        p.duration AS duration,
        p.hourly_rate AS hourlyRate,
        p.total_cost AS totalCost,
        p.created_datetime AS createdDatetime,
        p.updated_datetime AS updatedDatetime,
        p.source AS source,
        p.status AS status,
        p.additional_details AS additionalDetails,
        p.tsheet_user_id AS tsheetUserId,
        p.tsheet_user_name AS tsheetUserName,
        p.tsheet_job_code AS tsheetJobCode,
        p.tsheet_timezone AS tsheetTimezone,
        p.tsheet_id AS tsheetId,
        p.tsheet_jobcode_id AS tsheetJobcodeId,
        p.tsheet_approved_to AS tsheetApprovedTo,
        p.tsheet_submitted_to AS tsheetSubmittedTo,
        p.tsheet_update_flag AS tsheetUpdateFlag,
        p.tsheet_locked AS tsheetLocked,
        p.job_id AS jobId,
		(SELECT CONCAT(first_name, '' '', last_name) 
         FROM ' + QUOTENAME(@Tenant) + '.user_user_details 
         WHERE user_id = p.created_by) AS createdBy,
        (SELECT CONCAT(first_name, '' '', last_name) 
         FROM ' + QUOTENAME(@Tenant) + '.user_user_details 
         WHERE user_id = p.updated_by) AS updatedBy
    FROM 
        ' + QUOTENAME(@Tenant) + '.user_payroll_details p
    LEFT JOIN 
        ' + QUOTENAME(@Tenant) + '.user_user_details u
    ON 
        p.user_id = u.user_id
    WHERE
        p.shift_date  BETWEEN  '''+CONVERT(nvarchar, @startDate)+''' AND '''+CONVERT(nvarchar, @endDate)+'''AND p.status=''Active'' '
 
    EXEC sp_executesql @SQL, N'@startDate DATETIME, @endDate DATETIME', @startDate, @endDate;

END;
