AS
BEGIN
SET NOCOUNT ON;
DECLARE @tenant nvarchar(MAX)
DECLARE  @list nvarchar(MAX)
DECLARE  @i int
DECLARE @SQL VARCHAR(MAX)
SET @i=1
SET @list=(select count(contractor) from common.association where status='Active');
DROP TABLE IF EXISTS #temp
CREATE TABLE #temp(id int  identity(1,1), contractor nvarchar(255))
INSERT INTO #temp SELECT schema_name from common.rest_comp_details where rest_comp_id in(select contractor from common.association where status='Active')
while(@i<=@list)
BEGIN
SET @tenant=(select contractor from #temp where id=@i)
SET @SQL= N';
select u.user_name,u.first_name,u.last_name,(select rest_comp_name from '+QUOTENAME(@Tenant)+'.'+' rest_comp_details),u.last_signin from  '+QUOTENAME(@Tenant)+'.'+' user_user_details u where u.status=''Active''';
SET @i=@i+1
END
PRINT (@SQL)
EXEC (@SQL)
END
