      ,'+QUOTENAME(@Tenant)+'.'+'[job_estimate].[estimated_datetime]
      ,'+QUOTENAME(@Tenant)+'.'+'[job_estimate].[updated_by]
      ,'+QUOTENAME(@Tenant)+'.'+'[job_estimate].[updated_datetime]
  FROM '+QUOTENAME(@Tenant)+'.'+'[job_estimate]
  LEFT JOIN '+QUOTENAME(@Tenant)+'.'+'[job_details]
 ON '+QUOTENAME(@Tenant)+'.'+'[job_estimate].[job_id] = '+QUOTENAME(@Tenant)+'.'+'[job_details].[job_id]
 WHERE '+QUOTENAME(@Tenant)+'.'+'[job_estimate].[estimated_datetime] >=GETDATE() - 7
  ORDER BY [job_type]'
  EXEC(@SQL)
  PRINT(@SQL)
END
