-- Repeatable Migration - Re-runs when content changes
-- =============================================
CREATE OR ALTER PROCEDURE [dbo].[RevivalRestoration_WEEKLY_REPORTS] (@Tenant Varchar(255))
AS
DECLARE @SQL VARCHAR(MAX)
BEGIN
SET @SQL=N';
SELECT '+QUOTENAME(@Tenant)+'.'+'[job_details].[job_type],	
COUNT('+QUOTENAME(@Tenant)+'.'+'[job_estimate].[job_id]) AS ''Number of Estimates'',
FORMAT(SUM('+QUOTENAME(@Tenant)+'.'+'[job_estimate].[estimated_amount]),''c'',''en-US'') AS ''Estimated Amount''
FROM '+QUOTENAME(@Tenant)+'.'+'[job_estimate]
LEFT JOIN '+QUOTENAME(@Tenant)+'.'+'[job_details]
ON '+QUOTENAME(@Tenant)+'.'+'[job_estimate].[job_id] = '+QUOTENAME(@Tenant)+'.'+'[job_details].[job_id]
WHERE [estimated_datetime] >=GETDATE() - 7
GROUP BY '+QUOTENAME(@Tenant)+'.'+'[job_details].[job_type]';
EXEC (@SQL)
print(@SQL)
END
