CREATE OR ALTER PROCEDURE [dbo].[utlization_reports_java21]
(@Tenant Varchar(255))
As
Declare @SQL varchar(MAX)

Set @SQL=N';



select t.purchased_user,t.users_count,t.last_job_created_date,t.last_note_created_date,t.last_schedule_created_date,t.job_count ,t.notes_count,t.time_tracking_count,t.forms_count,t.task_count ,t.calender_count,t.sales_activity_count,t.contact_notes_count,t.organization_notes_count,t.encircle,t.cleanClaims,
t.quickbooksdesktop,t.quickbooksonline,t.zapier,t.pictureCount,t.recentPictureCount,t.companyCam,t.schemaName as tenantNumber from

((select count(user_id) as users_count,(select rest_comp_max_users from '+QUOTENAME(@Tenant)+'.rest_comp_details) as purchased_user,(select top 1 created_datetime from '+QUOTENAME(@Tenant)+'.[job_details] where job_id=(select max(job_id) from  '+QUOTENAME(@Tenant)+'.[job_details])) as last_job_created_date,
(select top 1 written_datetime from '+QUOTENAME(@Tenant)+'.[common_notes] where mast_num_job_notes_id=(select max(mast_num_job_notes_id) from  '+QUOTENAME(@Tenant)+'.[common_notes])) as last_note_created_date,
(select top 1 created_datetime from '+QUOTENAME(@Tenant)+'.[ems_schedule] where schedule_id=(select max(schedule_id) from  '+QUOTENAME(@Tenant)+'.[ems_schedule])) as last_schedule_created_date,
(select count(job_id) from '+QUOTENAME(@Tenant)+'.[job_details] where CONVERT(date,created_datetime)>=CONVERT(date, GETDATE()-30) and CONVERT(date,created_datetime)<=CONVERT(date, GETDATE())) as job_count,
(select count(mast_num_job_notes_id) from '+QUOTENAME(@Tenant)+'.[common_notes] where CONVERT(date,written_datetime)>=CONVERT(date, GETDATE()-30) and CONVERT(date,written_datetime)<=CONVERT(date, GETDATE())) as notes_count,
(select count(user_id) from '+QUOTENAME(@Tenant)+'.[user_payroll_details] where CONVERT(date,clock_in_time)>=CONVERT(date, GETDATE()-30) and CONVERT(date,clock_in_time)<=CONVERT(date, GETDATE())) as time_tracking_count,
(select count(form_transaction_id) from '+QUOTENAME(@Tenant)+'.[form_transactions] where CONVERT(date,created_datetime)>=CONVERT(date, GETDATE()-30) and CONVERT(date,created_datetime)<=CONVERT(date, GETDATE())) as forms_count,
(select count(task_id) from '+QUOTENAME(@Tenant)+'.[common_tasks] where status=''completed'' and CONVERT(date,updated_datetime)>=CONVERT(date, GETDATE()-30) and CONVERT(date,updated_datetime)<=CONVERT(date, GETDATE())) as task_count,
(select count(schedule_id) from '+QUOTENAME(@Tenant)+'.[ems_schedule] where CONVERT(date,created_datetime)>=CONVERT(date, GETDATE()-30) and CONVERT(date,created_datetime)<=CONVERT(date, GETDATE())) as calender_count,
(select count(sales_activity_id) from '+QUOTENAME(@Tenant)+'.[sales_activities] where CONVERT(date,updated_datetime)>=CONVERT(date, GETDATE()-30) and CONVERT(date,updated_datetime)<=CONVERT(date, GETDATE())) as sales_activity_count,
(select count(contact_notes_id) from '+QUOTENAME(@Tenant)+'.[contact_notes] where CONVERT(date,updated_datetime)>=CONVERT(date, GETDATE()-30) and CONVERT(date,updated_datetime)<=CONVERT(date, GETDATE())) as contact_notes_count,
(select count(external_agency_notes_id) from '+QUOTENAME(@Tenant)+'.[external_agency_notes] where CONVERT(date,updated_datetime)>=CONVERT(date, GETDATE()-30) and CONVERT(date,updated_datetime)<=CONVERT(date, GETDATE())) as organization_notes_count,
(select encircle_check from '+QUOTENAME(@Tenant)+'.rest_comp_details) as encircle,
(select cleanClaims_check from '+QUOTENAME(@Tenant)+'.rest_comp_details) as cleanClaims,
(select qb_check from '+QUOTENAME(@Tenant)+'.rest_comp_details) as quickbooksdesktop,
(select qbo_check from common.rest_comp_details where schema_name='''+@Tenant+''') as quickbooksonline,
(select zapier_check from common.rest_comp_details where schema_name='''+@Tenant+''') as zapier,
(select count(file_id) from '+QUOTENAME(@Tenant)+'.[common_file_details] where source=''Xcelerate'' and status=''Active'' and file_type=''Picture'') as pictureCount,
(select count(file_id) from '+QUOTENAME(@Tenant)+'.[common_file_details] where source=''Xcelerate'' and status=''Active'' and file_type=''Picture'' and CONVERT(date,uploaded_datetime)>=CONVERT(date, GETDATE()-30) and CONVERT(date,uploaded_datetime)<=CONVERT(date, GETDATE())) as recentPictureCount,';
SET @SQL=@SQL+'(select company_cam_check from common.rest_comp_details where schema_name='''+@Tenant+''') as companyCam,'''+@Tenant+''' as schemaName
from '+QUOTENAME(@Tenant)+'.[user_user_details] where status=''Active'')) AS  t'


EXEC (@SQL)
print(@SQL)
GO

