-- =============================================
-- Stored Procedure: [dbo].[wip_report]
-- Repeatable Migration - Re-runs when content changes
-- =============================================
CREATE OR ALTER PROCEDURE [dbo].[wip_report]
(@Tenant VARCHAR(90),@date DATE,@endDate Datetime=NULL,@Week INT=1)
AS
BEGIN

DECLARE @SQL VARCHAR(MAX);
SET @SQL=N';
SELECT 
	jd.job_id,
    jd.[job_code],
    jd.[job_name],
    jd.[job_type],
	jd.job_hash_code,
    jd.[current_job_status],
    round(jd.[total_estimates],2) As ''Total Estimates'',
    jd.[budget_gp_percentage] As ''Budget GP %'',
    round(sum(fi.[doc_amt]), 2) AS ''Total Invoiced'',
    round(sum(fp.[doc_amt]), 2) AS ''Total Payments'',
    ISNULL(round(sum(fc.[doc_amt]), 2),0) + ISNULL(round(sum(upd.[total_cost]), 2),0) AS ''Total Costs'',
	(select location_code from '+QUOTENAME(@Tenant)+'.'+'rest_comp_location where rest_comp_location_id=jd.rest_comp_location_id) AS location
FROM 
    '+QUOTENAME(@Tenant)+'.'+'[job_details] jd
LEFT JOIN 
    (
        SELECT [file_number], round(sum([doc_amt]), 2) AS [doc_amt]
        FROM '+QUOTENAME(@Tenant)+'.'+'[file_invoice]
        WHERE [doc_type] = ''Invoice'' AND [doc_date] < '''+CONVERT(nvarchar, @date)+'''
        GROUP BY [file_number]
    ) fi ON jd.[job_code] = fi.[file_number]
LEFT JOIN 
    (
        SELECT [file_number], round(sum([doc_amt]), 2) AS [doc_amt]
        FROM '+QUOTENAME(@Tenant)+'.'+'[file_invoice]
        WHERE [doc_type] IN(''Payments'',''Payment'') AND [doc_date] < '''+CONVERT(nvarchar, @date)+'''
        GROUP BY [file_number]
    ) fp ON jd.[job_code] = fp.[file_number]
LEFT JOIN 
    (
        SELECT [job_code], round(sum([total_cost]), 2) AS [total_cost]
        FROM '+QUOTENAME(@Tenant)+'.'+'[user_payroll_details]
        WHERE clock_out_time < '''+CONVERT(nvarchar, @date)+'''
        GROUP BY [job_code]
    ) upd ON jd.[job_code] = upd.[job_code]
LEFT JOIN 
    (
        SELECT [file_number], round(sum([doc_amt]), 2) AS [doc_amt]
        FROM '+QUOTENAME(@Tenant)+'.'+'[file_cost]
        WHERE [transaction_date] < '''+CONVERT(nvarchar, @date)+'''
        GROUP BY [file_number]
    ) fc ON jd.[job_code] = fc.[file_number]
WHERE jd.[current_job_status] NOT IN(''Rejected'',''Closed'',''New'',''Sales'',''Deleted'')

GROUP BY 
	jd.[job_id],
    jd.[job_code],
    jd.[job_name],
    jd.[job_type],
	jd.[job_hash_code],
    jd.[current_job_status],
    jd.[total_estimates],
    jd.[budget_gp_percentage],
    fi.[file_number],
	jd.rest_comp_location_id

ORDER BY [job_id] desc'


END
PRINT(@SQL)
EXEC (@SQL)

GO

GO
-- =============================================
-- Stored Procedure: [dbo].[ems_scheduler_View_java21]
-- Repeatable Migration - Re-runs when content changes
-- =============================================
CREATE OR ALTER PROCEDURE [dbo].[ems_scheduler_View_java21]
(@Tenant VARCHAR(90),@locationId int,@startDate VARCHAR(90),@endDate VARCHAR(90),@status VARCHAR(90),@userId int,@divisionType VARCHAR(90))
AS


DECLARE @SQL VARCHAR(MAX)

SET @SQL=N';

select ROW_NUMBER() OVER (ORDER BY CAST(j.created_datetime AS DATE) desc) AS id,e.schedule_id as scheduleId,j.job_id as jobId,j.job_code as jobCode,j.job_name as jobName,j.job_hash_code as jobHashCode,e.schedule_date as scheduleDate,
e.status as schStatus,ed.status as techStatus,
(select MIN(u.clock_in_time) from '+QUOTENAME(@Tenant)+'.'+'user_payroll_details u where u.job_id=j.job_id and u.labor_type in (''Labor'')
and u.clock_in_time>='''+CONVERT(nvarchar, @startDate)+''' and u.clock_in_time<='''+CONVERT(nvarchar, @endDate)+''' and u.user_id=ed.technician_id ) as clockInTime,

