(select u.first_name+'' ''+u.last_name from '+QUOTENAME(@Tenant)+'.'+'user_user_details u where u.user_id=ed.technician_id and ed.status='''+@status+''') as technicianName,

j.customer_type AS customerType,j.customer_company_name AS customerCompanyName,j.company as company,
