e.type_of_visit as typeOfVisit,(select Top 1 scratchpad from '+QUOTENAME(@Tenant)+'.'+'ems_schedule where job_id=j.job_id) as scratchpad,e.arrival_time as arrivalTime,e.expected_duration as expectedDuration,ed.technician_id as technicianId,
ed.type_of_visit as techTypeOfVisit,j.loss_address_city as city ,e.description
from '+QUOTENAME(@Tenant)+'.'+'job_details j


'


