        WHERE status_category IN (''New'', ''Sales'', ''Estimating (Initial)'', ''Planning'', ''Production'')
)
and CONVERT(VARCHAR(8), j.created_datetime, 112)>CONVERT(VARCHAR(8), ''2017-01-01 00:00:00'', 112)'
IF(@locationId>0)
BEGIN
