CREATE OR ALTER PROCEDURE [dbo].[scheduler_appointment_details_java21]
(@Tenant VARCHAR(90),@locationId int,@startDate NVARCHAR(90),@endDate NVARCHAR(90),@currentDate Datetime,@jobId NVARCHAR(50),@targetTimeZone NVARCHAR(90))
AS

DECLARE @SQL VARCHAR(MAX)

SET @SQL=N';



select ROW_NUMBER() OVER (ORDER BY CAST(j.created_datetime AS DATE) desc) AS id,e.schedule_id as scheduleId,j.job_id as jobId,j.job_code as jobCode,j.job_name as jobName,j.job_hash_code as jobHashCode, j.first_name as firstName, j.last_name as lastName,
(case when (e.schedule_start_date is null or e.all_day_event=''true'') then concat(e.schedule_date,'' '',''00:00:00'') else e.schedule_start_date end) as scheduleStartDate,
(case when (e.schedule_end_date is null  AND e.all_day_event=''true'') then concat(DateADD(D,1,e.schedule_date),'' '',''00:00:00'') else e.schedule_end_date end) as scheduleEndDate,
(select u.first_name+'' ''+u.last_name from '+QUOTENAME(@Tenant)+'.'+'user_user_details u where u.user_id=ed.technician_id and ed.status=''Active'') as technicianName,
j.current_job_status as status,j.job_type as jobType,
e.type_of_visit as typeOfVisit,(select Top 1 scratchpad from '+QUOTENAME(@Tenant)+'.'+'ems_schedule where job_id=j.job_id) as scratchpad,e.arrival_time as arrivalTime,
e.expected_duration as expectedDuration,ed.technician_id as technicianId,ed.type_of_visit as techTypeOfVisit,j.loss_address_city as city ,
e.description,e.location,
(case when SUBSTRING(e.event_occurrence,1,1)='':'' then SUBSTRING(e.event_occurrence,2,LEN(e.event_occurrence)-2) else e.event_occurrence end)as eventOccurrence,
ed.schedule_detail_id as scheduleDetailId,
(case when e.title is null then concat(j.job_code,'' - '',
(case when j.customer_type = ''Customer'' then concat(j.First_name,'' '',j.last_name) else j.customer_company_name end)) else e.title end) as title,
(select MIN(u.clock_in_time) from '+QUOTENAME(@Tenant)+'.'+'user_payroll_details u where u.job_id=j.job_id and u.labor_type in (''Labor'')
and u.clock_in_time>='''+ @startDate+''' and u.clock_in_time<='''+@endDate+''' and u.user_id=ed.technician_id ) as clockInTime,



(select MAX(u.clock_out_time) from '+QUOTENAME(@Tenant)+'.'+'user_payroll_details u where u.job_id=j.job_id
and u.labor_type in (''Labor'') and u.user_id=ed.technician_id and u.clock_in_time>='''+@startDate+''' and u.clock_in_time<='''+ @endDate+''') as clockOutTime,



(select MIN(u.clock_out_time) from '+QUOTENAME(@Tenant)+'.'+'user_payroll_details u where u.job_id=j.job_id and u.labor_type in (''Travel Time'')
and u.clock_out_time>='''+@startDate+''' and u.clock_out_time<='''+@endDate+''' and u.user_id=ed.technician_id ) as actualArrivalTime,



case when e.schedule_start_date is null then
DateDiff(n,concat(e.schedule_date,'' '',''00:00:00''),'''+CONVERT(nvarchar, @currentDate)+''')
else
DateDiff(n,e.schedule_start_date, '''+CONVERT(nvarchar, @currentDate)+''' ) end as overDueClockIn,e.all_day_event as allDayEvent,
e.calendar_guid as internalId,e.calendar_type as calendarType,e.external_guid as externalId,e.activity_status as activityStatus,
e.appointment_type as appointmentType,e.external_agency_id as organizationId,e.contact_id as contactId,
o.external_agency_name as organizationName,c.contact_first_name+'' ''+c.contact_last_name as contactName,
e.amount_budgeted as amountBudgeted,e.amount_spent as amountSpent,e.sales_activity_type as activityType,
e.recurrence_exception as recurrenceException




from '+QUOTENAME(@Tenant)+'.'+'ems_schedule e'




BEGIN



SET @SQL=@SQL+'
left join '+QUOTENAME(@Tenant)+'.'+'ems_schedule_details ed on ed.schedule_id=e.schedule_id and ed.status=''Active''
left join '+QUOTENAME(@Tenant)+'.'+'job_details j on  e.job_id=j.job_id
left join '+QUOTENAME(@Tenant)+'.'+'contact_details c on c.contact_id=e.contact_id and c.contact_status=''Active''
left join '+QUOTENAME(@Tenant)+'.'+'external_agency_details o on o.external_agency_id=e.external_agency_id and o.external_agency_status=''Active''


WHERE e.status = ''Active''
  AND (
    e.event_occurrence IS NOT NULL
    OR (
      CAST(''' + @startDate + ''' AS DATE) >= CAST(
            e.schedule_start_date AT TIME ZONE ''Eastern Standard Time'' AT TIME ZONE  ''' + @targetTimeZone+ '''
        AS DATE)
        AND CAST(''' + @startDate + ''' AS DATE) <= CAST(
            e.schedule_end_date AT TIME ZONE ''Eastern Standard Time'' AT TIME ZONE  ''' +@targetTimeZone + '''
        AS DATE)
    )
    OR (
      e.schedule_date >= ''' + @startDate + '''
      AND e.schedule_date <= ''' + @endDate + '''
    )
  )';



END

IF( @jobId IS NOT NULL and @jobId != 'NULL' and @jobId != '0')

BEGIN
SET @SQL=@SQL+' and e.job_id='+@jobId;
END

ELSE

BEGIN
SET @SQL=@SQL;
END


EXEC (@SQL)
print (@SQL)
GO

