-- =============================================
-- Stored Procedure: [dbo].[check_duplicate_notes_java21]
-- Repeatable Migration - Re-runs when content changes
-- Fix: EXEC moved inside procedure; uses sp_executesql with parameters (safe + correct)
-- =============================================
CREATE OR ALTER PROCEDURE [dbo].[check_duplicate_notes_java21]
    @Tenant VARCHAR(90),
    @jobId INT,
    @notes VARCHAR(MAX)
AS
BEGIN
    DECLARE @SQL NVARCHAR(MAX);
    DECLARE @notesCleaned NVARCHAR(MAX) = [dbo].[RemoveSpecialChars](@notes);

    SET @SQL = N'
        SELECT *
        FROM ' + QUOTENAME(@Tenant) + N'.common_notes c
        WHERE c.job_id = @jobId
          AND [dbo].[RemoveSpecialChars](c.notes) = @notesCleaned;
    ';

    EXEC sp_executesql @SQL,
        N'@jobId INT, @notesCleaned NVARCHAR(MAX)',
        @jobId = @jobId,
        @notesCleaned = @notesCleaned;
END
GO

