CREATE OR ALTER PROCEDURE [dbo].[check_duplicate_notes]
(@Tenant VARCHAR(90),@jobId INT,@notes NVARCHAR(MAX))
AS
BEGIN

DECLARE @SQL VARCHAR(MAX)

SET @SQL=N';
select c.[mast_num_job_notes_id] ,c.[mast_num_id] ,c.[job_id] ,c.[notes_applicable] 
,c.[notes_category] ,c.[notes] ,c.[written_by] ,c.[written_datetime] ,c.[updated_by] 
,c.[updated_datetime] ,c.[source] ,c.[notes_written_by] ,c.[zapier_updated_by] ,c.[encircle_note_id] 
,c.[encircle_sync_status] ,c.[status] ,c.[external_ref_id] ,c.[notes_sub_category] ,c.[file_id] 
from '+QUOTENAME(@Tenant)+'.'+'common_notes c 
where c.job_id='+cast (@jobId as NVARCHAR(10))+' and [dbo].[RemoveSpecialChars](c.notes)='''+[dbo].[RemoveSpecialChars](@notes)+'''';

END
PRINT @SQL
EXEC (@SQL)
