            SET @SQL3='
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
'
            DECLARE @SQL1 VARCHAR(MAX) = ''
            SET @SQL1 = (SELECT definition+'
GO' from #temp1 WHERE ID=@i1)

