-- =============================================
-- Stored Procedure: [dbo].[sys_CreateTenantUserAndPermissions]
-- Repeatable Migration - Re-runs when content changes
-- =============================================
CREATE OR ALTER PROCEDURE sys_CreateTenantUserAndPermissions
@tenant NVARCHAR(128)
AS
BEGIN
    DECLARE @SQL1 NVARCHAR(MAX)
    DECLARE @sql NVARCHAR(MAX) = '';  -- Variable to store dynamic SQL for stored procedures

    -- Build the SQL query string dynamically for user creation and role assignments
    SET @SQL1 = N'CREATE USER ' + QUOTENAME(@tenant) + N' WITHOUT LOGIN WITH DEFAULT_SCHEMA = ' + QUOTENAME(@tenant) + N';

    ALTER AUTHORIZATION ON SCHEMA::' + QUOTENAME(@tenant) + N' TO ' + QUOTENAME(@tenant) + N';

    ALTER ROLE [db_datareader] ADD MEMBER ' + QUOTENAME(@tenant) + N';

    ALTER ROLE [db_datawriter] ADD MEMBER ' + QUOTENAME(@tenant) + N';'

    SET @SQL1 = @SQL1 + N' GRANT CREATE TABLE TO ' + QUOTENAME(@tenant) + N';';

    -- Query to get all stored procedures from the dbo schema and build dynamic GRANT EXECUTE SQL
    SELECT @sql = @sql + 'GRANT EXECUTE ON [dbo].[' + name + '] TO ' + QUOTENAME(@tenant) + ';' + CHAR(13)
    FROM sys.objects
    WHERE type = 'P'  -- 'P' is for stored procedures
      AND schema_id = SCHEMA_ID('dbo');  -- Filter for dbo schema

    -- Combine user creation and role assignment SQL with the GRANT EXECUTE statements
    SET @SQL1 = @SQL1 + @sql;

    -- Print the final generated SQL (optional)
    PRINT @SQL1;

    -- Execute the combined dynamic SQL
    EXEC sp_executesql @SQL1;
END

GO

