-- =============================================
-- Stored Procedure: [dbo].[sys_DeleteTenantUserAndPermissions]
-- Repeatable Migration - Re-runs when content changes
-- =============================================
CREATE OR ALTER PROCEDURE sys_DeleteTenantUserAndPermissions
@tenant NVARCHAR(128)
AS
BEGIN
    DECLARE @SQL NVARCHAR(MAX)

    -- Revoke EXECUTE permissions on all stored procedures in the dbo schema
    SET @SQL = ''
    SELECT @SQL = @SQL + 'REVOKE EXECUTE ON [dbo].[' + name + '] TO ' + QUOTENAME(@tenant) + ';' + CHAR(13)
    FROM sys.objects
    WHERE type = 'P'  -- 'P' is for stored procedures
      AND schema_id = SCHEMA_ID('dbo');  -- Filter for dbo schema

    -- Execute the revoke command for EXECUTE on all stored procedures
    EXEC sp_executesql @SQL;

    -- Remove the user from the db_datareader and db_datawriter roles
    EXEC sp_addrolemember 'db_datareader', @tenant;
    EXEC sp_addrolemember 'db_datawriter', @tenant;

    -- Drop the user
    SET @SQL = N'DROP USER ' + QUOTENAME(@tenant) + N';'
    EXEC sp_executesql @SQL;

    -- Optional: Drop the schema if it's no longer needed
    -- SET @SQL = N'DROP SCHEMA ' + QUOTENAME(@tenant) + N';'
    -- EXEC sp_executesql @SQL;

    PRINT 'User and permissions for ' + @tenant + ' have been deleted.';
END

GO

