-- =============================================
-- Stored Procedure: [dbo].[copy_taskpack_tasks_from_template]
-- Repeatable Migration - Re-runs when content changes
-- =============================================
CREATE OR ALTER PROCEDURE dbo.copy_taskpack_tasks_from_template
    @tenant NVARCHAR(100)
AS
BEGIN
    SET NOCOUNT ON;

    DECLARE @taskpack_name NVARCHAR(255);
    DECLARE @task_name NVARCHAR(255);

    DECLARE @taskpack_id BIGINT;
    DECLARE @task_id BIGINT;

    DECLARE @target_taskpack_id BIGINT;
    DECLARE @target_task_id BIGINT;

    DECLARE @sql NVARCHAR(MAX);
    DECLARE @paramDef NVARCHAR(MAX);

    DECLARE task_cursor CURSOR FOR
        SELECT tp.taskpack_name, t.task_name, tp.taskpack_id, t.task_id
        FROM tenant3.m_taskpacks tp
        JOIN tenant3.m_taskpack_tasks tpt ON tp.taskpack_id = tpt.taskpack_id
        JOIN tenant3.m_tasks t ON t.task_id = tpt.task_id
        WHERE tp.taskpack_name IN (
            'TEMPLATE Mitigation Workflow',
            'TEMPLATE Mitigation SOP',
            'TEMPLATE Recon Workflow',
            'TEMPLATE Structural Cleaning',
            'TEMPLATE MOLD SOP',
            'TEMPLATE FIRE DAMAGE SOP',
            'TEMPLATE ASBESTOS SOP',
            'TEMPLATE RECONSTRUCTION SOP',
            'TEMPLATE CONTENTS SOP',
            'TEMPLATE BIO SOP',
            'TEMPLATE ROOFING SOP'
        );

    OPEN task_cursor;
    FETCH NEXT FROM task_cursor INTO @taskpack_name, @task_name, @taskpack_id, @task_id;

    WHILE @@FETCH_STATUS = 0
    BEGIN
        -- Get taskpack_id from target tenant
        SET @sql = '
            SELECT @target_taskpack_id_out = taskpack_id
            FROM ' + QUOTENAME(@tenant) + '.m_taskpacks
            WHERE taskpack_name = @taskpack_name_in';

        SET @paramDef = N'@taskpack_name_in NVARCHAR(255), @target_taskpack_id_out BIGINT OUTPUT';

        EXEC sp_executesql @sql, @paramDef, @taskpack_name_in = @taskpack_name, @target_taskpack_id_out = @target_taskpack_id OUTPUT;

        -- Get task_id from target tenant
        SET @sql = '
            SELECT @target_task_id_out = task_id
            FROM ' + QUOTENAME(@tenant) + '.m_tasks
            WHERE task_name = @task_name_in';

        SET @paramDef = N'@task_name_in NVARCHAR(255), @target_task_id_out BIGINT OUTPUT';

        EXEC sp_executesql @sql, @paramDef, @task_name_in = @task_name, @target_task_id_out = @target_task_id OUTPUT;

        -- Insert into target tenant's m_taskpack_tasks
        SET @sql = '
            INSERT INTO ' + QUOTENAME(@tenant) + '.m_taskpack_tasks (
                taskpack_id,
                task_id,
                task_sequence,
                assign_type,
                assign_to,
                action_required,
                action_id,
                trigger_event,
                trigger_event_id,
                time_to_complete,
                time_uom,
                created_by,
                created_datetime,
                updated_by,
                updated_datetime,
                source,
                mark_milestone,
                action_required_doc_type,
                contingent_task_yes,
                contingent_task_no,
                change_status_upon_completion,
                change_corporate_status_upon_completion,
                assignment_notification,
                status,
                reason_for_delete,
                previous_or_simultaneously_task
            )
            SELECT
                @target_taskpack_id,
                @target_task_id,
                tpt.task_sequence,
                tpt.assign_type,
                tpt.assign_to,
                tpt.action_required,
                tpt.action_id,
                tpt.trigger_event,
                tpt.trigger_event_id,
                tpt.time_to_complete,
                tpt.time_uom,
                tpt.created_by,
                tpt.created_datetime,
                tpt.updated_by,
                tpt.updated_datetime,
                tpt.source,
                tpt.mark_milestone,
                tpt.action_required_doc_type,
                tpt.contingent_task_yes,
                tpt.contingent_task_no,
                tpt.change_status_upon_completion,
                tpt.change_corporate_status_upon_completion,
                tpt.assignment_notification,
                tpt.status,
                tpt.reason_for_delete,
                tpt.previous_or_simultaneously_task
            FROM tenant3.m_taskpack_tasks tpt
            WHERE tpt.taskpack_id = @taskpack_id AND tpt.task_id = @task_id';

        SET @paramDef = N'
            @target_taskpack_id BIGINT,
            @target_task_id BIGINT,
            @taskpack_id BIGINT,
            @task_id BIGINT';

        EXEC sp_executesql @sql, @paramDef,
            @target_taskpack_id = @target_taskpack_id,
            @target_task_id = @target_task_id,
            @taskpack_id = @taskpack_id,
            @task_id = @task_id;

        FETCH NEXT FROM task_cursor INTO @taskpack_name, @task_name, @taskpack_id, @task_id;
    END;

    CLOSE task_cursor;
    DEALLOCATE task_cursor;
END;
GO

