-- =============================================
-- Stored Procedure: [dbo].[task_list_summary_procedure]
-- Repeatable Migration - Re-runs when content changes
-- =============================================
CREATE OR ALTER PROCEDURE  [dbo].[task_list_summary_procedure]
(@Tenant Varchar(255),@locationId INT,@listType Varchar(50),@userId INT,@currentDate Datetime)
As

BEGIN

SET NOCOUNT ON;

DECLARE @SQL VARCHAR(MAX)
SET @SQL=N';

select c.task_title as taskTitle,j.job_type as job,j.job_code as jobCode,j.job_hash_code as jobHashCode,j.job_id as jobId,
c.task_id as taskId,c.delay_reason as delayReason,c.status as status,c.expected_end_datetime as dueDate,c.actual_end_datetime as completedDatetime,
c.closed_reason as closedReason,c.rejected_reason as rejectedReason,c.action_required as actionRequiredToComplete,
(CASE when c.assign_type=''User'' then (select concat(u.first_name,'' '',u.last_name) from '+QUOTENAME(@Tenant)+'.'+'user_user_details u where u.user_id=c.assigned_to)
when c.assign_type=''Division'' then (select division_name from '+QUOTENAME(@Tenant)+'.'+'m_divisions where division_id=c.assigned_to)
when c.assign_type=''Role'' then (select role_name from  '+QUOTENAME(@Tenant)+'.'+'m_roles where role_id=c.assigned_to) end) as owner,
c.action_required_doc_type as actionRequiredDocType,
j.job_name as jobName,(select location_city from '+QUOTENAME(@Tenant)+'.'+'rest_comp_location where rest_comp_location_id=j.rest_comp_location_id) as locationName,
c.task_desc as description,(case when c.expected_end_datetime<'''+CONVERT(nvarchar, @currentDate)+''' and c.status != ''Completed'' and c.status!=''Rejected'' then ''true'' else ''false'' end) as overDue,
(case when j.customer_type=''Customer'' then concat(j.first_name,'' '',j.last_name) else j.customer_company_name end) as customerName,c.change_corporate_status_upon_completion as changeCorporateStatusUponCompletion,
c.change_status_upon_completion as changeStatusUponCompletion,
c.assignment_notification as assignmentNotification,
c.icon_id 
from '+QUOTENAME(@Tenant)+'.'+'common_tasks c join '+QUOTENAME(@Tenant)+'.'+'job_details j on c.source_id = j.job_id 
where '
 
IF(@locationId != 0) 
	BEGIN
		SET @SQL=@SQL+' c.source_id IN(select job_id from '+QUOTENAME(@Tenant)+'.'+'job_details where current_job_status !=''Deleted'' and rest_comp_location_id='+ cast (@locationId as NVARCHAR(10))+') and ';
	END
IF(@listType = 'My')

BEGIN 
SET @SQL=@SQL+' c.status IN(''Open'',''To Do'') and ((c.assign_type=''User'' and c.assigned_to='+ cast (@userId as NVARCHAR(10))+') or (c.assign_type=''Division'' and (select count(*) from '+QUOTENAME(@Tenant)+'.'+'user_division  
ud where ud.user_id='+ cast (@userId as NVARCHAR(10))+' and ud.status=''Active'' and ud.division_id=c.assigned_to)>0) or (c.assign_type=''Role'' and (select count(*) from '+QUOTENAME(@Tenant)+'.'+'user_user_roles  
ur where ur.user_id='+ cast (@userId as NVARCHAR(10))+' and ur.status=''Active'' and ur.role_id=c.assigned_to)>0)) ';
END 
ELSE IF(@listType = 'Dashboard')

BEGIN 
SET @SQL=@SQL+' c.status=''Open'' and (c.assign_type=''User'' and c.assigned_to='+ cast (@userId as NVARCHAR(10))+')';
END 

ELSE IF(@listType = 'All Open')
BEGIN

SET @SQL=@SQL+' c.status IN(''Open'',''To Do'') ';

END

ELSE IF(@listType = 'Revision Required')
BEGIN

SET @SQL=@SQL+' c.status IN(''Revision'',''Revision Required'') ';

END
ELSE
BEGIN
SET @SQL=@SQL+' c.status != ''Deleted'''
END

EXEC (@SQL)
print  (@SQL)

END


GO

