-- =============================================
-- Stored Procedure: [dbo].[GetUsersForWikiProUpdate]
-- Repeatable Migration - Re-runs when content changes
-- =============================================
CREATE OR ALTER PROCEDURE [dbo].[GetUsersForWikiProUpdate]
    @UserId     INT,
    @Tenant     SYSNAME,
    @RestCompID INT
AS
BEGIN
    SET NOCOUNT ON;

    IF (@Tenant IS NULL OR LTRIM(RTRIM(@Tenant)) = '')
BEGIN
            RAISERROR('Tenant is required.', 16, 1);
            RETURN;
END;

    IF (@UserId IS NULL)
BEGIN
            RAISERROR('UserId is required.', 16, 1);
            RETURN;
END;

    IF (@RestCompID IS NULL)
BEGIN
            RAISERROR('RestCompID is required.', 16, 1);
            RETURN;
END;

    DECLARE @sql NVARCHAR(MAX) = N'
;WITH RolesExpanded AS (
    SELECT
        u.user_id,
        LTRIM(RTRIM(u.first_name)) AS first_name,
        LTRIM(RTRIM(u.last_name))  AS last_name,
        u.email_id,
        r.role_name,
        CASE
            WHEN UPPER(r.role_name) IN (''ADMINISTRATOR'',''ADMIN'') THEN ''admin''
            WHEN UPPER(r.role_name) IN (''PROJECT MANAGER'',''SUPERVISOR'',''COORDINATOR'') THEN ''manager''
            ELSE ''staff''
        END AS Bucket,
        ROW_NUMBER() OVER (
            PARTITION BY u.user_id
            ORDER BY CASE
                        WHEN UPPER(r.role_name) IN (''ADMINISTRATOR'',''ADMIN'') THEN 1
                        WHEN UPPER(r.role_name) IN (''PROJECT MANAGER'',''SUPERVISOR'',''COORDINATOR'') THEN 2
                        ELSE 3
                     END
        ) AS rn
    FROM ' + QUOTENAME(@Tenant) + N'.user_user_details AS u
    INNER JOIN ' + QUOTENAME(@Tenant) + N'.user_user_roles AS ur
        ON ur.user_id = u.user_id
    INNER JOIN ' + QUOTENAME(@Tenant) + N'.m_roles AS r
        ON r.role_id = ur.role_id
    WHERE u.user_id = @UserId
      AND (r.status IS NULL OR UPPER(r.status) = ''ACTIVE'')
      AND u.email_id IS NOT NULL
      AND LTRIM(RTRIM(u.email_id)) <> ''''
)
SELECT
    re.user_id    AS UserId,
    re.first_name AS FirstName,
    re.last_name  AS LastName,
    re.email_id   AS Email,
    re.Bucket     AS Role,
    re.role_name  AS RoleName,
    we.wikipro_id AS StaffId,
    (
        SELECT TOP (1) o.company_id
        FROM common.wikipro_oauth AS o
        WHERE o.rest_comp_details_rest_comp_id = @RestCompID
        ORDER BY o.created_at DESC
    ) AS CompanyId
FROM RolesExpanded AS re
LEFT JOIN ' + QUOTENAME(@Tenant) + N'.wikipro_employee AS we
       ON we.user_id = re.user_id
WHERE re.rn = 1;
';

EXEC sys.sp_executesql
         @sql,
         N'@UserId INT, @RestCompID INT',
         @UserId     = @UserId,
         @RestCompID = @RestCompID;
END
go

GO
-- =============================================
-- Stored Procedure: [dbo].[GetUsersForWikiSync]
-- Repeatable Migration - Re-runs when content changes
-- =============================================
CREATE OR ALTER PROCEDURE [dbo].[GetUsersForWikiSync]
    @UserId INT = NULL,
    @Tenant         SYSNAME
AS
BEGIN
    SET NOCOUNT ON;

    IF (@Tenant IS NULL OR LTRIM(RTRIM(@Tenant)) = '')
BEGIN
            RAISERROR('Tenant is required.', 16, 1);
            RETURN;
END;

    DECLARE @sql NVARCHAR(MAX) = N'
;WITH RolesExpanded AS (
    SELECT
        u.user_id,
        LTRIM(RTRIM(u.first_name)) AS first_name,
        LTRIM(RTRIM(u.last_name))  AS last_name,
        u.email_id,
        r.role_name,
        CASE
            WHEN UPPER(r.role_name) IN (''ADMINISTRATOR'',''ADMIN'') THEN ''admin''
            WHEN UPPER(r.role_name) IN (''PROJECT MANAGER'',''SUPERVISOR'',''COORDINATOR'') THEN ''manager''
            ELSE ''staff''
        END AS Bucket,
        ROW_NUMBER() OVER (
            PARTITION BY u.user_id
            ORDER BY CASE
                        WHEN UPPER(r.role_name) IN (''ADMINISTRATOR'',''ADMIN'') THEN 1
                        WHEN UPPER(r.role_name) IN (''PROJECT MANAGER'',''SUPERVISOR'',''COORDINATOR'') THEN 2
                        ELSE 3
                    END
        ) AS rn
    FROM ' + QUOTENAME(@Tenant) + N'.user_user_details AS u
    INNER JOIN ' + QUOTENAME(@Tenant) + N'.user_user_roles AS ur
        ON ur.user_id = u.user_id
    INNER JOIN ' + QUOTENAME(@Tenant) + N'.m_roles AS r
        ON r.role_id = ur.role_id
    WHERE (@UserId IS NULL OR u.user_id = @UserId)
      AND UPPER(u.status) = ''ACTIVE''
      AND (r.status IS NULL OR UPPER(r.status) = ''ACTIVE'')
      AND u.email_id IS NOT NULL
      AND LTRIM(RTRIM(u.email_id)) <> ''''
      AND NOT EXISTS (
          SELECT 1
          FROM ' + QUOTENAME(@Tenant) + N'.wikipro_employee AS we
          WHERE we.user_id = u.user_id
      )
)
SELECT
    user_id    AS UserId,
    first_name AS FirstName,
    last_name  AS LastName,
    email_id   AS Email,
    Bucket     AS [Role],
    role_name  AS [RoleName]
FROM RolesExpanded
WHERE rn = 1
ORDER BY FirstName, LastName;';

EXEC sys.sp_executesql
         @sql,
         N'@UserId INT',
         @UserId = @UserId;
END
GO

