-- =============================================
-- Stored Procedure: [dbo].[GetWikiProAdminPushEndpoints]
-- Repeatable Migration - Re-runs when content changes
-- Purpose: Retrieve push notification endpoints for active WikiPro admin users
--          in a given tenant schema. Includes legacy fallback from user_user_details
--          for admins who have not yet registered via the new push_endpoints table.
-- Usage:   EXEC dbo.GetWikiProAdminPushEndpoints @Tenant = 'tenant7'
-- =============================================
CREATE OR ALTER PROCEDURE [dbo].[GetWikiProAdminPushEndpoints]
    @Tenant NVARCHAR(100)
AS
BEGIN
    SET NOCOUNT ON;

    IF (@Tenant IS NULL OR LTRIM(RTRIM(@Tenant)) = '')
    BEGIN
        RAISERROR('Tenant is required.', 16, 1);
        RETURN -1;
    END;

    DECLARE @sql NVARCHAR(MAX);
    SET @sql = N'
        -- Primary: new push_endpoints table (multi-device)
        SELECT we.user_id, pe.token, pe.platform
        FROM ' + QUOTENAME(@Tenant) + N'.wikipro_employee we
        INNER JOIN ' + QUOTENAME(@Tenant) + N'.push_endpoints pe
            ON pe.user_id = we.user_id AND pe.enabled = 1
        WHERE we.active = 1 AND we.role = ''Admin''

        UNION ALL

        -- Fallback: legacy single token from user_user_details
        SELECT we.user_id, ud.mobile_device_fcm_token AS token, ud.mobile_device_os AS platform
        FROM ' + QUOTENAME(@Tenant) + N'.wikipro_employee we
        INNER JOIN ' + QUOTENAME(@Tenant) + N'.user_user_details ud
            ON ud.user_id = we.user_id
            AND ud.mobile_device_fcm_token IS NOT NULL
            AND ud.mobile_device_os IS NOT NULL
            AND LEN(ud.mobile_device_fcm_token) > 0
            AND LEN(ud.mobile_device_os) > 0
        WHERE we.active = 1 AND we.role = ''Admin''
          AND NOT EXISTS (
            SELECT 1 FROM ' + QUOTENAME(@Tenant) + N'.push_endpoints pe2
            WHERE pe2.user_id = we.user_id
          )
    ';
    EXEC sys.sp_executesql @sql;
END
GO

