-- =============================================
-- Stored Procedure: [dbo].[user_notification_details]
-- Repeatable Migration - Re-runs when content changes
-- =============================================
CREATE OR ALTER PROCEDURE [dbo].[user_notification_details]
(@Tenant VARCHAR(90),@userId NVARCHAR(100),@status VARCHAR(50))
AS


DECLARE @SQL VARCHAR(MAX)

SET @SQL=N';
select n.notification_id,un.user_notification_id,n.message,un.read_status,n.created_datetime,un.assignee,
(select c.contact_profile_pic from '+QUOTENAME(@Tenant)+'.'+'contact_details c where c.contact_id=n.contact_id) as contact_profile_pic,
j.customer_type,j.first_name,j.last_name,j.customer_company_name,j.job_hash_code,j.job_code,n.job_id,j.job_type,n.contact_id,
(select concat(c.contact_first_name,'' '',c.contact_last_name) from '+QUOTENAME(@Tenant)+'.'+'contact_details c where c.contact_id=n.contact_id) as contact_name,
'''' as notified_on,n.notification_type 
 from  '+QUOTENAME(@Tenant)+'.'+'notification_details n join '+QUOTENAME(@Tenant)+'.'+'user_notifications un 
 on un.notification_id=n.notification_id
 left join '+QUOTENAME(@Tenant)+'.'+'job_details j on j.job_id=n.job_id
 where un.assignee='+@userId+' and n.status=''Active'' and un.status=''Active'''

 IF(@status='unread')
 BEGIN
	SET @SQL =  @SQL+' and un.read_status=''unread''';
 END

 SET @SQL=@SQL+' order by n.created_datetime desc'
EXEC (@SQL)
print  (@SQL)


