			where p.status=''Active'' and
			((p.clock_in_time>='''+CONVERT(nvarchar, @startDate)+''' and p.labor_type IN(''Uncategorized/Shop'',''Labor'',''Travel Time'') and p.clock_in_time<='''+CONVERT(nvarchar, @endDate)+''')
			or (p.clock_in_time>='''+CONVERT(nvarchar, @timeOffStartDate)+''' and p.labor_type is null and p.clock_in_time<='''+CONVERT(nvarchar, @timeOffEndDate)+'''))  order by p.clock_in_time';


EXEC (@SQL)
print  (@SQL)
