-- =============================================
-- Stored Procedure: [dbo].[user_payroll_summary_proc]
-- Repeatable Migration - Re-runs when content changes
-- =============================================
CREATE OR ALTER PROCEDURE  [dbo].[user_payroll_summary_proc](@Tenant Varchar(255), @startDate Datetime, @endDate Datetime,
                                                   @timeOffStartDate Datetime, @timeOffEndDate Datetime,
                                                   @type varchar(50), @userId int)
As

DECLARE @SQL VARCHAR(MAX);
    SET @SQL = N';

select ROW_NUMBER() OVER (ORDER BY CAST(p.clock_in_time AS DATE))AS id,u.first_name+'' ''+u.last_name AS empName,p.user_id as userId,min(p.clock_in_time) as clockInTime,max(p.clock_out_time) as clockOutTime,sum(p.duration) AS duration,CAST(p.clock_in_time AS DATE) as shiftDate,p.hour_type as hourType,u.email_id as emailAddress
from ' + QUOTENAME(@Tenant) + '.user_payroll_details p,' + QUOTENAME(@Tenant) +
               '.user_user_details u where p.user_id=u.user_id and p.status=''Active'' and (( p.clock_in_time>=''' +
               CONVERT(nvarchar, @startDate) + ''' and p.clock_in_time<=''' + CONVERT(nvarchar, @endDate) +
               ''' and p.labor_type IN(''Uncategorized/Shop'',''Labor'',''Travel Time'')) or ( p.clock_in_time>=''' +
               CONVERT(nvarchar, @timeOffStartDate) + ''' and p.clock_in_time<=''' +
               CONVERT(nvarchar, @timeOffEndDate) + ''' and p.labor_type IS NULL))';
    IF (@Type = 'My')
        BEGIN
            SET @SQL = @SQL + ' and p.user_id=' + cast(@userId as NVARCHAR(10));
            /**SET @SQL=@SQL+'and m.status IN (''New'',''Open'') and m.mast_num_id in(select jd.mast_num_id from '+QUOTENAME(@Tenant)+'.'+'[job_details] jd where jd.job_Id IN(select jr.job_Id from '+QUOTENAME(@Tenant)+'.'+'[job_roles] jr where jr.user_id='+ cast (@userId as NVARCHAR(10))+')) order by m.created_datetime desc';**/
            /**** and j.job_id in(select jr.job_Id from '+QUOTENAME(@Tenant)+'.'+'[job_roles] jr where jr.user_id='+ cast (@userId as NVARCHAR(10))+') and j.current_job_status NOT IN(''Closed'',''Rejected'') ****/

        END
    SET @SQL = @SQL +
               ' group by p.user_id,CAST(p.clock_in_time AS DATE),u.first_name,u.last_name,p.hour_type,u.email_id order by CAST(p.clock_in_time AS DATE)';


    EXEC (@SQL)
    print (@SQL)

GO

GO
-- =============================================
-- Stored Procedure: [dbo].[user_schedule_mobile_java21]
-- Repeatable Migration - Re-runs when content changes
-- =============================================
CREATE OR ALTER PROCEDURE [dbo].[user_schedule_mobile_java21]
(@Tenant VARCHAR(90),@locationId int,@userId NVARCHAR(100),@startDate NVARCHAR(90),@endDate NVARCHAR(90))
AS


DECLARE @SQL VARCHAR(MAX)
--DECLARE @startDate VARCHAR(100)
--DECLARE @endDate VARCHAR(100)
SET @startDate = @startDate+' 00:00:00'
SET @endDate = @endDate+' 23:59:59'
SET @SQL=N';

select ROW_NUMBER() OVER (ORDER BY CAST(j.created_datetime AS DATE) desc) AS id,e.schedule_id as scheduleId,ed.schedule_detail_id as scheduleDetailId,j.job_id as jobId,j.job_code as jobCode,j.job_name as jobName,j.job_hash_code as jobHashCode,e.schedule_date as scheduleDate,

(select MIN(u.clock_in_time) from '+QUOTENAME(@Tenant)+'.'+'user_payroll_details u where u.job_id=j.job_id and u.labor_type in (''Labor'')
and u.clock_in_time>='''+@startDate+''' and u.clock_in_time<='''+@endDate+''' and u.user_id='+@userId+') as clockInTime,

(select MAX(u.clock_out_time) from '+QUOTENAME(@Tenant)+'.'+'user_payroll_details u where u.job_id=j.job_id
and u.labor_type in (''Labor'') and u.user_id='+@userId+' and u.clock_in_time>='''+@startDate+''' and u.clock_in_time<='''+@endDate+''') as clockOutTime,
(select user_payroll_id from '+QUOTENAME(@Tenant)+'.'+'user_payroll_details u where u.job_id=j.job_id
and u.labor_type in (''Labor'') and u.user_id='+@userId+' and u.clock_in_time>='''+@startDate+''' and u.clock_in_time<='''+@endDate+'''
and u.clock_out_time is NULL) as userPayrollId,
(select u.first_name+'' ''+u.last_name from '+QUOTENAME(@Tenant)+'.'+'user_user_details u where u.user_id=ed.technician_id) as technicianName,
j.customer_type AS customerType,j.customer_company_name AS customerCompanyName,j.company as company,
j.first_name As firstName, j.last_name As lastName,j.current_job_status as status,j.job_type as jobType,j.loss_address as lossAddress,j.loss_address_city as lossAddressCity,
j.loss_address_state as lossAddressState,j.loss_address_zip as lossAddressZip,e.type_of_visit as typeOfVisit,ed.priority as priority,e.expected_duration as expectedDuration,
e.arrival_time as arrivalTime,j.mobile as mobile,j.phone1 as phoneNo,j.work_phone as workPhone,j.email as email,j.mast_num_id as mastNumId,';
SET @SQL=@SQL+'  stuff((
        select '','' + concat(u.first_name,'' '',u.last_name)
        from '+QUOTENAME(@Tenant)+'.'+'ems_schedule_details esd,'+QUOTENAME(@Tenant)+'.'+'user_user_details u
        where esd.technician_id = u.user_id and esd.schedule_id=e.schedule_id
        order by esd.schedule_detail_id
        for xml path('''')
    ),1,1,'''') as technicians,e.title,e.description,e.location,
(case when (e.schedule_start_date is null or e.all_day_event=''true'') then concat(e.schedule_date,'' '',''00:00:00'') else e.schedule_start_date end) as scheduleStartDate,
(case when (e.schedule_end_date is null  or e.all_day_event=''true'') then concat(DateADD(D,1,e.schedule_date),'' '',''00:00:00'') else e.schedule_end_date end) as scheduleEndDate,
e.event_occurrence as eventOccurrence,e.all_day_event as allDayEvent,e.external_agency_id as organizationId,e.contact_id as contactId,e.amount_budgeted as amountBudgeted,e.amount_spent as amountSpent,
e.calendar_guid as internalId,e.calendar_type as calendarType,e.external_guid as externalId,e.activity_status as activityStatus,
e.appointment_type as appointmentType

from '+QUOTENAME(@Tenant)+'.'+'ems_schedule e
left join '+QUOTENAME(@Tenant)+'.'+'job_details j on e.job_id=j.job_id
left join '+QUOTENAME(@Tenant)+'.'+'ems_schedule_details ed on ed.schedule_id=e.schedule_id and ed.status=''Active''
--left join '+QUOTENAME(@Tenant)+'.'+'ems_schedule_recurrence_details er on er.schedule_id=e.schedule_id and er.status=''Active''
--and er.schedule_start_date >='''+ @startDate+''' and  er.schedule_end_date <= '''+@endDate+'''
 where e.status=''Active'' and  (e.event_occurrence is not null or ((e.schedule_start_date >='''+ @startDate+''' and e.schedule_end_date <= '''+@endDate+''') or
(e.schedule_date>='''+ @startDate+''' and e.schedule_date <= '''+@endDate+''')))  and ed.technician_id='+@userId+'
 order by ed.priority';


EXEC (@SQL)
print  (@SQL)
GO

GO
