-- =============================================
-- Stored Procedure: [dbo].[user_schedule]
-- Repeatable Migration - Re-runs when content changes
-- =============================================
CREATE OR ALTER PROCEDURE [dbo].[user_schedule]
(@Tenant VARCHAR(90),@userId NVARCHAR(100),@scheduleDate NVARCHAR(90))
AS


DECLARE @SQL VARCHAR(MAX)
DECLARE @startDate VARCHAR(100)
DECLARE @endDate VARCHAR(100)
SET @startDate = @scheduleDate+' 00:00:00'
SET @endDate = @scheduleDate+' 23:59:59'
SET @SQL=N';

select e.schedule_id as scheduleId,ed.schedule_detail_id as scheduleDetailId,j.job_id as jobId,j.job_code as jobCode,j.job_name as jobName,j.job_hash_code as jobHashCode,e.schedule_date as scheduleDate,
CASE
    WHEN j.sms_broadcasting_enabled IS NULL
    THEN ''false''
    ELSE j.sms_broadcasting_enabled
END AS smsBroadcastingEnabled,
CASE
    WHEN j.mobile IS NOT NULL
     AND EXISTS (
        SELECT 1
        FROM ' + QUOTENAME(@Tenant) + N'.wikipro_chat wc
        WHERE wc.user_id = '+@userId+'
          AND wc.phone_number = j.mobile
          AND CAST(wc.sent_at AS date) = CAST(GETDATE() AS date)
     )
    THEN CAST(1 AS bit)
    ELSE CAST(0 AS bit)
END AS onMyWaySentToday,
(select MIN(u.clock_in_time) from '+QUOTENAME(@Tenant)+'.'+'user_payroll_details u where u.job_id=j.job_id and u.labor_type in (''Labor'') 
and u.clock_in_time>='''+@startDate+''' and u.clock_in_time<='''+@endDate+''' and u.user_id='+@userId+') as clockInTime,

(select MAX(u.clock_out_time) from '+QUOTENAME(@Tenant)+'.'+'user_payroll_details u where u.job_id=j.job_id 
and u.labor_type in (''Labor'') and u.user_id='+@userId+' and u.clock_in_time>='''+@startDate+''' and u.clock_in_time<='''+@endDate+''') as clockOutTime,
(select user_payroll_id from '+QUOTENAME(@Tenant)+'.'+'user_payroll_details u where u.job_id=j.job_id 
and u.labor_type in (''Labor'') and u.user_id='+@userId+' and u.clock_in_time>='''+@startDate+''' and u.clock_in_time<='''+@endDate+'''
and u.clock_out_time is NULL) as userPayrollId,
(select u.first_name+'' ''+u.last_name from '+QUOTENAME(@Tenant)+'.'+'user_user_details u where u.user_id=ed.technician_id) as technicianName,
j.customer_type AS customerType,j.customer_company_name AS customerCompanyName,j.company as company, 
j.first_name As firstName, j.last_name As lastName,j.current_job_status as status,j.job_type as jobType,j.loss_address as lossAddress,j.loss_address_city as lossAddressCity,
j.loss_address_state as lossAddressState,j.loss_address_zip as lossAddressZip,j.loss_address_lat as latitude,j.loss_address_lan as longitude,e.type_of_visit as typeOfVisit,
ed.priority as priority,e.expected_duration as expectedDuration,e.arrival_time as arrivalTime,j.mobile as mobile,j.phone1 as phoneNo,j.work_phone as workPhone,j.email as email,
j.mast_num_id as mastNumId,e.schedule_start_date as scheduleStartDate,e.schedule_end_date as scheduleEndDate,';
SET @SQL=@SQL+'  stuff((
        select '','' + concat(u.first_name,'' '',u.last_name)
        from '+QUOTENAME(@Tenant)+'.'+'ems_schedule_details esd,'+QUOTENAME(@Tenant)+'.'+'user_user_details u
        where esd.technician_id = u.user_id and esd.schedule_id=e.schedule_id and esd.technician_id!=ed.technician_id and esd.status=''Active''
        order by esd.schedule_detail_id
        for xml path('''')
    ),1,1,'''') as technicians,e.title,e.description,e.location
from '+QUOTENAME(@Tenant)+'.'+'ems_schedule e 
left join '+QUOTENAME(@Tenant)+'.'+'job_details j on e.job_id=j.job_id  
FULL join '+QUOTENAME(@Tenant)+'.'+'ems_schedule_details ed on ed.schedule_id=e.schedule_id and ed.status=''Active'' 
FULL join '+QUOTENAME(@Tenant)+'.'+'ems_schedule_recurrence_details er on er.schedule_id=e.schedule_id and er.status=''Active'' 
and er.schedule_start_date is not null and er.schedule_start_date >='''+ @startDate+''' and  er.schedule_end_date <= '''+@endDate+'''
where e.status=''Active'' and ed.technician_id='+@userId+' 
and (e.schedule_date = '''+@scheduleDate+'''
 or ( er.schedule_start_date >='''+ @startDate+''' and  er.schedule_end_date <= '''+@endDate+'''))
 order by ed.priority'


EXEC (@SQL)
print  (@SQL)
GO

GO
